-- Poems batch 189
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('bdd48965-aa70-498a-83e9-a344f687c53a','答王去非覓柳栽','劉宰','宋','宋诗','song-poetry','','[]','不惜柔條折贈君，與君分占萬家春。',32,'全唐诗/poet.song.181000.json','["不惜柔條折贈君，與君分占萬家春。", "祇愁五柳門前景，不稱三槐堂裏人。"]'),
('6b100a89-4f0a-481f-8d1a-49da5ea4d43e','得軒即事','劉宰','宋','宋诗','song-poetry','','[]','上印還家不計年，水光彌望木參天。',32,'全唐诗/poet.song.181000.json','["上印還家不計年，水光彌望木參天。", "綠雲洞裏開書幌，紅錦波心漾酒船。"]'),
('6090e5e5-3932-46d7-8fa1-a3724bbce2c5','荷花','劉宰','宋','宋诗','song-poetry','','[]','淤泥除盡藕根空，留得孤芳照病翁。',32,'全唐诗/poet.song.181000.json','["淤泥除盡藕根空，留得孤芳照病翁。", "水面亭亭塵不染，懸知不是蓼花紅。"]'),
('ff5c83e6-45d8-44e7-8aca-7aead54c0895','和錢晉之綠雲洞天韻','劉宰','宋','宋诗','song-poetry','','[]','理亂幽人了不聞，扶疎遶舍綠成雲。',32,'全唐诗/poet.song.181000.json','["理亂幽人了不聞，扶疎遶舍綠成雲。", "洞中不異人間世，一枕邯鄲浪策勳。"]'),
('78279a04-c7bf-45a7-af60-702bf961aeb3','答鍾元達覓藕栽二首  其一','劉宰','宋','宋诗','song-poetry','','[]','紅粧翠蓋出污塗，水面風吹醉欲扶。',32,'全唐诗/poet.song.181000.json','["紅粧翠蓋出污塗，水面風吹醉欲扶。", "自是凌波有仙種，文君莫訝茂陵姝。"]'),
('e5e815f2-84b5-410d-a1aa-0b0f130c3a76','答鍾元達覓藕栽二首  其二','劉宰','宋','宋诗','song-poetry','','[]','漸點青錢浮水面，猶將素節混泥沙。',32,'全唐诗/poet.song.181000.json','["漸點青錢浮水面，猶將素節混泥沙。", "送君百頃風潭上，莫笑原非十丈花。"]'),
('a3f4e025-fda7-4ba1-8a4a-762f0a5e616f','戲謝張端衡惠牡丹并湯鵝','劉宰','宋','宋诗','song-poetry','','[]','右軍渾脫從花王，老子開盤喜欲狂。',32,'全唐诗/poet.song.181000.json','["右軍渾脫從花王，老子開盤喜欲狂。", "擬插一枝無稱面，浪餐鵝炙愧劉郎。"]'),
('b9ba7395-2af2-4734-8231-74f071261b3b','題瀑布畫','劉宰','宋','宋诗','song-poetry','','[]','洩雲澒洞遮山腹，古木槎牙繚山足。',32,'全唐诗/poet.song.181000.json','["洩雲澒洞遮山腹，古木槎牙繚山足。", "舉頭百丈瀉寒泉，知有高峯插天綠。"]'),
('5f00210c-92b5-4e3f-a373-df664cb0b725','題德源庵','劉宰','宋','宋诗','song-poetry','','[]','牖戶綢繆實父基，豆區積貯訓承師。',32,'全唐诗/poet.song.181000.json','["牖戶綢繆實父基，豆區積貯訓承師。", "老來事業僅如此，慚愧平生祇小知。"]'),
('022bf82a-8dce-4e06-966e-3e8b51b146ba','回陳兄惠瓜','劉宰','宋','宋诗','song-poetry','','[]','碧圓到眼舌生津，三載深慚拜賜頻。',32,'全唐诗/poet.song.181000.json','["碧圓到眼舌生津，三載深慚拜賜頻。", "莫怪尊前最知味，東陵自是種瓜人。"]'),
('99c90f4f-6854-4c17-9c26-01ad0c257ffe','奉酬陳居士','劉宰','宋','宋诗','song-poetry','','[]','高人不作飯牛歌，盍嚮滄浪具笠蓑。',32,'全唐诗/poet.song.181000.json','["高人不作飯牛歌，盍嚮滄浪具笠蓑。", "正使同舟欠西子，也勝逐日效秦娥。"]'),
('a4649827-f0bc-4bbf-ba01-d7833a988f00','用韻索青娥丸','劉宰','宋','宋诗','song-poetry','','[]','病餘不賦惱儂歌，活計江湖一釣蓑。',32,'全唐诗/poet.song.181000.json','["病餘不賦惱儂歌，活計江湖一釣蓑。", "儻許膏肓驅二豎，肯令紅粉污青娥。"]'),
('eb585b63-b056-4d05-89f8-469a07a7d1a6','代柬蘇僉','劉宰','宋','宋诗','song-poetry','','[]','七十收身古戰場，歸來八十更康强。',32,'全唐诗/poet.song.181000.json','["七十收身古戰場，歸來八十更康强。", "酒闌庭戶秋光好，想見詩成一縷香。"]'),
('c08ca27e-e888-43ba-8e5e-2729f93db39a','柬張簿二首  其一','劉宰','宋','宋诗','song-poetry','','[]','簿書閲過幾牛腰，一縷清香午未消。',32,'全唐诗/poet.song.181000.json','["簿書閲過幾牛腰，一縷清香午未消。", "梔室醉吟誰是伴，鐵城折簡可頻招。"]'),
('7c882ade-0a21-4ee9-9d44-9c1a7ab233cc','柬張簿二首  其二','劉宰','宋','宋诗','song-poetry','','[]','細肋朝來正割鮮，瓦瓶先臘湛寒泉。',32,'全唐诗/poet.song.181000.json','["細肋朝來正割鮮，瓦瓶先臘湛寒泉。", "香棲枳棘寧多日，斷送橫飛上九天。"]'),
('546d82f7-eb4a-42d9-97f4-a6e318e5f0fc','代柬促陳居士歸','劉宰','宋','宋诗','song-poetry','','[]','一棹東遊久未歸，羞囊應已典春衣。',32,'全唐诗/poet.song.181000.json','["一棹東遊久未歸，羞囊應已典春衣。", "淡煙疎柳鱸魚市，底事流涎對落暉。"]'),
('5242d4dc-4d95-4108-9f30-f45fb00f69c9','代柬答徐監押','劉宰','宋','宋诗','song-poetry','','[]','隋堤綠柳漾清流，畫舸輸君爛漫遊。',32,'全唐诗/poet.song.181000.json','["隋堤綠柳漾清流，畫舸輸君爛漫遊。", "柘蕩高湖須老伴，不妨捩柁出灣頭。"]'),
('8bb16975-af6c-4a67-90c6-9e4410a565cf','口占送紙鶴帳與王克家中書','劉宰','宋','宋诗','song-poetry','','[]','雪翎丹頂更玄裳，持赴君家六尺牀。',32,'全唐诗/poet.song.181000.json','["雪翎丹頂更玄裳，持赴君家六尺牀。", "午枕不須蠻素問，主人心地正清涼。"]'),
('67a37912-56ed-45ad-b54e-74adb1c567cf','和王克家所寄草堂詩二首  其一','劉宰','宋','宋诗','song-poetry','','[]','絃歌流化記琴堂，椎魯難言愧互鄉。',32,'全唐诗/poet.song.181000.json','["絃歌流化記琴堂，椎魯難言愧互鄉。", "正對薇花揮翰墨，猶能春草夢池塘。"]'),
('4ce48d47-15bc-479c-bdb6-bd65c5b123f1','和王克家所寄草堂詩二首  其二','劉宰','宋','宋诗','song-poetry','','[]','身在金華與玉堂，寄聲時到祝雞鄉。',32,'全唐诗/poet.song.181000.json','["身在金華與玉堂，寄聲時到祝雞鄉。", "爲言舊訪盧仝處，柳壓平堤水滿塘。"]'),
('a28e81b2-7a7e-413d-a911-bac3e906a938','次韻謝范黄中運管二絕  其一','劉宰','宋','宋诗','song-poetry','','[]','一區聞道宅新成，瀟灑真堪寄此生。',32,'全唐诗/poet.song.181000.json','["一區聞道宅新成，瀟灑真堪寄此生。", "胸次清冰元自瑩，不妨更向玉壺盛。"]'),
('f96bb39c-8db5-4c11-a6f9-d9faaa870358','次韻謝范黄中運管二絕  其二','劉宰','宋','宋诗','song-poetry','','[]','刁塢春回花滿枝，沈溪夢斷水盈池。',32,'全唐诗/poet.song.181000.json','["刁塢春回花滿枝，沈溪夢斷水盈池。", "遥知弔古經行處，落紙雲烟總是詩。"]'),
('e2fff4b7-c589-443d-aff1-5ebc656182da','題恭靖兄志庵二首  其一','劉宰','宋','宋诗','song-poetry','','[]','宅兆當從志所安，故山松竹舞林巒。',32,'全唐诗/poet.song.181000.json','["宅兆當從志所安，故山松竹舞林巒。", "莫嗟外有封疆隔，自覺中含宇宙寬。"]'),
('675243a3-f722-4c8a-bb09-d3f4d697f259','題恭靖兄志庵二首  其二','劉宰','宋','宋诗','song-poetry','','[]','山勢西來如鳳舞，林巒左轉若龍蟠。',32,'全唐诗/poet.song.181000.json','["山勢西來如鳳舞，林巒左轉若龍蟠。", "門前一水流新綠，須信神心萬古安。"]'),
('ca8fdd55-6873-4b63-8fd6-4601939220b2','題明倫堂','劉宰','宋','宋诗','song-poetry','','[]','六樹庭前過屋山，一枝仙桂許高攀。',32,'全唐诗/poet.song.181000.json','["六樹庭前過屋山，一枝仙桂許高攀。", "風雲有幸逢千載，里社應先庇萬間。"]'),
('16cd3867-6156-4420-b0c9-f3e3cb363dea','送徐兄封川之行','劉宰','宋','宋诗','song-poetry','','[]','別時觸目是愁端，適喜君懷宇宙寬。',32,'全唐诗/poet.song.181000.json','["別時觸目是愁端，適喜君懷宇宙寬。", "千里事人猶見喜，寄聲別駕好相看。"]'),
('6576e882-4758-4697-a917-c23e1bb77cbd','聞杜鵑三首  其一','劉宰','宋','宋诗','song-poetry','','[]','當日停輈古道傍，大言聊以解愁腸。',32,'全唐诗/poet.song.181000.json','["當日停輈古道傍，大言聊以解愁腸。", "只今老去還吳下，無復驅車走四方。"]'),
('f0f90197-ca49-4df1-8b91-e84064213f5c','聞杜鵑三首  其二','劉宰','宋','宋诗','song-poetry','','[]','天津橋上小徘徊，入耳新聲兆有開。',32,'全唐诗/poet.song.181000.json','["天津橋上小徘徊，入耳新聲兆有開。", "家住江南異京洛，不因君至浪驚猜。"]'),
('678f7e1f-1e52-4fe0-968f-14e39cbb4d24','聞杜鵑三首  其三','劉宰','宋','宋诗','song-poetry','','[]','薄宦思歸畏嶮巇，從君歸去苦嫌遲。',32,'全唐诗/poet.song.181000.json','["薄宦思歸畏嶮巇，從君歸去苦嫌遲。", "歸時綠鬢今黄髮，歸路平安我獨知。"]'),
('739593fa-8cc7-48cb-80ad-398bb1d7a9ed','送洪季揚分教橫州兼呈丁帥二首  其一','劉宰','宋','宋诗','song-poetry','','[]','仕有爲貧難擇地，志將及物要乘時。',32,'全唐诗/poet.song.181000.json','["仕有爲貧難擇地，志將及物要乘時。", "青衫入手南中去，此意惟應我輩知。"]'),
('32d78a6a-783f-45ce-9a02-168149d656f9','送洪季揚分教橫州兼呈丁帥二首  其二','劉宰','宋','宋诗','song-poetry','','[]','五百人中占上游，四千里外客諸侯。',32,'全唐诗/poet.song.181000.json','["五百人中占上游，四千里外客諸侯。", "南中頼有賢方伯，處我應須勝自謀。"]'),
('ebd4ee3a-f2a7-4862-80a9-a29a921ebf6a','送機僧代柬莊氏','劉宰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長蕩湖南好事家，祇今無復舊豪華。',32,'全唐诗/poet.song.181000.json','["長蕩湖南好事家，祇今無復舊豪華。", "斗升爲乞西江水，涸鮒餘生或有涯。"]'),
('85e524a0-8799-4547-a6fa-385bb84fc3b3','送丁道士住洞陽','劉宰','宋','宋诗','song-poetry','','[]','華陽洞口鍊丹臺，仙客遺基在草萊。',32,'全唐诗/poet.song.181000.json','["華陽洞口鍊丹臺，仙客遺基在草萊。", "急遣羽流專洒掃，千年去鶴會歸來。"]'),
('366bf595-4010-4684-bea2-96ca6269d8f0','九日送酒黄竹磵','劉宰','宋','宋诗','song-poetry','','[]','老瓦盆中淥酒香，田家風物近重陽。',32,'全唐诗/poet.song.181000.json','["老瓦盆中淥酒香，田家風物近重陽。", "不知竹磵槃桓處，今賦黄華第幾章。"]'),
('7de0d75f-313c-4564-b978-43a89e118e51','寄題洪氏永則軒','劉宰','宋','宋诗','song-poetry','','[]','此則天然與性俱，執柯何必遠求歟。',32,'全唐诗/poet.song.181000.json','["此則天然與性俱，執柯何必遠求歟。", "父兄行己一家法，聖哲傳心萬卷書。"]'),
('a31ae75a-3f03-4b07-b278-b623923d2801','爲紀生借屋','劉宰','宋','宋诗','song-poetry','','[]','乃祖焚身爲祖劉，末孫那敢不相周。',32,'全唐诗/poet.song.181000.json','["乃祖焚身爲祖劉，末孫那敢不相周。", "單辭往扣賢公子，茅屋何妨得借留。"]'),
('8715385d-09bb-4e80-8f93-52b699c6b65f','送上元張尉兼柬呂制幹二首  其一','劉宰','宋','宋诗','song-poetry','','[]','千古繁華白下亭，萬家花柳擁層城。',32,'全唐诗/poet.song.181000.json','["千古繁華白下亭，萬家花柳擁層城。", "登臨此去非無地，彈壓中間要有聲。"]'),
('264dd543-2988-4eba-8866-fadc9fa651f5','送上元張尉兼柬呂制幹二首  其二','劉宰','宋','宋诗','song-poetry','','[]','幕府東來第一人，姓名星斗揭蒼旻。',32,'全唐诗/poet.song.181000.json','["幕府東來第一人，姓名星斗揭蒼旻。", "龍駒要踏浮雲去，好向庭前一問津。"]'),
('604a4e4a-4316-48dc-a9d6-b97d79de8173','枕上四首呈丁景舒  其一','劉宰','宋','宋诗','song-poetry','','[]','督郵行縣豈徒哉，指點虛無作禍媒。',32,'全唐诗/poet.song.181000.json','["督郵行縣豈徒哉，指點虛無作禍媒。", "料得淵明知此意，懸拋印綬賦歸來。"]'),
('0d3bdc62-b26f-4d33-b7c8-2dc4a71c0c5a','枕上四首呈丁景舒  其二','劉宰','宋','宋诗','song-poetry','','[]','弦歌容與倦將迎，五斗看來一羽輕。',32,'全唐诗/poet.song.181000.json','["弦歌容與倦將迎，五斗看來一羽輕。", "若也兒曹知此意，可容千載擅清名。"]'),
('c575e854-ecc4-4d20-b78c-6fa0516236ce','枕上四首呈丁景舒  其三','劉宰','宋','宋诗','song-poetry','','[]','籬邊把菊玩遺芳，未肯從渠入醉鄉。',32,'全唐诗/poet.song.181000.json','["籬邊把菊玩遺芳，未肯從渠入醉鄉。", "五字句中窺屈宋，七絃聲裏到羲皇。"]'),
('c9be3f28-f47d-43e1-98aa-b8b82e989247','枕上四首呈丁景舒  其四','劉宰','宋','宋诗','song-poetry','','[]','等閒遊目送飛鴻，適意何妨酒一鍾。',32,'全唐诗/poet.song.181000.json','["等閒遊目送飛鴻，適意何妨酒一鍾。", "蓮社未應尋盛遠，竹林中亦著濤戎。"]'),
('768b1b4f-b84b-44d4-aa2b-8a1ac9bfa6f9','代柬謝袁兄','劉宰','宋','宋诗','song-poetry','','[]','漁樵並舍兩相忘，三逕回看久就荒。',32,'全唐诗/poet.song.181000.json','["漁樵並舍兩相忘，三逕回看久就荒。", "只有生平真活計，湖光萬頃接山光。"]'),
('884dad2f-cf74-4309-82ee-b16afc46032f','送無灰酒周馬帥口占三絕  其一','劉宰','宋','宋诗','song-poetry','','[]','寶璽來歸萬國春，海隅花鳥亦欣欣。',32,'全唐诗/poet.song.181000.json','["寶璽來歸萬國春，海隅花鳥亦欣欣。", "皇恩更向將軍厚，乞與人間自在身。"]'),
('52aacec9-054d-48a0-b1e5-4a9e99fbd69b','送無灰酒周馬帥口占三絕  其二','劉宰','宋','宋诗','song-poetry','','[]','乞得閒身荷聖朝，舊棲佳處日逍遥。',32,'全唐诗/poet.song.181000.json','["乞得閒身荷聖朝，舊棲佳處日逍遥。", "却憐赤壁歸來日，歌舞樽前祇小喬。"]'),
('c3e9778a-ef31-40fe-a1d2-41780e0116a2','送無灰酒周馬帥口占三絕  其三','劉宰','宋','宋诗','song-poetry','','[]','奉寄無灰酒十罌，一盃入藥可長生。',32,'全唐诗/poet.song.181000.json','["奉寄無灰酒十罌，一盃入藥可長生。", "藥成預約分酬我，眉壽相期比老彭。"]'),
