('fea5ba77-9724-444e-9201-32dd6e1428fe','題劉文簡所藏墨梅卷','劉宰','宋','宋诗','song-poetry','','[]','煙雨和成宛擅場，新來翻著雪衣裳。',32,'全唐诗/poet.song.181000.json','["煙雨和成宛擅場，新來翻著雪衣裳。", "以吾不可學渠可，善學楊君祇此郎。"]'),
('2cbf9ad8-5566-4e66-a126-dd5a129d208a','雲邊偶成二首  其一','劉宰','宋','宋诗','song-poetry','','[]','月下浮舟去，雲邊曳杖行。',48,'全唐诗/poet.song.181000.json','["月下浮舟去，雲邊曳杖行。", "物華隨節換，人意與秋清。", "小圃蔬逾潤，荒叢菊向榮。", "幽尋元自好，底用絆浮名。"]'),
('11ae3df0-b822-41ef-b55a-b058ee17f842','雲邊偶成二首  其二','劉宰','宋','宋诗','song-poetry','','[]','地曠晚逾靜，山空月倍明。',48,'全唐诗/poet.song.181000.json','["地曠晚逾靜，山空月倍明。", "銀河橫灝氣，石澗伴吟聲。", "颯颯迎風葉，飛飛濕露螢。", "歲華行晚矣，爲爾一凝情。"]'),
('01121cac-e41a-40aa-bf9b-4eeeaa8e05a7','發紹興','劉宰','宋','宋诗','song-poetry','','[]','留滯青春晚，經行此日初。',48,'全唐诗/poet.song.181000.json','["留滯青春晚，經行此日初。", "柔條桑著眼，短穗麥生鬚。", "竹外雲埋屋，花邊水遶渠。", "箇中容我老，肯遺子公書。"]'),
('80d05ede-5ac6-4448-a467-ef070804f163','天台道中','劉宰','宋','宋诗','song-poetry','','[]','花重朝霏散，鳥啼春意深。',48,'全唐诗/poet.song.181000.json','["花重朝霏散，鳥啼春意深。", "風光自流轉，行役負登臨。", "澗水流新綠，山雲捲夕陰。", "病容兼白鬢，漂泊此時心。"]'),
('3df95b20-9e7e-4b02-950b-491bc8d68261','馮公嶺','劉宰','宋','宋诗','song-poetry','','[]','地隘山逾峻，人勤俗不奢。',48,'全唐诗/poet.song.181000.json','["地隘山逾峻，人勤俗不奢。", "時培石上土，更種竹間茶。", "接畛田成篆，連筒水濺花。", "征塵如不到，老我即東家。"]'),
('96dde556-a1f6-40ae-9362-5c04a3887d10','長林場海邊道上','劉宰','宋','宋诗','song-poetry','','[]','海霧晚逾合，海風春更寒。',48,'全唐诗/poet.song.181000.json','["海霧晚逾合，海風春更寒。", "衰顔欺薄酒，老膽傲驚湍。", "叢竹人家近，平沙客路寬。", "明朝應更好，山翠撲征鞍。"]'),
('c1e7ffb0-1b16-4420-9fbb-7186bda8cd0e','松江道中','劉宰','宋','宋诗','song-poetry','','[]','久作松江夢，重來泛短篷。',48,'全唐诗/poet.song.181000.json','["久作松江夢，重來泛短篷。", "淡雲飛急雪，枯葉戰狂風。", "煙末三家市，波心一釣翁。", "鴟夷身計耳，吳越等成空。"]'),
('a30c90dc-719b-4096-ba90-45c6fd4ee947','同葉恭叔鄭節卿飲于趙子野官舍','劉宰','宋','宋诗','song-poetry','','[]','相望各千里，相逢酒一壺。',48,'全唐诗/poet.song.181000.json','["相望各千里，相逢酒一壺。", "交情貫金石，詩思渺江湖。", "夜雨滋園菊，秋風落井梧。", "歸歟吾有日，聚散一長吁。"]'),
('f32d1292-6f65-4c62-ba70-65c43e6bc52b','偶成','劉宰','宋','宋诗','song-poetry','','[]','木落山呈骨，泉空水反源。',48,'全唐诗/poet.song.181000.json','["木落山呈骨，泉空水反源。", "知時秋燕去，負日午蜂喧。", "玉粒炊晨甑，金英卧晚園。", "歲華今已暮，身世兩忘言。"]'),
('4748be87-2a5d-4e76-ac2c-be864fdf95d6','試郭生筆','劉宰','宋','宋诗','song-poetry','','[]','金華山中僊，委蛇霜雪明。',48,'全唐诗/poet.song.181000.json','["金華山中僊，委蛇霜雪明。", "君於何處得，束縛封管城。", "大白真若辱，脫帽甘沉冥。", "世有揚子雲，猶堪草玄經。"]'),
('78d358f9-aaea-4986-a254-5cd4daa6d01d','送傅守歸  其一','劉宰','宋','宋诗','song-poetry','','[]','煩暑斂清曉，西風生遠林。',48,'全唐诗/poet.song.181000.json','["煩暑斂清曉，西風生遠林。", "客懷感素秋，歸夢越千岑。", "祖帳城南門，藹藹萃華簪。", "舉觴忽有贈，去矣無遐心。"]'),
('564094d8-efd3-4d1d-b185-9d7887daa7b5','送傅守歸  其二','劉宰','宋','宋诗','song-poetry','','[]','堂堂司馬公，獨樂五畝園。',48,'全唐诗/poet.song.181000.json','["堂堂司馬公，獨樂五畝園。", "歲月坐成晚，花木亦已繁。", "世事尚可爲，石交有遺言。", "歸來默無語，拊石弄潺湲。"]'),
('14751edb-0357-49f0-a8af-cf30a7d73b36','送傅守歸  其三','劉宰','宋','宋诗','song-poetry','','[]','令行肅權豪，仁施先困窮。',48,'全唐诗/poet.song.181000.json','["令行肅權豪，仁施先困窮。", "適此饑饉餘，喟彼杼軸空。", "勞來窮人謀，祈禳與天通。", "那得三百州，落落皆此公。"]'),
('30524bd0-d994-4489-a49b-0861c96cd882','送傅守歸  其四','劉宰','宋','宋诗','song-poetry','','[]','世念分五兵，當使道戰勝。',48,'全唐诗/poet.song.181000.json','["世念分五兵，當使道戰勝。", "昔別稽山陰，風采臞而整。", "重逢驚少壯，神光爍衰病。", "一氣中夜存，還丹嗤葛令。"]'),
('df1d6a3b-cac2-4102-81de-da3d8d4fbe55','送傅守歸  其五','劉宰','宋','宋诗','song-poetry','','[]','永日來清風，黄堂少公事。',48,'全唐诗/poet.song.181000.json','["永日來清風，黄堂少公事。", "憑欄一長望，千載幾興廢。", "論功赤壁多，語士北府銳。", "歸舟眇家具，弔古足新製。"]'),
('c195acfb-a8d9-43ec-8451-0148491171c5','送傅守歸  其六','劉宰','宋','宋诗','song-poetry','','[]','金山故佳麗，傑觀環孤峯。',48,'全唐诗/poet.song.181000.json','["金山故佳麗，傑觀環孤峯。", "對峙焦公廬，林杪出疎鐘。", "南歸謝塵鞅，北眺足從容。", "應持濟川手，一酹擊楫翁。"]'),
('0417bd2b-20ae-4d82-8967-af8f044ecb33','送傅守歸  其七','劉宰','宋','宋诗','song-poetry','','[]','辯士變初說，勇士衰再鼓。',48,'全唐诗/poet.song.181000.json','["辯士變初說，勇士衰再鼓。", "向來東海濱，有士節獨苦。", "歲晚兒女戀，頗亦類張禹。", "堂堂裴晉公，綠野能容與。"]'),
('6f0fd216-71f9-4e93-a92b-656ea1fc41e5','送傅守歸  其八','劉宰','宋','宋诗','song-poetry','','[]','仕至二千石，富貴有足樂。',48,'全唐诗/poet.song.181000.json','["仕至二千石，富貴有足樂。", "官爲諫大夫，亦足究所學。", "蘭階擢珠樹，金閨聯棣萼。", "何妨赤松遊，不負黄石約。"]'),
('a6bb331a-220e-40b3-8e6b-85ff80ba9ca0','送傅守歸  其九','劉宰','宋','宋诗','song-poetry','','[]','濯纓滄浪水，爲愛滄浪清。',48,'全唐诗/poet.song.181000.json','["濯纓滄浪水，爲愛滄浪清。", "明明中興主，齋居方厲精。", "疏傅不自惜，決去鴻毛輕。", "濫觴爾何知，咄哉檀長卿。"]'),
('2c92db88-6f50-4d1a-9bbd-0bdc95d54499','送傅守歸  其一○','劉宰','宋','宋诗','song-poetry','','[]','北渚有狂士，病卧忘四時。',48,'全唐诗/poet.song.181000.json','["北渚有狂士，病卧忘四時。", "綠暗知春晚，葉落識秋期。", "西風日已高，凝露方自滋。", "獨有歲寒心，不負流水知。"]'),
('9f039f9e-d661-41f7-a8a6-d1413d04fdba','送梁伯賜歸括蒼三首  其一','劉宰','宋','宋诗','song-poetry','','[]','怒風駕海潮，錢塘天下壯。',48,'全唐诗/poet.song.181000.json','["怒風駕海潮，錢塘天下壯。", "岷山浚源委，東下極奔放。", "中橫吳淞江，煙波渺四望。", "歸歟太史筆，偃蹇九霄上。"]'),
('c551cfdd-90a8-4314-8d53-c730d3e49709','送梁伯賜歸括蒼三首  其二','劉宰','宋','宋诗','song-poetry','','[]','城關美少年，三五事游冶。',48,'全唐诗/poet.song.181000.json','["城關美少年，三五事游冶。", "明璫燭綺疏，寶香籠舞榭。", "一朝黄金盡，帷蓋羞狗馬。", "短檠有真樂，行矣遴取舍。"]'),
('ade8d379-ad85-4006-9251-26c40d6e0ff3','送梁伯賜歸括蒼三首  其三','劉宰','宋','宋诗','song-poetry','','[]','西北天馬駒，墮地志千里。',48,'全唐诗/poet.song.181000.json','["西北天馬駒，墮地志千里。", "暴生執鞭轡，邂逅渥洼水。", "東來薦郊廟，聲名藹千祀。", "咄爾駑駘輩，局縮當愧死。"]'),
('1d6906ef-93f1-4724-b9fd-573c750ba3ca','雲邊偶成','劉宰','宋','宋诗','song-poetry','','[]','樂歲饒嘉澤，荒山徧有秋。',48,'全唐诗/poet.song.181000.json','["樂歲饒嘉澤，荒山徧有秋。", "斷雲猶過雨，平陸自交流。", "香飯炊紅軟，嘉蔬薦綠柔。", "蠅營竟何事，老我即菟裘。"]'),
('69152f3a-5345-4a92-86ad-6731d476533e','即事有懷二首  其一','劉宰','宋','宋诗','song-poetry','','[]','千山收宿靄，一氣藹金行。',48,'全唐诗/poet.song.181000.json','["千山收宿靄，一氣藹金行。", "爽吹舒澄碧，晴暉麗太清。", "徘徊望前嶺，徙倚步南榮。", "爲問蓴鱸客，何須身後名。"]'),
('6f08a22a-78cd-42e6-b2b7-d2fd70a0d946','即事有懷二首  其二','劉宰','宋','宋诗','song-poetry','','[]','濟世無長策，觀詩歎小明。',48,'全唐诗/poet.song.181000.json','["濟世無長策，觀詩歎小明。", "悠悠忘夜永，淅淅聽秋聲。", "困躓鹽車驥，飛騰腐草螢。", "乖逢偶然爾，造物兩何情。"]'),
('72f78b8d-6242-4031-8fae-bb3ea9045228','儀真雍生見和因再用韻兼懷儀真  其一','劉宰','宋','宋诗','song-poetry','','[]','北觀憑欄望，西橋信馬行。',48,'全唐诗/poet.song.181000.json','["北觀憑欄望，西橋信馬行。", "朋從有名勝，風物正凄清。", "亂定人煙改，春回草木榮。", "遥憐舊游處，壞壁暗題名。"]'),
('74785d8f-d48b-40ae-bf91-3652316c4370','儀真雍生見和因再用韻兼懷儀真  其二','劉宰','宋','宋诗','song-poetry','','[]','久客憐之子，寒窗幾晦明。',48,'全唐诗/poet.song.181000.json','["久客憐之子，寒窗幾晦明。", "羈禽戀鄉國，來雁尚邊聲。", "事去雲成狗，時來草化螢。", "未須論得失，把酒謾忘情。"]'),
('fbdc3a22-1f7a-49ae-bc8d-a73083882149','和郡倅陳校書祈雨韻','劉宰','宋','宋诗','song-poetry','','[]','麥隴收黄槁，秧田欠綠滋。',48,'全唐诗/poet.song.181000.json','["麥隴收黄槁，秧田欠綠滋。", "三時猶好在，一雨未爲遲。", "精意能先物，神明敢後期。", "邦人孚至意，可但不能欺。"]'),
('481761af-1120-4074-97bd-ed9ba6567fe4','和羅權丞至日雪韻','劉宰','宋','宋诗','song-poetry','','[]','臺上五雲紀，宮中一線添。',48,'全唐诗/poet.song.181000.json','["臺上五雲紀，宮中一線添。", "巧開三白瑞，幻出六花鹽。", "宿麥猶期潤，前山已見尖。", "應憐貴公子，索句久巡簷。"]'),
('67e10f0d-1d6d-4e61-bc84-06790a0f8091','送張端袤攝簿建平','劉宰','宋','宋诗','song-poetry','','[]','吏道貴更事，君行非爲貧。',48,'全唐诗/poet.song.181000.json','["吏道貴更事，君行非爲貧。", "勾稽戾初意，疾痛繫斯民。", "一日居須葺，他年政若神。", "放船秋水闊，著眼看修鱗。"]'),
('0fc58ea0-a9ed-4ecf-839d-57d22911af3b','戲呈南池同遊諸兄','劉宰','宋','宋诗','song-poetry','','[]','方池带南郭，勝踐及西風。',48,'全唐诗/poet.song.181000.json','["方池带南郭，勝踐及西風。", "多稼天連碧，芳蓮水映紅。", "漁歌來席上，鳥影度屏中。", "想見垂楊裏，詩成又暮鐘。"]'),
('2eb4bd58-c9ce-4e60-a5ca-e8cda8434d7e','山行阻雪呈同游諸友','劉宰','宋','宋诗','song-poetry','','[]','幽尋本無急，聊以會友生。',48,'全唐诗/poet.song.181000.json','["幽尋本無急，聊以會友生。", "塵中妨劇談，故作林下行。", "僕夫問歸路，夜聞風雪聲。", "何妨小遲留，妙理細重評。"]'),
('78d160e0-97e0-4d82-87d5-3973471d00d8','和前韻呈李果州','劉宰','宋','宋诗','song-poetry','','[]','行樂非吾事，朋從慰此生。',48,'全唐诗/poet.song.181000.json','["行樂非吾事，朋從慰此生。", "劇談忘夜永，起立緩盃行。", "黄獨幽人供，朱絃太古聲。", "他年盛山集，不假退之評。"]'),
('07cffc00-7572-46f2-b138-4da8f199de59','送張端袤主含山簿','劉宰','宋','宋诗','song-poetry','','[]','計利無非利，辭難枉作難。',48,'全唐诗/poet.song.181000.json','["計利無非利，辭難枉作難。", "驅車平路去，高枕此心安。", "縣小勾稽易，時危賦斂殫。", "好裨千慮失，可使百憂寬。"]'),
('092a7b5b-5433-40d6-af8c-4f4668552cb1','寄寶應丘大夫','劉宰','宋','宋诗','song-poetry','','[]','制閫今元帥，男邦舊大夫。',48,'全唐诗/poet.song.181000.json','["制閫今元帥，男邦舊大夫。", "受成無弊事，直上有夷塗。", "赤縣圖新入，蒼生喘欲蘇。", "底須勞戰士，城築守淮隅。"]'),
('b5dbdd57-c9d9-4238-bb92-c69726d9198d','丁亥冬感懷寄趙章泉三首  其一','劉宰','宋','宋诗','song-poetry','','[]','楚塞仍多事，章泉闕寄音。',48,'全唐诗/poet.song.181000.json','["楚塞仍多事，章泉闕寄音。", "由來使狙詐，何意啟狼心。", "國勢時輕重，江流自古今。", "遥憐杜陵老，對雪幾愁吟。"]'),
('f136641a-03fb-4bb9-8864-7e5faca732d7','丁亥冬感懷寄趙章泉三首  其二','劉宰','宋','宋诗','song-poetry','','[]','報國知無術，書空竟若何。',48,'全唐诗/poet.song.181000.json','["報國知無術，書空竟若何。", "淮山雲慘淡，鍾阜石嵯峨。", "高孝遺規在，梁陳往鑒多。", "癙憂徒爾耳，遠浦聽漁歌。"]'),
('b31bece4-2766-4f2f-896e-8cdb4b0c87ad','丁亥冬感懷寄趙章泉三首  其三','劉宰','宋','宋诗','song-poetry','','[]','我屋方茅下，君家閩楚交。',48,'全唐诗/poet.song.181000.json','["我屋方茅下，君家閩楚交。", "鹿門知得計，燕幕未安巢。", "澗谷泉堪飲，山田飯可抄。", "應携靈壽杖，雪蘂嗅梅梢。"]'),
('1bf497ab-969c-4c6e-b81d-1deac8b4f56f','寄同年朱景淵通判八首  其一','劉宰','宋','宋诗','song-poetry','','[]','念昔從子游，金陵佳麗地。',48,'全唐诗/poet.song.181000.json','["念昔從子游，金陵佳麗地。", "幕府盛賓僚，東南稱兩尉。", "子才清而通，我拙世無二。", "櫟社雖輪囷，靈根同晚歲。"]'),
('a225324b-ec8c-4f1a-99b0-a9b2de38cb42','寄同年朱景淵通判八首  其二','劉宰','宋','宋诗','song-poetry','','[]','默數金陵友，在者猶四人。',60,'全唐诗/poet.song.181000.json','["默數金陵友，在者猶四人。", "糾曹今別乘，法官駕朱輪。", "千鍾已弗暨，一念還酸辛。", "况我病所纏，漁樵寄此身。", "輸子曳朱紱，斑衣奉慈親。"]'),
('4fd3698e-5838-424e-90d3-7f68fd730a98','寄同年朱景淵通判八首  其三','劉宰','宋','宋诗','song-poetry','','[]','當時最少年，雪林紫芝翁。',48,'全唐诗/poet.song.181000.json','["當時最少年，雪林紫芝翁。", "詩名三十年，正復坐此窮。", "落日澹平湖，宿草鳴寒蛩。", "何時一樽酒，往酹與子同。"]'),
('b7de4183-c4cb-40a6-bb93-53aee8924049','寄同年朱景淵通判八首  其四','劉宰','宋','宋诗','song-poetry','','[]','四海游夫子，粹學洞古今。',48,'全唐诗/poet.song.181000.json','["四海游夫子，粹學洞古今。", "聞善亟推輓，常恐力不任。", "時危係長才，白日已西沉。", "拱木戰寒風，凄其千載心。"]'),
('93c6e230-2a28-4ec6-994b-e583d303463c','寄同年朱景淵通判八首  其五','劉宰','宋','宋诗','song-poetry','','[]','茂苑子周子，慷慨憂時危。',48,'全唐诗/poet.song.181000.json','["茂苑子周子，慷慨憂時危。", "斯文鼂董流，炳炳日星垂。", "言深衆所驚，用淺才不施。", "穹窿山下笛，懷人定誰其。"]'),
('37bd06c2-77ff-4417-8b67-73befa6503ba','寄同年朱景淵通判八首  其六','劉宰','宋','宋诗','song-poetry','','[]','滕子嗜古學，萬卷作生計。',48,'全唐诗/poet.song.181000.json','["滕子嗜古學，萬卷作生計。", "孤燈耿夜闌，盜畏不敢睨。", "至寶世不售，虛名竟何利。", "尚想古城隅，幽花開繞砌。"]'),
('518f2a38-2ebc-4ecb-bc46-2ce6bbe7c850','寄同年朱景淵通判八首  其七','劉宰','宋','宋诗','song-poetry','','[]','細柳真將軍，勁氣可立懦。',60,'全唐诗/poet.song.181000.json','["細柳真將軍，勁氣可立懦。", "向來拯時危，功畧天下半。", "屢詔不肯起，出處懸自斷。", "十載山澤游，萬念春冰渙。", "何當求識面，介子同里閈。"]'),
('398caa08-69e0-4ee2-ab64-b555572c7fae','寄同年朱景淵通判八首  其八','劉宰','宋','宋诗','song-poetry','','[]','古人重結交，一諾輕千金。',48,'全唐诗/poet.song.181000.json','["古人重結交，一諾輕千金。", "嗟我與夫子，論交歲月深。", "一別三十年，兩鬢霜雪侵。", "願言益自强，鴈來時寄音。"]'),
('e3f2b3d6-fed6-41ac-9fbb-7b3f0fa1649c','題王荆公半山圖','劉宰','宋','宋诗','song-poetry','','[]','歸來心事平，蹇馿踏秋風。',48,'全唐诗/poet.song.181000.json','["歸來心事平，蹇馿踏秋風。", "舉鞭問髯奴，何如浣花翁。", "道旁幾高松，風來自相語。", "桃李今何之，歲寒予與汝。"]'),
('64f7598c-8473-4301-8bb9-8bbc9fad7f3a','喜延陵從事還任','劉宰','宋','宋诗','song-poetry','','[]','聞道古延邑，歡迎舊尹歸。',48,'全唐诗/poet.song.181000.json','["聞道古延邑，歡迎舊尹歸。", "鄰翁爭掃舍，學子競牽衣。", "賸喜陳編在，還欣俗物稀。", "樽前重懷想，葵日映清暉。"]'),
('fcd99152-00e0-461f-a1e3-e17dfce02550','題戴氏稼庵','劉宰','宋','宋诗','song-poetry','','[]','小泊尋前約，周行得偉觀。',48,'全唐诗/poet.song.181000.json','["小泊尋前約，周行得偉觀。", "乾坤開玉宇，日月走金丸。", "高岸城池固，平田井牧寬。", "京塵障遊日，從子稅征鞍。"]'),
('5740b7a5-03bb-4e78-8083-df34fc507d27','題茅山潑墨池慶雲庵','劉宰','宋','宋诗','song-poetry','','[]','路轉幾山腰，地尋雙海眼。',48,'全唐诗/poet.song.181000.json','["路轉幾山腰，地尋雙海眼。", "澗咽呂公泉，橋橫蜀道棧。", "主人去不歸，山空春事晚。", "何時具蔬筍，開門延客飯。"]'),
('935a1fd0-694c-4c61-8ef8-ab0fffa6bea3','寄宜興趙大夫二首  其一','劉宰','宋','宋诗','song-poetry','','[]','勝地古陽羨，清才今長官。',48,'全唐诗/poet.song.181000.json','["勝地古陽羨，清才今長官。", "能令三害遠，坐使四民安。", "勿謂時無幾，仍防弊有端。", "做成循吏樣，傳與世人看。"]'),
('f52a8825-e60c-4c6f-a5f5-a99f2015a2d9','寄宜興趙大夫二首  其二','劉宰','宋','宋诗','song-poetry','','[]','去接鴛行侶，猶憐鶴髮翁。',48,'全唐诗/poet.song.181000.json','["去接鴛行侶，猶憐鶴髮翁。", "連翩致嘉實，多旨薦清空。", "往見孤成約，酬知有樸忠。", "金張渠爾耳，相閥自清風。"]'),
('7b8e1577-34f7-40cd-9c31-8e615e5b3c7a','苦雨遣興','劉宰','宋','宋诗','song-poetry','','[]','老去身何有，時危念苦深。',48,'全唐诗/poet.song.181000.json','["老去身何有，時危念苦深。", "朝陽方借煖，宿靄又成陰。", "梁楚安巢少，關河去鳥沉。", "誰歌出塞曲，慷慨百年心。"]'),
('ea377606-2cfc-49df-a820-1c87bf93ceaf','答王虞卿邀遊山','劉宰','宋','宋诗','song-poetry','','[]','墨池催勝遊，虞卿枉真蹟。',48,'全唐诗/poet.song.181000.json','["墨池催勝遊，虞卿枉真蹟。", "我行浩無期，君歸定何日。", "非憂年歲晚，自嘆機會失。", "空煩日卓午，蔬飯滿香積。"]'),
('10cc701a-8a96-49e0-b0ee-55fb08d6f8ea','碧雲即事','劉宰','宋','宋诗','song-poetry','','[]','唧唧秋蛩鳴，耿耿秋夜長。',48,'全唐诗/poet.song.181000.json','["唧唧秋蛩鳴，耿耿秋夜長。", "簡編負初心，枕簟怯新涼。", "朝曦入疎牖，宿雲散前岡。", "歸歟一葉舟，浩歌聽滄浪。"]'),
('94e95c92-b3b6-4c03-8da4-ccbaa96ccfbf','送黄竹磵','劉宰','宋','宋诗','song-poetry','','[]','湘流不盡恨，楚客賦離騷。',48,'全唐诗/poet.song.181000.json','["湘流不盡恨，楚客賦離騷。", "世已殊於古，君奚罕所遭。", "羈懷便酒聖，野興挾詩豪。", "醉裏擡詩眼，山空月色高。"]'),
('4e938049-8f90-49c3-ab84-b263732677cb','雲邊喜潘兄見訪','劉宰','宋','宋诗','song-poetry','','[]','年衰病愈難，學廢朋來少。',48,'全唐诗/poet.song.181000.json','["年衰病愈難，學廢朋來少。", "聞子剝啄聲，慰我精廬悄。", "高談極今古，遠識到微眇。", "願君緘此言，勿貽俗子誚。"]'),
('e5e5f7f1-91a2-423e-ad55-f5c623024055','題真州廣惠倉倉即故船場居南樓及天寧寺後中有大池塔影浸其中','劉宰','宋','宋诗','song-poetry','','[]','淅淅風摇叢葦，霏霏雨弄新晴。',56,'全唐诗/poet.song.181000.json','["淅淅風摇叢葦，霏霏雨弄新晴。", "坐對江南山色，往來無限離情。", "塔影參差波面，歌聲宛轉樓頭。", "已負少年行樂，更輸衲子清幽。"]'),
('90c08958-4aa6-4146-b09e-16efb8049d18','送陳內機棄官還','劉宰','宋','宋诗','song-poetry','','[]','一官已判歸休，五斗何須外求。',56,'全唐诗/poet.song.181000.json','["一官已判歸休，五斗何須外求。", "違己莫詢田父，折腰免見督郵。", "身寄紅蓮綠幕，夢餐翠柏丹霞。", "歸去聊尋舊隠，功名盍付渠家。"]'),
('33f8dd42-5ce3-48db-9a69-2e8b7d76132c','代賦壽寧宗潜邸','劉宰','宋','宋诗','song-poetry','','[]','聖學家傳自有師，更羅英俊侍經帷。',64,'全唐诗/poet.song.181000.json','["聖學家傳自有師，更羅英俊侍經帷。", "治功尚論唐虞際，政體寧甘漢晉卑。", "猥向梁園陪末坐，敢憑堯歷記佳期。", "羞囊已辦詩千首，準擬年年薦壽巵。"]'),
('334fa258-c7be-45c9-a2e5-cf3ca13d210e','和真州太守營屋新成之韻三首  其一','劉宰','宋','宋诗','song-poetry','','[]','長淮清晏久無虞，官舍人煙已復初。',64,'全唐诗/poet.song.181000.json','["長淮清晏久無虞，官舍人煙已復初。", "共喜輿圖方日闢，詎應卒伍尚星居。", "四營分創因遺址，百堵周圍列聚廬。", "武備既嚴軍氣壯，豈專捍禦奠州閭。"]'),
('54cdd1cc-b04b-46df-a0d8-cf8b49a93db3','和真州太守營屋新成之韻三首  其二','劉宰','宋','宋诗','song-poetry','','[]','東南列將謹防虞，尚記熙寧變法初。',64,'全唐诗/poet.song.181000.json','["東南列將謹防虞，尚記熙寧變法初。", "一自胡雛飲江水，遂令卒伍雜民居。", "炊煙不斷雲橫壘，清夜無譁月滿廬。", "妙用獨推賢太守，征徭元不到鄉閭。"]'),
('79e45c45-8818-438b-96c7-56844603eef5','和真州太守營屋新成之韻三首  其三','劉宰','宋','宋诗','song-poetry','','[]','經始南風詠有虞，落成候筦報秋初。',64,'全唐诗/poet.song.181000.json','["經始南風詠有虞，落成候筦報秋初。", "連甍盡撤編茅舊，萬竈重新列屋居。", "千里只今成保障，一廛誰復等蘧廬。", "何人袖出如椽筆，爲寫豐功揭里閭。"]'),
('b6082c79-f713-4d0d-be28-27b9e79e2dff','和淮漕八月十四夜月詩二首  其一','劉宰','宋','宋诗','song-poetry','','[]','清涼景界限塵紛，玉宇從容靜夜分。',64,'全唐诗/poet.song.181000.json','["清涼景界限塵紛，玉宇從容靜夜分。", "欲滿尚慳今夜月，乍舒還斂北山雲。", "孤光翻動枝頭鵲，餘暈潛驅草際蚊。", "好處欲言人不解，湛然天宇印心君。"]'),
('935245aa-78c0-47f4-bc9d-3d0b25802c7a','和淮漕八月十四夜月詩二首  其二','劉宰','宋','宋诗','song-poetry','','[]','長淮百穀慶西成，萬里何妨共此晴。',64,'全唐诗/poet.song.181000.json','["長淮百穀慶西成，萬里何妨共此晴。", "霖雨尚關天下望，月華猶幸晚來明。", "要看玉宇清光滿，聞道銀河此去平。", "邂逅西風輕借力，夜深桂影更敷榮。"]'),
('84bad545-5a34-4990-b1f7-e0734af0768a','中秋月有雲翳再用韻','劉宰','宋','宋诗','song-poetry','','[]','孤城急鼓轉嚴更，步屧中庭午夜晴。',64,'全唐诗/poet.song.181000.json','["孤城急鼓轉嚴更，步屧中庭午夜晴。", "人世昏昏同夢寐，使星耿耿伴清明。", "雲開霄漢光華遠，望極關河眼界平。", "想見登臨無限意，此身那復計浮榮。"]'),
('361e7f94-5148-49ad-b500-f4d4455d142b','儀真和同官韻二首  其一','劉宰','宋','宋诗','song-poetry','','[]','先生文采似班揚，俗子何能較短長。',64,'全唐诗/poet.song.181000.json','["先生文采似班揚，俗子何能較短長。", "顧我未知全璧否，期君聊復善刀藏。", "壯懷欲寫須更僕，勝日能來對舉觴。", "青紫不須分失得，舊游多少困槐黄。"]'),
('61fd6e54-6e01-4dcb-b276-487605a53c0b','儀真和同官韻二首  其二','劉宰','宋','宋诗','song-poetry','','[]','簿書塵裏見清揚，握手論心味更長。',64,'全唐诗/poet.song.181000.json','["簿書塵裏見清揚，握手論心味更長。", "何日山林共歸去，故園花竹可遊藏。", "顔徒自樂一瓢飲，漢殿爭陪萬壽觴。", "馬革裹屍成底事，要須高卧到羲皇。"]'),
('0fb06b57-59f4-49d3-9c95-2adba8564b86','北固山望揚州懷古','劉宰','宋','宋诗','song-poetry','','[]','北固城高萬象秋，煙竿一縷認揚州。',64,'全唐诗/poet.song.181000.json','["北固城高萬象秋，煙竿一縷認揚州。", "試乘綠漲三篙水，要見朱簾十里樓。", "淚濕宮衣朝霧重，愁薰寒草夕陽浮。", "隋堤舊事無人問，兩兩垂楊繫客舟。"]'),
('444a39a8-f3db-412a-b74b-85372aa66d91','懷林維國二首  其一','劉宰','宋','宋诗','song-poetry','','[]','四海論交二十年，知心一見似前緣。',64,'全唐诗/poet.song.181000.json','["四海論交二十年，知心一見似前緣。", "情親尚記通宵語，忠告難忘送別篇。", "夢入蓬壺重會面，座看書史尚堆前。", "應憐廢學從農圃，要使留心在簡編。"]'),
('808430d3-53e9-4b2b-8934-0ccbcf1ce71f','懷林維國二首  其二','劉宰','宋','宋诗','song-poetry','','[]','尚記升堂拜母時，滿前兒女競牽衣。',64,'全唐诗/poet.song.181000.json','["尚記升堂拜母時，滿前兒女競牽衣。", "鳳雛想見今成立，鴈序遥聞已奮飛。", "身後聲名終不朽，家傳詩禮足相輝。", "傷心白下金陵道，無復班荆話昨非。"]'),
('af4e571a-edd2-4124-aaec-8351347d1a49','送友人赴省試','劉宰','宋','宋诗','song-poetry','','[]','月滿千門夜未央，憶陪多士湊文場。',64,'全唐诗/poet.song.181000.json','["月滿千門夜未央，憶陪多士湊文場。", "露將寒透銀袍冷，興與秋來筆力剛。", "十載轉頭成昨夢，一身爲客尚他鄉。", "爲言桂苑聯鑣客，要折高枝壓衆芳。"]'),
('51441627-171b-4222-b530-e2160af35f0c','送趙子野歸','劉宰','宋','宋诗','song-poetry','','[]','秦淮契闊幾經春，釣月臨風入夢頻。',64,'全唐诗/poet.song.181000.json','["秦淮契闊幾經春，釣月臨風入夢頻。", "萬竈無譁新號令，一樽相屬舊慇懃。", "綠波南浦予回棹，落日孤城子問津。", "聚散雲萍渾若此，臨分一笑大江濱。"]'),
('df8b2559-3955-4aaf-bbfb-b66d3aea9d0a','送恭叔兄赴省二首  其一','劉宰','宋','宋诗','song-poetry','','[]','秋薦吳江北鴈來，幾看文陣奪標回。',64,'全唐诗/poet.song.181000.json','["秋薦吳江北鴈來，幾看文陣奪標回。", "鴒飛鵲喜情何限，龍化鵬摶兆有開。", "禮部定知當一得，大廷端可壓羣才。", "春秋正學非阿世，莫作公孫愧草萊。"]'),
('f95ecf1d-3259-4e0e-9753-783ec1178063','送恭叔兄赴省二首  其二','劉宰','宋','宋诗','song-poetry','','[]','睎驥長慚馬不前，著鞭何意在君先。',64,'全唐诗/poet.song.181000.json','["睎驥長慚馬不前，著鞭何意在君先。", "須懲牛後羞餘子，獨占鰲頭下九天。", "上苑未須誇得意，道山共擬便登仙。", "雖然富貴浮雲等，要使功名在簡編。"]'),
('2aa5b635-6284-4cb0-8227-e52f3764ac5d','過蘭亭','劉宰','宋','宋诗','song-poetry','','[]','茂林修竹翠參天，一水西爲尚折旋。',64,'全唐诗/poet.song.181000.json','["茂林修竹翠參天，一水西爲尚折旋。", "欲泛羽觴追往事，悵無嘉客繼前賢。", "短章回寄二三友，勝踐堪尋八百年。", "笑拂蒼崖題姓字，爲言曾此掬流泉。"]'),
('d3763030-d956-4a17-9168-f8f55142778c','喜王節夫過訪','劉宰','宋','宋诗','song-poetry','','[]','我方丱角子勝冠，我老君猶鬢未斑。',64,'全唐诗/poet.song.181000.json','["我方丱角子勝冠，我老君猶鬢未斑。", "可但孤生多疾疢，也輸華館富清閒。", "交情敢忘鶑求友，野性終便鹿在山。", "何日歸歟同里社，杖藜來往翠微間。"]'),
('90cfb8c8-13a1-408c-aee1-e2b518c484d8','用韻寄陳仲思聞有詩它贈而不見及','劉宰','宋','宋诗','song-poetry','','[]','之子才宜獬豸冠，我纔童丱即窺斑。',64,'全唐诗/poet.song.181000.json','["之子才宜獬豸冠，我纔童丱即窺斑。", "溟鵬已擊三千里，天驥猶遺十二閑。", "五字飽聞傳有位，尺書枉用到窮山。", "春風得句能相寄，待我猶存季孟間。"]'),
('6a921d45-48a7-43eb-ab4c-1b68d2289cdc','再用韻戲答陳仲思','劉宰','宋','宋诗','song-poetry','','[]','一讀新詩一解顔，天孫機杼錦斕斑。',64,'全唐诗/poet.song.181000.json','["一讀新詩一解顔，天孫機杼錦斕斑。", "致師自昔能無語，瞥眼君宜付等閑。", "風定波濤收萬壑，雲歸紫翠出千山。", "論交早歲今華髮，少有猜疑愧兩間。"]'),
('d30b0624-6707-4e07-8ff2-0a1aaca14ab9','賀陳子揚致仕追贈父母二首  其一','劉宰','宋','宋诗','song-poetry','','[]','一念平生在報親，九原今日喜追榮。',64,'全唐诗/poet.song.181000.json','["一念平生在報親，九原今日喜追榮。", "鼎來天上維新渥，足慰人間罔極情。", "康樂弟兄傳絕唱，胡威父子擅清名。", "君家盛事人難及，倦客聞風亦眼明。"]'),
('2e4a3e01-15bf-49d3-a128-4ef9434e207c','賀陳子揚致仕追贈父母二首  其二','劉宰','宋','宋诗','song-poetry','','[]','一笑相逢意自親，別來庭樹幾枯榮。',64,'全唐诗/poet.song.181000.json','["一笑相逢意自親，別來庭樹幾枯榮。", "流傳郢客陽春句，想見鴟夷萬里情。", "賈傅才能通國體，柳州文字占時名。", "何如一棹洮湖去，獨泛滄波弄月明。"]'),
('11c00f32-b9d5-452a-b19b-7b53778df80d','代李居士謁王去非制幹三首  其一','劉宰','宋','宋诗','song-poetry','','[]','家山目斷古幽州，百口來歸路阻脩。',64,'全唐诗/poet.song.181000.json','["家山目斷古幽州，百口來歸路阻脩。", "丁字無端輕介胄，蟬冠却羨出兜鍪。", "箕裘忍墜先人業，甔石誰爲客子謀。", "不惜饑寒同一死，南來恐作北人羞。"]'),
('5f4213dc-db0b-433b-a8fa-439761713f27','代李居士謁王去非制幹三首  其二','劉宰','宋','宋诗','song-poetry','','[]','僑居無地寄生涯，布襪青鞋著處家。',64,'全唐诗/poet.song.181000.json','["僑居無地寄生涯，布襪青鞋著處家。", "太乙虛舟想蓮葉，玄都活計問桃花。", "不堪衆稚貧爲累，坐使孤生髮半華。", "儻許侏儒均賦粟，不妨老子自餐霞。"]'),
('9e6e9341-2dfa-4c7d-a90e-dfbe12977d9d','代李居士謁王去非制幹三首  其三','劉宰','宋','宋诗','song-poetry','','[]','一來寒谷轉春風，百萬喁喁說此翁。',64,'全唐诗/poet.song.181000.json','["一來寒谷轉春風，百萬喁喁說此翁。", "坐見西州成俗阜，忍令北客尚途窮。", "籌邊聞道無遺策，幕府流傳已上功。", "便有細書催入覲，早回生意一言中。"]'),
('919a05e6-5327-42a1-9c06-ed58b23487b7','寄潘子善上舍','劉宰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','少陽一疏折羣姦，拂袖歸來日月閒。',64,'全唐诗/poet.song.181000.json','["少陽一疏折羣姦，拂袖歸來日月閒。", "誤國小人猶法從，叩閽諸子自賢關。", "是非頗亦通千古，義利那能立兩間。", "若向西湖浮畫舫，好傾巵酒酹孤山。"]'),
('f80d60ce-7057-43b8-882e-c5ed23808ea7','送邵監酒兼柬儀真趙法曹呈潘使君二首  其一','劉宰','宋','宋诗','song-poetry','','[]','儀真來往幾經秋，風物淮南第一州。',64,'全唐诗/poet.song.181000.json','["儀真來往幾經秋，風物淮南第一州。", "山勢北來開壯觀，大江東下峙危樓。", "沙頭縹緲千家市，艫尾連翩萬斛舟。", "去去煩君問耆老，幾人猶得守林丘。"]'),
('e32ef771-d0a7-4260-9a44-c09faa8a6679','送邵監酒兼柬儀真趙法曹呈潘使君二首  其二','劉宰','宋','宋诗','song-poetry','','[]','十萬流離仰二天，淮民只說使君賢。',64,'全唐诗/poet.song.181000.json','["十萬流離仰二天，淮民只說使君賢。", "向來積貯知無有，此去規模要有傳。", "幼學可能傳榷酤，遠猷無惜助籌邊。", "公餘更向髯參問，今賦梅花第幾篇。"]'),
('86259c82-bffc-4308-acd7-b943e785fc51','懷徐表兄','劉宰','宋','宋诗','song-poetry','','[]','一笑相逢句曲天，別來十五換流年。',64,'全唐诗/poet.song.181000.json','["一笑相逢句曲天，別來十五換流年。", "忍思渭上瓊瑰詠，無復通泉寶劍篇。", "北渚春回芳樹合，西山日暮碧雲連。", "鴈來數寄平安信，無限相思若箇邊。"]'),
('b0e1194c-4e7a-4765-9ec7-0694b53ba488','偶題雲邊','劉宰','宋','宋诗','song-poetry','','[]','桃花山下水流長，花不長開水自香。',64,'全唐诗/poet.song.181000.json','["桃花山下水流長，花不長開水自香。", "此地正須招隠士，山菴聊復對崇岡。", "屏幃繚繞竹千箇，旌纛森嚴柏兩行。", "士會不生今已矣，不妨閒處且徜徉。"]'),
('18c1bbee-ab0e-48a1-b48a-312cdc751452','送友人','劉宰','宋','宋诗','song-poetry','','[]','年來去客半西東，須信勞生等轉蓬。',64,'全唐诗/poet.song.181000.json','["年來去客半西東，須信勞生等轉蓬。", "萬里相望成別恨，一聲何處遞冥鴻。", "人情對景分憂樂，月色於今豈異同。", "莫把壯懷成索寞，舉盃聊與吸清風。"]'),
('cc3d4280-793e-426f-8080-8d4adee81f89','毗陵邂逅京口同舍湯叔厚','劉宰','宋','宋诗','song-poetry','','[]','雞犬相聞里社同，琴書曾共客儒宮。',64,'全唐诗/poet.song.181000.json','["雞犬相聞里社同，琴書曾共客儒宮。", "南樓夜醉三更月，北固秋吟萬里風。", "去魯羨君勤采藻，游吳愧我尚飄蓬。", "相逢便與論心曲，莫笑依然舊阿蒙。"]'),
('6185a36f-53df-4c24-b73a-77bf1feb8ece','和張寺丞謝惠河魨韻二首  其一','劉宰','宋','宋诗','song-poetry','','[]','先生盛德信光亨，微物將誠愧晚生。',64,'全唐诗/poet.song.181000.json','["先生盛德信光亨，微物將誠愧晚生。", "春岸正當餘雨過，寒江尚想小舟橫。", "一奩走送慚遲暮，兩舍相望欠割烹。", "未必甘芹解知味，王公當諒野人情。"]'),
('81fa4dc5-1fcb-44c7-8409-adb1f02b6a96','和張寺丞謝惠河魨韻二首  其二','劉宰','宋','宋诗','song-poetry','','[]','鼎來佳句仰謙亨，春入池塘草正生。',64,'全唐诗/poet.song.181000.json','["鼎來佳句仰謙亨，春入池塘草正生。", "清夜擬陪簷雨酌，暮天應對碧雲橫。", "逍遥莊叟一枝穩，富貴齊人五鼎烹。", "戟衛肅迎揮手去，蘇州應愧此時情。"]'),
('b08eb414-3818-4bec-af7d-7ff8e6295ee2','和傅侍郎鹿鳴宴韻二首  其一','劉宰','宋','宋诗','song-poetry','','[]','向來北固萃群英，可但江山擅美名。',64,'全唐诗/poet.song.181000.json','["向來北固萃群英，可但江山擅美名。", "秀氣中間空畚築，斯文今日遇權衡。", "歌成白雪傳新唱，帆飽西風趣去程。", "會體使君珍重意，不專車馬羨桓榮。"]'),
('4892382a-453b-4242-b110-8a898aee2eb8','和傅侍郎鹿鳴宴韻二首  其二','劉宰','宋','宋诗','song-poetry','','[]','先生讜論在延英，早歲金甌已覆名。',64,'全唐诗/poet.song.181000.json','["先生讜論在延英，早歲金甌已覆名。", "自古正人羞枉尺，祇今公論有持衡。", "九重聞道將飛詔，一水何妨緩作程。", "莫笑田家去天遠，春來野草亦敷榮。"]'),
('529b542a-bb25-4ab7-bed4-6f8656663d51','和湯叔永二首  其一','劉宰','宋','宋诗','song-poetry','','[]','魯人豈解識東丘，夫子猶懷去魯憂。',64,'全唐诗/poet.song.181000.json','["魯人豈解識東丘，夫子猶懷去魯憂。", "公論世間誰了了，德人心事本休休。", "致身官路雖非遠，回首家山盍少留。", "三徑未荒松菊在，天涯多少望鄉愁。"]'),
('5163932a-3c9d-44a4-826d-1629c00f8152','和湯叔永二首  其二','劉宰','宋','宋诗','song-poetry','','[]','底須彈鋏嘆無家，自有詩人賦子嗟。',64,'全唐诗/poet.song.181000.json','["底須彈鋏嘆無家，自有詩人賦子嗟。", "平世豈應遺燭武，暮年安可傅長沙。", "爲隣幸賜千金諾，進德相期一簣加。", "欲泛五湖觀浩渺，興來還可共浮槎。"]'),
('2ce58e40-5db4-4696-b9fd-7400f079aa22','送姜君玉赴省試','劉宰','宋','宋诗','song-poetry','','[]','樽酒論文弱冠前，交情老去只依然。',64,'全唐诗/poet.song.181000.json','["樽酒論文弱冠前，交情老去只依然。", "久荒三徑無來客，細撥青燈話昔年。", "少日功名誰汗簡，舊遊江海半華顛。", "君行試問都門柳，幾送銀袍上九天。"]'),
('26ac6ba7-2483-419a-9b45-a9926b86cbea','送彥與孫兄赴廷對','劉宰','宋','宋诗','song-poetry','','[]','捷書夜到古朱方，之子登名甲乙行。',64,'全唐诗/poet.song.181000.json','["捷書夜到古朱方，之子登名甲乙行。", "偉行向來高月旦，遺經端合破天荒。", "公孫對策風雲會，董子留名日月光。", "趨向一分燕越異，贈言惟有用心剛。"]'),
('4bde4e97-acb3-4fee-91f8-96429de190c7','夢使高麗到東海口占','劉宰','宋','宋诗','song-poetry','','[]','夢魂飛到碧霄東，日出扶桑萬丈紅。',64,'全唐诗/poet.song.181000.json','["夢魂飛到碧霄東，日出扶桑萬丈紅。", "窗戶曈曚開曉色，園林淡蕩已春風。", "時平正使車書混，天遠那能玉帛通。", "萬事悠悠均夢爾，一樽聊與故人同。"]'),
('e379e649-9d1e-4a00-abbd-3dcb22546b03','代柬答合淝蘇刑曹兼呈淮西帥同年趙寶謨二首  其一','劉宰','宋','宋诗','song-poetry','','[]','青衫擬掾襲芳塵，短褐歸來理釣緡。',64,'全唐诗/poet.song.181000.json','["青衫擬掾襲芳塵，短褐歸來理釣緡。", "二紀期君紹先烈，一官投老祇參軍。", "宦情自與秋光薄，公論猶期歲晚伸。", "見說宗工好風鑒，薦書何日到嚴宸。"]'),
('2c2ad7be-e4de-4502-aaca-367449b0f80b','代柬答合淝蘇刑曹兼呈淮西帥同年趙寶謨二首  其二','劉宰','宋','宋诗','song-poetry','','[]','聞道中原百戰餘，遺民億萬企來蘇。',64,'全唐诗/poet.song.181000.json','["聞道中原百戰餘，遺民億萬企來蘇。", "浪言恢復真疎矣，絕意懷來亦可乎。", "北望凄凉皆故土，南來睥睨幾狂胡。", "祇今淝水山川改，寄語元戎盍遠圖。"]'),
('2b68f084-98fc-4c0f-be81-1fb423237d5d','送友人','劉宰','宋','宋诗','song-poetry','','[]','凜凜霜臺起事功，翛翛三徑任窮通。',64,'全唐诗/poet.song.181000.json','["凜凜霜臺起事功，翛翛三徑任窮通。", "幾因節物傷離別，無奈行藏苦異同。", "白露感懷悲杜老，黄樓得句憶坡翁。", "鴈行何日齊飛去，岸幘相看酒一中。"]'),
('b5384d92-85bf-4fd3-99d4-23a4dbc11d7a','柬施上舍','劉宰','宋','宋诗','song-poetry','','[]','萬里秋光酒一鍾，別來木末幾西風。',64,'全唐诗/poet.song.181000.json','["萬里秋光酒一鍾，別來木末幾西風。", "懷人滾滾東流水，問訊冥冥北去鴻。", "愧我形容難似舊，喜君意氣尚摩空。", "相逢莫怪深相問，一笑猶疑是夢中。"]'),
('f3a62702-0c4d-47f3-b844-b37f7f0306aa','代譚與可謝石大夫鄉飲酒','劉宰','宋','宋诗','song-poetry','','[]','大夫舉酒屬青衿，八十衰翁亦許臨。',64,'全唐诗/poet.song.181000.json','["大夫舉酒屬青衿，八十衰翁亦許臨。", "要向席間明厚意，敢辭酒半效狂吟。", "持身勿使虧名義，學古還須探聖心。", "元日習鄉君解否，須知齒髮易駸駸。"]'),
('fd83e4b6-a7e6-40b2-8fa0-84bf3b3b62a3','勉王甥','劉宰','宋','宋诗','song-poetry','','[]','莘野凄涼渭水遥，事功無復在漁樵。',64,'全唐诗/poet.song.181000.json','["莘野凄涼渭水遥，事功無復在漁樵。", "但令一第先餘子，自可清名動聖朝。", "禁路家聲猶赫奕，詞場筆勢已嫖姚。", "夜窗燈火秋來好，莫歎辛勤髀肉消。"]'),
('fbf44057-8c9e-4b45-8114-9118d4284510','送鍾元達赴餘杭','劉宰','宋','宋诗','song-poetry','','[]','知音十九在巖廊，姓字高懸日月旁。',64,'全唐诗/poet.song.181000.json','["知音十九在巖廊，姓字高懸日月旁。", "視草祇今虛省署，種花聊復向河陽。", "困窮已甚情當察，富貴徐來味更長。", "梵宇仙宮最佳處，詩成數寄水雲鄉。"]'),
('7e88c041-3c2c-4a82-a1cc-403aaeca9489','送王去非入餉幕','劉宰','宋','宋诗','song-poetry','','[]','春歸花藥尚紅酣，送子脂車馬在驂。',64,'全唐诗/poet.song.181000.json','["春歸花藥尚紅酣，送子脂車馬在驂。", "幕畫向來多實用，事機今可付常談。", "學方用力須千百，事或當仁勿二三。", "別後欲知漁釣處，五湖天水共澄涵。"]'),
('489efab9-0999-42ed-97b6-9fa7ede11fca','雨後口占呈陳校書','劉宰','宋','宋诗','song-poetry','','[]','下田已漫高田槁，太守來遲歸苦早。',64,'全唐诗/poet.song.181000.json','["下田已漫高田槁，太守來遲歸苦早。", "忽傳亞倅府中來，太守停驂尚精禱。", "前日應禱五日期，今朝好雨隨車歸。", "遲速有期君解否，太守束裝留不久。"]'),
('854eb9ca-65fd-4591-a6fb-da2392b91ee5','送石令君','劉宰','宋','宋诗','song-poetry','','[]','攀轅父老雜兒童，十載重欣見此風。',64,'全唐诗/poet.song.181000.json','["攀轅父老雜兒童，十載重欣見此風。", "可但三年方論定，亦由去日與初同。", "一塵不染冰常瑩，萬折難回水必東。", "正直自應神所介，人心况有是非公。"]'),
('3abfe93a-a38a-4c81-9601-b804f85fb965','和羅權丞尊經閣元旦觀雪','劉宰','宋','宋诗','song-poetry','','[]','億萬饑民久籲天，天開上瑞豈徒然。',64,'全唐诗/poet.song.181000.json','["億萬饑民久籲天，天開上瑞豈徒然。", "深潭龜拆寒莎底，淺土蝗遺宿麥邊。", "厲氣已消除日後，祥霙飛墮曉風前。", "醉吟樓上瀛洲客，爲記三登第一年。"]'),
('fac47ab2-87a0-4b3f-82ee-d53320e20e8a','送衛汝積歸句曲','劉宰','宋','宋诗','song-poetry','','[]','樓岡亭谷萬山西，縹緲炊煙出翠微。',64,'全唐诗/poet.song.181000.json','["樓岡亭谷萬山西，縹緲炊煙出翠微。", "歸路正當清晝永，離懷莫悵白雲飛。", "學醫要使人無費，問道須知昨已非。", "好向庭闈商略此，短章中或有玄機。"]'),
('9618367a-e481-43e5-8992-5ac5451643d3','送杜尉秩滿還天台','劉宰','宋','宋诗','song-poetry','','[]','眼看時事廢因循，官路三年子獨勤。',64,'全唐诗/poet.song.181000.json','["眼看時事廢因循，官路三年子獨勤。", "袖有新詩頻教我，邑無長策可留君。", "向來過計憂周隕，此去何時靜楚氛。", "未必詩書盡虛語，勉哉行矣張吾軍。"]'),
('3f08379e-6393-41f1-81ba-365f5623c05d','送羅季能還延陵鎮','劉宰','宋','宋诗','song-poetry','','[]','眼底紛紛利欲昏，君心當與哲人論。',64,'全唐诗/poet.song.181000.json','["眼底紛紛利欲昏，君心當與哲人論。", "俗塵不染脩莖露，世味逾輕太古尊。", "朞月此來當歲儉，寒冬何地不春溫。", "幡然不憚延陵去，季子清風百世存。"]'),
('5355d3c2-714d-4cd2-a14f-291a9639abf4','謝朱仲玉二首  其一','劉宰','宋','宋诗','song-poetry','','[]','君家只隔小橋西，幾度占星望少微。',64,'全唐诗/poet.song.181000.json','["君家只隔小橋西，幾度占星望少微。", "已向龍墀攄大對，不應鸞翼尚低飛。", "杖藜喜逐先生後，斂板誰知故我非。", "欲學丘江吟短句，錦文試覓景陽機。"]'),
('fc0b01aa-d5a7-447d-ae47-7e2528c58d05','謝朱仲玉二首  其二','劉宰','宋','宋诗','song-poetry','','[]','夫子知名浙水西，妙年奧學洞幾微。',64,'全唐诗/poet.song.181000.json','["夫子知名浙水西，妙年奧學洞幾微。", "一官簿領身如寄，萬里雲霄步若飛。", "詩苦何妨同杜老，說難終不羨韓非。", "擬酬白雪陽春句，願借天孫織女機。"]'),
('c5fb99c3-5927-490b-bfd5-7f7154e459f8','仲玉和前詩見贈因再用韻','劉宰','宋','宋诗','song-poetry','','[]','官倉出粟徧東西，多謝朱公念隠微。',64,'全唐诗/poet.song.181000.json','["官倉出粟徧東西，多謝朱公念隠微。", "但覺閭閻猶菜色，不知園囿已花飛。", "當年國論無同異，此日民言有是非。", "天上鴛鴻方刷羽，海邊鷗鷺已忘機。"]'),
('380d6a60-4d68-46ca-8b89-d45eb67ef3dd','謝湯生惠酒和來韻','劉宰','宋','宋诗','song-poetry','','[]','聞道吾猶及老成，高秋離索不勝情。',64,'全唐诗/poet.song.181000.json','["聞道吾猶及老成，高秋離索不勝情。", "朋緘已喜賢從事，二缶那堪對麯生。", "多病吾今同退鷁，壯懷君可掣長鯨。", "能來共醉西風否，木落千山夕照明。"]'),
('c1d02ecc-9373-4669-9b61-365d4f6c22c6','奉酬友人登多景樓見懷','劉宰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','雲橫不斷古神州，縹緲河山總戍樓。',64,'全唐诗/poet.song.181000.json','["雲橫不斷古神州，縹緲河山總戍樓。", "此地幾經人北顧，長江不住水東流。", "犬羊萬里知離穴，稻蟹三吳正得秋。", "人事天時多錯忤，一盃聊復潤吟喉。"]'),
('fa98df31-f8a6-4e4c-a1af-7816b828d96b','代書答龔楚州','劉宰','宋','宋诗','song-poetry','','[]','使君問政及郊扉，病叟何能措一辭。',64,'全唐诗/poet.song.181000.json','["使君問政及郊扉，病叟何能措一辭。", "積粟鼂生真至計，屯田充國亦良規。", "將權可與他人共，德意須令舊壤知。", "聞說鹽城有真令，相逢爲說每相思。"]'),
('c143785a-c70a-433e-a91f-f594a810e126','漫塘晚望','劉宰','宋','宋诗','song-poetry','','[]','霽色催雲作晚霞，小橋却立岸烏紗。',64,'全唐诗/poet.song.181000.json','["霽色催雲作晚霞，小橋却立岸烏紗。", "雨餘菱芡新抽葉，秋早菰蒲未著花。", "燈影微茫行客艇，鐘聲縹緲梵王家。", "沉吟索句輸公等，我欲臨流理釣槎。"]'),
('f10c8ac0-c689-488d-afaa-81e7f5ddf6ac','寄陸大夫','劉宰','宋','宋诗','song-poetry','','[]','寄語金淵陸大夫，歸田相府竟何如。',64,'全唐诗/poet.song.181000.json','["寄語金淵陸大夫，歸田相府竟何如。", "提兵劫取已非矣，縱火燒殘豈義歟。", "百口喪身端自爾，千錢酬直殆欺余。", "放翁舊隠佳山水，賸好歸歟理故書。"]'),
('7ec7a8f9-489e-4d38-bd8a-a20745f638ca','送鍾元達倅濠','劉宰','宋','宋诗','song-poetry','','[]','喜見弦歌近帝京，又分風月向邊城。',64,'全唐诗/poet.song.181000.json','["喜見弦歌近帝京，又分風月向邊城。", "時方急士國家計，事不辭難臣子情。", "塞下規模鼂御史，湟中勳業趙營平。", "君行試與重商略，烏鵲南來數寄聲。"]'),
('13c0c6dc-b49f-4432-94c3-7bbcd73824ac','送平江趙法曹','劉宰','宋','宋诗','song-poetry','','[]','金科天上耿星辰，丹筆年來有屈伸。',64,'全唐诗/poet.song.182000.json','["金科天上耿星辰，丹筆年來有屈伸。", "子去平反供母笑，民知寬大頌君仁。", "祇今茂苑題輿客，曾是瓊林合席人。", "若問殘生煩寄語，扁舟長占五湖春。"]'),
('54c1693f-0603-4526-b21b-51bdad584afe','送黄子弘歸吳門','劉宰','宋','宋诗','song-poetry','','[]','玉樓工就故人仙，宿草離離起暮煙。',64,'全唐诗/poet.song.182000.json','["玉樓工就故人仙，宿草離離起暮煙。", "曾說項斯誰復記，尚懷中散子真賢。", "鼎來窮巷方今日，勝讀殘編已十年。", "西望猶能話離索，秋風來共釣魚船。"]'),
('f4064224-c5a4-462f-a28c-aaeaffa8b9cf','代邑士上趙百里','劉宰','宋','宋诗','song-poetry','','[]','美矣吾邦此大夫，仁中有勇信今無。',64,'全唐诗/poet.song.182000.json','["美矣吾邦此大夫，仁中有勇信今無。", "治侔東里興鄉校，政壓西門送女巫。", "謀廣生員來共學，力排淫祀警羣愚。", "一陶風俗成醇厚，千古聲名泰華俱。"]'),
('2164eea9-a506-4028-b715-3210e577c952','社日僧舍風雨','劉宰','宋','宋诗','song-poetry','','[]','借蔬香積共晨炊，客裏良辰總不知。',64,'全唐诗/poet.song.182000.json','["借蔬香積共晨炊，客裏良辰總不知。", "孺子從渠均胙肉，南翁無處聽巴詞。", "神鴉得志飽終日，巢燕有心來及時。", "風雨聒人聾轉甚，半鍾濁酒可能治。"]'),
('705cec76-7c72-4f38-adf8-de916c35563e','寄題戴氏別墅','劉宰','宋','宋诗','song-poetry','','[]','聞君築室水雲鄉，一榻翛然獨老龐。',64,'全唐诗/poet.song.182000.json','["聞君築室水雲鄉，一榻翛然獨老龐。", "近挹荷香供几案，遠邀山翠入軒窗。", "自歌自笑遊鱼樂，時去時來白鳥雙。", "何日過門成夜泊，一樽相與對銀缸。"]'),
('d4203ef7-558f-46c3-923b-2a65cde03ae9','和趙龍圖鹿鳴宴韻二首  其一','劉宰','宋','宋诗','song-poetry','','[]','勸駕丁寧自漢興，禮行郡國玉鏘鳴。',64,'全唐诗/poet.song.182000.json','["勸駕丁寧自漢興，禮行郡國玉鏘鳴。", "使君珍重新開宴，多士連翩喜策名。", "月窟一枝傳好信，風帆千里送脩程。", "主賓後會君知否，紫橐青袍對寵榮。"]'),
('ca1b203a-fcf3-42f4-8253-7388aa92a0c9','和趙龍圖鹿鳴宴韻二首  其二','劉宰','宋','宋诗','song-poetry','','[]','預宴當年記夙興，笙歌堂上正和鳴。',64,'全唐诗/poet.song.182000.json','["預宴當年記夙興，笙歌堂上正和鳴。", "別來幾送龍門客，去後空題雁塔名。", "麋鹿羣中便野性，蜩鳩飛處笑雲程。", "羞肴也到茅簷下，磊塊堆盤里社榮。"]'),
('aa0e15b8-59cd-45e6-aee5-6377242458c7','和趙章泉見寄二首  其一','劉宰','宋','宋诗','song-poetry','','[]','先生人物眇應劉，千載詩亡獨泝流。',64,'全唐诗/poet.song.182000.json','["先生人物眇應劉，千載詩亡獨泝流。", "五字還堪薦郊廟，一官何事老林丘。", "章泉樂處知何似，南澗良朋亦健不。", "欲拜龐公何日是，夢隨飛鶴過山頭。"]'),
('2d007be7-fa1d-43a3-97c8-f1aa3c951a51','和趙章泉見寄二首  其二','劉宰','宋','宋诗','song-poetry','','[]','平生暗裏識曹劉，眼底誰爲第一流。',64,'全唐诗/poet.song.182000.json','["平生暗裏識曹劉，眼底誰爲第一流。", "錦里正應推老杜，魯人亦解說東丘。", "騎馿頗忘推敲否，上馬還能矍鑠不。", "此去相思君會取，菊黄梅蘂上枝頭。"]'),
('d4591478-8ab0-4429-9b6a-170b60b45aa2','用韻煩蔣延陵寄前詩至章泉','劉宰','宋','宋诗','song-poetry','','[]','之子交游柳與劉，朅來聲聞水東流。',64,'全唐诗/poet.song.182000.json','["之子交游柳與劉，朅來聲聞水東流。", "懸知此去居三館，可但當年記九丘。", "滄海狎鷗猶好在，紅塵沒馬肯回不。", "短篇爲寄章泉老，莫聽浮沉付石頭。"]'),
('fe717594-cc7a-4132-be3c-4732334b3b53','謝章泉再以前韻見寄三首  其一','劉宰','宋','宋诗','song-poetry','','[]','白社相從遠與劉，可憐衲子溷儒流。',64,'全唐诗/poet.song.182000.json','["白社相從遠與劉，可憐衲子溷儒流。", "自嗟達巷知夫子，緬想諸荀從太丘。", "書寄洪喬空爾耳，詩編杜集可容不。", "前山底處堪長望，我欲携筇上上頭。"]'),
('4673acf7-3126-46fd-90e1-30953dd13d48','謝章泉再以前韻見寄三首  其二','劉宰','宋','宋诗','song-poetry','','[]','解印歸來白社劉，風流靖節許同流。',64,'全唐诗/poet.song.182000.json','["解印歸來白社劉，風流靖節許同流。", "詩來幾說鶑求友，老去自慚狐首丘。", "會合由來天幸耳，殷勤還識我心不。", "春回是處堪行樂，能復携錢掛杖頭。"]'),
('591f9d68-eb0b-4ed6-b815-bcf2fea0504a','謝章泉再以前韻見寄三首  其三','劉宰','宋','宋诗','song-poetry','','[]','書賢從事我非劉，傑句君爭萬壑流。',64,'全唐诗/poet.song.182000.json','["書賢從事我非劉，傑句君爭萬壑流。", "擬學岑參酬杜甫，可能列子識壺丘。", "倦游審已懸車矣，問字猶多載酒不。", "無限相思梅發處，手摧殘雪嗅枝頭。"]'),
('4e183a0b-0e41-4b92-a168-11105770d13d','和邑大夫勸駕韻','劉宰','宋','宋诗','song-poetry','','[]','自笑當年躍冶金，老來文物見彬彬。',64,'全唐诗/poet.song.182000.json','["自笑當年躍冶金，老來文物見彬彬。", "登名已喜多三邑，擢秀懸知敵萬人。", "晴日琴堂開宴好，春風瓊苑拜恩新。", "惟餘卧病江湖客，坐看聯翩對玉宸。"]'),
('0b0d63fd-b6b1-428d-817b-a8a59b1f4d84','送張端衡尉句容二首  其一','劉宰','宋','宋诗','song-poetry','','[]','梅仙西上古仙鄉，梅蘂先春特地香。',64,'全唐诗/poet.song.182000.json','["梅仙西上古仙鄉，梅蘂先春特地香。", "自是邾人聞魯柝，懸知晉盜避秦疆。", "名山久合清蕪穢，窮巷猶聞缺蓋藏。", "惠政由來要全美，須君努力佐琴堂。"]'),
('335e16a8-1e46-4b76-8d12-851707c80249','送張端衡尉句容二首  其二','劉宰','宋','宋诗','song-poetry','','[]','去鄉喜見似鄉人，君去家山祇比鄰。',64,'全唐诗/poet.song.182000.json','["去鄉喜見似鄉人，君去家山祇比鄰。", "令長垂髫同里社，交承握手記城闉。", "絃歌堂上寧忘舊，樽俎筵中必告新。", "若也從容問無恙，爲言魚鳥已情親。"]'),
('7b8ef311-7ccc-4af2-ab2b-efcc2a6d41a9','送王去非服除造朝','劉宰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','疾風吹雨洗塵寰，北渚津頭水沒灘。',64,'全唐诗/poet.song.182000.json','["疾風吹雨洗塵寰，北渚津頭水沒灘。", "千里送君黄鵠舉，一生笑我白鷗閒。", "清名已至雲霄上，逸氣還充宇宙間。", "此去西湖重回首，淡煙疎柳認孤山。"]'),
('d2611439-cf35-46d3-b86b-1c7e10b57fd9','送張晉望倅湖州','劉宰','宋','宋诗','song-poetry','','[]','風月平分古治中，掛帆直指水晶宮。',64,'全唐诗/poet.song.182000.json','["風月平分古治中，掛帆直指水晶宮。", "祇今第宅多親貴，自昔閭閻有阨窮。", "勿用彌縫乖直道，毋煩歌舞競新功。", "舉頭見日長安近，詔入元非藉子公。"]'),
('248554f1-8208-4901-b003-6b91ee82e3ae','代柬寄張端衡','劉宰','宋','宋诗','song-poetry','','[]','句曲山頭白鶴飛，遥憐綵棒正宣威。',64,'全唐诗/poet.song.182000.json','["句曲山頭白鶴飛，遥憐綵棒正宣威。", "仙家有喜迎仙吏，客路無塵點客衣。", "月澹郊原從犬卧，秋高籬落任雞肥。", "子真東野齊名在，莫向西風苦念歸。"]'),
('569d8e26-e757-49d2-8ea7-ee1d6b6dfa6e','爲布金寺僧慧鑑作呈趙守','劉宰','宋','宋诗','song-poetry','','[]','老樹槎牙記佛廬，露啼蛩弔百年餘。',64,'全唐诗/poet.song.182000.json','["老樹槎牙記佛廬，露啼蛩弔百年餘。", "鼎新堂殿誰爲此，壯觀林泉我弗如。", "身上無華惟布縷，盂中舐味祇山蔬。", "野僧勤瘁能如許，罪或無多乞赦除。"]'),
('5af8e79f-a5d8-4ade-98a2-45049fd44b52','送高桂陽之任二首  其一','劉宰','宋','宋诗','song-poetry','','[]','清才寧合駕緹車，天上新分竹使符。',64,'全唐诗/poet.song.182000.json','["清才寧合駕緹車，天上新分竹使符。", "此去專城重摩撫，向來涉筆幾嗟吁。", "南州想見歌何暮，北府猶聞戒疾驅。", "更恐掖垣須敏手，未應千騎出重湖。"]'),
('c8de9880-dec5-4a4d-b229-49021262ec3b','送高桂陽之任二首  其二','劉宰','宋','宋诗','song-poetry','','[]','一笑相逢此道同，別來木末幾青紅。',64,'全唐诗/poet.song.182000.json','["一笑相逢此道同，別來木末幾青紅。", "自憐老去北窗下，猶得身棲廣厦中。", "良夜擬乘千里月，神山竟隔一帆風。", "贈行更愧留行者，遮道歌翻別駕功。"]'),
('1365cc44-83cf-4328-b855-ada1564e76c6','和趙章泉寄詩韻','劉宰','宋','宋诗','song-poetry','','[]','索居靈瑣久塵埃，一讀新篇病眼開。',64,'全唐诗/poet.song.182000.json','["索居靈瑣久塵埃，一讀新篇病眼開。", "妄意嚴詩編杜集，敢陪郭隗上燕臺。", "紆朱晚歲徒云爾，養素平生壯矣哉。", "更許韓非書傳尾，遺榮何止被雲來。"]'),
('2b149ca2-2899-4174-966d-8f74f0801890','次姜君玉韻且賀北固新居  其一','劉宰','宋','宋诗','song-poetry','','[]','車來流水馬如龍，北上精藍西復東。',64,'全唐诗/poet.song.182000.json','["車來流水馬如龍，北上精藍西復東。", "雅意只貪山在近，高標誰與子相同。", "門開正好來三益，文就何妨送五窮。", "擬向巖前分半席，可能闢地著隣翁。"]'),
('063e8d69-f7b5-4814-86f6-3ce6e99fd929','次姜君玉韻且賀北固新居  其二','劉宰','宋','宋诗','song-poetry','','[]','門外青山跨伏龍，山頭未曉日生東。',64,'全唐诗/poet.song.182000.json','["門外青山跨伏龍，山頭未曉日生東。", "竹林已喜王戎近，蓮社還堪惠遠同。", "盛事正應符地勝，清才豈必坐詩窮。", "欲成善頌陪張老，自笑尊前一禿翁。"]'),
('510c85de-8459-4c50-85c8-f3994e03f20b','送張端袤赴潘葑','劉宰','宋','宋诗','song-poetry','','[]','汲取人間第二泉，釀成天上酌神仙。',64,'全唐诗/poet.song.182000.json','["汲取人間第二泉，釀成天上酌神仙。", "渠儂得此良佳矣，我輩爲之或未然。", "職守近來成漫浪，湖山佳處且回旋。", "向陽花木逢春易，會取聲名動日邊。"]'),
('cd23f079-07dc-4085-a3a4-9c48338eb6b0','和柴監','劉宰','宋','宋诗','song-poetry','','[]','之子通才不受拘，妙年文史足三餘。',64,'全唐诗/poet.song.182000.json','["之子通才不受拘，妙年文史足三餘。", "司征關市方共二，宴啟華堂正樂胥。", "錦帳笙歌香霧繞，禪房風月夜窗虛。", "後生取舍能如此，問信寧非遠器歟。"]'),
('5e8f722a-0858-44f4-8188-1f769f3a7d4c','學門肇開爲諸兄賀','劉宰','宋','宋诗','song-poetry','','[]','幾年黌宇傍城隈，禮樂文章蔽草萊。',64,'全唐诗/poet.song.182000.json','["幾年黌宇傍城隈，禮樂文章蔽草萊。", "逵道一朝隨地闢，宮牆數仞倚天開。", "舉頭日月清光近，入眼湖山秀氣來。", "寄語鄉邦頭角士，龍門此去會風雷。"]'),
('3f13eec4-d796-40d7-8d25-fd6dbde9499b','和尤伯華廣德使君怡亭對雨  其一','劉宰','宋','宋诗','song-poetry','','[]','之子胸中不外營，軒亭水到自渠成。',64,'全唐诗/poet.song.182000.json','["之子胸中不外營，軒亭水到自渠成。", "詞章妙處窺騷雅，師友平生祇弟兄。", "元凱一門兼衆美，夷齊千古擅雙清。", "新詩有贈不知報，衰拙如余盍負荆。"]'),
('4587ad48-4285-4fd8-b2ec-c561ad78e82b','和尤伯華廣德使君怡亭對雨  其二','劉宰','宋','宋诗','song-poetry','','[]','軒亭闓爽喜新營，燕雀應來賀厦成。',64,'全唐诗/poet.song.182000.json','["軒亭闓爽喜新營，燕雀應來賀厦成。", "樽酒兩忘賢與聖，韋編相對弟和兄。", "詩如綉段從頭好，人似冰壺徹底清。", "寄語金昆同石友，道逢何日許班荆。"]'),
('6e1e3f15-4a89-4166-a57e-acd46de61b5d','勉張兄立民作詩','劉宰','宋','宋诗','song-poetry','','[]','翛然風骨一臞仙，誤走紅塵逐世緣。',64,'全唐诗/poet.song.182000.json','["翛然風骨一臞仙，誤走紅塵逐世緣。", "亦欲名同天壤壽，且須句與日星懸。", "後湖廢沼生春草，南郭遺墟起暮煙。", "聞道錦囊時有得，故山花鳥亦欣然。"]'),
('de57a86f-d5af-492d-bd6d-89e6277a7b11','趣劉聖與寓王甫桂墅','劉宰','宋','宋诗','song-poetry','','[]','門外平湖百頃寬，庭前翠竹繞欄干。',64,'全唐诗/poet.song.182000.json','["門外平湖百頃寬，庭前翠竹繞欄干。", "鳥啼花笑四時好，几浄窗明六月寒。", "賸可琴書供晝永，不妨絃管到更闌。", "留行莫爲歌楊柳，作計應須趁牡丹。"]'),
('ae07eb4d-3d48-4137-b3a0-1a080b106134','送戴子家歸永嘉','劉宰','宋','宋诗','song-poetry','','[]','君住柟溪第幾山，我家北渚水雲間。',64,'全唐诗/poet.song.182000.json','["君住柟溪第幾山，我家北渚水雲間。", "二千里遠來非易，三五朝留勿作難。", "有子已知頭角異，安心寧恤鬢毛斑。", "尺書頻寄問無恙，共樂生前日月閒。"]'),
('d802cfee-7b4f-4ad1-a93a-a32747d564ad','癸未寄王甥','劉宰','宋','宋诗','song-poetry','','[]','別時庭戶正秋清，劃見園林翠織成。',64,'全唐诗/poet.song.182000.json','["別時庭戶正秋清，劃見園林翠織成。", "吳下余思頻刮目，渭陽子豈遂忘情。", "堤間飛蓋分垂柳，水面浮舟約半萍。", "乘興時來共清話，相望能隔幾牛鳴。"]'),
('0066373d-4a20-4ff6-b5f0-2fd0d04f706b','贈尤丞季端','劉宰','宋','宋诗','song-poetry','','[]','冠製殊常袖更寬，風流王謝出長干。',64,'全唐诗/poet.song.182000.json','["冠製殊常袖更寬，風流王謝出長干。", "筆端雲錦呈天巧，胸次冰壺挹露寒。", "未許歸期占信宿，想應喜色動門闌。", "賢昆自有長生術，爲覓仙家九轉丹。"]'),
('faf38d94-308e-439e-ac6f-5ee115c9d7ff','讀張氏義莊畫一寄持甫輅院','劉宰','宋','宋诗','song-poetry','','[]','叔世誰憐族派同，高情真有古人風。',64,'全唐诗/poet.song.182000.json','["叔世誰憐族派同，高情真有古人風。", "宗分大小稽周典，惠匝親疎比范公。", "二頃開端能不吝，一編垂訓可無窮。", "欲書盛事傳千載，預愧衰孱語不工。"]'),
('ede8a7e1-ee39-42b7-ab54-c00b16e268b4','再韻謝張持甫過訪二首  其一','劉宰','宋','宋诗','song-poetry','','[]','甕牖篝燈一笑同，地爐燒火愧家風。',64,'全唐诗/poet.song.182000.json','["甕牖篝燈一笑同，地爐燒火愧家風。", "論財以義輕浮俗，論道歸儒識至公。", "行異於時方易沮，理趨於數要深窮。", "老來狂斐君無誚，他石猶堪付玉工。"]'),
('db453413-46cf-4c3b-8981-1a2125e7cea5','再韻謝張持甫過訪二首  其二','劉宰','宋','宋诗','song-poetry','','[]','道自周衰說異同，眼明伊洛振遺風。',64,'全唐诗/poet.song.182000.json','["道自周衰說異同，眼明伊洛振遺風。", "過人高行非難事，入聖微言本大公。", "道在鬼神常共在，術窮天地本無窮。", "三才並處君知否，不爾何裨造化工。"]'),
('0b4df1ee-bffe-4c2f-8ab1-fecd5c578a47','賀趙居父登第','劉宰','宋','宋诗','song-poetry','','[]','詞場聞奪錦標歸，好是斑衣映綠衣。',64,'全唐诗/poet.song.182000.json','["詞場聞奪錦標歸，好是斑衣映綠衣。", "永日湖山供賞詠，好風宮殿正清微。", "堂新六桂光宸翰，庭秀雙芝煥彩闈。", "肯向長安誇得意，妙年伯玉已知非。"]'),
('f49a2d57-2f08-4343-96c6-9da984ac4614','碧雲即事','劉宰','宋','宋诗','song-poetry','','[]','塊坐經年不入山，山僮拍手笑衰顔。',64,'全唐诗/poet.song.182000.json','["塊坐經年不入山，山僮拍手笑衰顔。", "登高猶喜心期在，望遠還驚目力慳。", "雲氣蒼茫自羈旅，煙波飄蕩幾惸鰥。", "朝來舊雨添新雨，誰識安危指顧間。"]'),
('c01ad9df-b266-405d-a70a-46f69b844f03','秋闈後勉子姪','劉宰','宋','宋诗','song-poetry','','[]','我生場屋慣周旋，得失從知豈偶然。',64,'全唐诗/poet.song.182000.json','["我生場屋慣周旋，得失從知豈偶然。", "天理先須盡人事，時文端的本塵編。", "日烘甕牖朝先起，雪壓茅齋夜不眠。", "萬里夷塗從此去，著鞭寧怕祖生先。"]'),
('9807656d-c1ca-4d78-8796-80881706f205','寄范黄中運管','劉宰','宋','宋诗','song-poetry','','[]','鐵甕城中十萬家，哀絃促管競繁華。',64,'全唐诗/poet.song.182000.json','["鐵甕城中十萬家，哀絃促管競繁華。", "晝長獨有揚雄宅，天遠空浮博望槎。", "讀罷離騷想芳草，吟成梁父對菱花。", "客來莫問行藏事，且共盧仝七椀茶。"]'),
('b5f169c5-84b0-4ce6-a759-71cf7c46458c','奉送諸兄謁府','劉宰','宋','宋诗','song-poetry','','[]','男邦養士擬侯邦，師帥寧分彼一方。',64,'全唐诗/poet.song.182000.json','["男邦養士擬侯邦，師帥寧分彼一方。", "明辨正須煩幕府，作成庶不異州庠。", "紫金山迥連三島，甘露樓高俯八荒。", "六代豪華猶在目，停橈毋惜小徜徉。"]'),
('40c9b85e-0d26-4aa1-91df-50bf7620614c','甲午至節後同諸兄入市歸有感','劉宰','宋','宋诗','song-poetry','','[]','七十衰翁入市歸，感今懷昔淚沾衣。',64,'全唐诗/poet.song.182000.json','["七十衰翁入市歸，感今懷昔淚沾衣。", "人稀舊識居猶是，俗競新華質已非。", "九府泉慳誰改作，五材兵去孰防微。", "西山不屬銀緋客，只合高歌詠采薇。"]'),
('5e8bf540-53a5-498e-a2f2-13a60ad0ce29','贈陳內機','劉宰','宋','宋诗','song-poetry','','[]','學詩常擬邵堯夫，問道曾謁楊慈湖。',64,'全唐诗/poet.song.182000.json','["學詩常擬邵堯夫，問道曾謁楊慈湖。", "堯夫之詩呈大樸，慈湖之學澄太虛。", "羨君優游兩者間，傲視軒冕如蘧廬。", "何時從我山中居，絕勝泛綠依紅蕖。"]'),
('d5319ee3-b631-462b-a627-026ebdef274e','送友人入京','劉宰','宋','宋诗','song-poetry','','[]','郭內無田負郭居，酒中有趣酒尊疎。',64,'全唐诗/poet.song.182000.json','["郭內無田負郭居，酒中有趣酒尊疎。", "波間屢聽濯纓曲，架上時繙種樹書。", "萬里長風摧岸柳，一天清露屬園蔬。", "故人欲問平安信，爲說年來頗晏如。"]'),
('0fda75b9-6e76-4800-96a8-2fce3f9c93be','開禧紀事二首  其一','劉宰','宋','宋诗','song-poetry','','[]','泥滑滑，僕姑姑，喚晴喚雨無時無。',40,'全唐诗/poet.song.182000.json','["泥滑滑，僕姑姑，喚晴喚雨無時無。", "曉窗未曙聞啼呼，更勸沽酒提壺蘆。", "年來貴，無酒沽。"]'),
('fee8a08a-4df8-4a3b-b98a-88fd32a0d388','開禧紀事二首  其二','劉宰','宋','宋诗','song-poetry','','[]','婆餠焦，車載板。',43,'全唐诗/poet.song.182000.json','["婆餠焦，車載板。", "餠焦有味婆可食，有板盈車死不晚。", "君不見比來翁姥盡饑死，狐狸嘬骨烏啄眼。"]'),
('4dd980ea-f299-455d-93cb-a1e6f8264c1f','儀真呈友人','劉宰','宋','宋诗','song-poetry','','[]','近聞李郭舟，送往涉重湖。',252,'全唐诗/poet.song.182000.json','["近聞李郭舟，送往涉重湖。", "我欲與之俱，鷁飛過宋都。", "死生見交情，嗟我失東隅。", "歸來整杖屨，顔厚見彼姝。", "念昔擔簦日，籃縷出無襦。", "公子載與歸，樽酒日相娛。", "所愧身爲客，如彼繞樹烏。", "食苹鹿在野，呦呦呼其𪋯。", "鴻鴈稽來書，提壺空勸沽。", "輸君山中行，梅梢嗅紫萸。", "又有好事人，開宴勤招呼。", "翻然棄舟楫，躍馬問長途。", "嗟我困行役，勝遊那能覦。", "方今神聖君，南風歌有虞。", "所須賢與能，搜羅遍八區。", "公等梁棟姿，咳唾玉與珠。", "尚從山澤遊，此理良可吁。", "翻思六月息，豈即非南圖。", "料公賜環日，禍轉當亡胡。", "願借尚方劍，先斬張禹顱。", "小子雖不敏，敢效一得愚。"]'),
('7ae41f11-98a2-4fa7-9151-ec9e074f1bf0','章倉席上','劉宰','宋','宋诗','song-poetry','','[]','官舍若幽居，四圍山水綠。',96,'全唐诗/poet.song.182000.json','["官舍若幽居，四圍山水綠。", "中有超詣士，簿書厭拘束。", "邂逅文字飲，交契如金玉。", "朱絃發清音，紋楸理新局。", "一盃復一盃，夜闌更秉燭。", "木落天宇寬，蟹肥酒初熟。", "相期壯觀游，憑高重送目。", "勿令兒曹知，此味我所獨。"]'),
('c5dc03a1-8eca-4eb5-bcd5-9d6ddf7fae4b','東陽道旁涵碧亭','劉宰','宋','宋诗','song-poetry','','[]','四山委蒼翠，一沼湛清漣。',120,'全唐诗/poet.song.182000.json','["四山委蒼翠，一沼湛清漣。", "雲飛松竹留，石墮藤蘿牽。", "泉音亂絲竹，鳥語賡笑言。", "斯亭作者誰，俛仰四百年。", "棟宇有興廢，篇章足流傳。", "官道紛往來，此地曠周旋。", "乃知造物意，以遺靜者便。", "我來旱暵餘，龜兆坼平田。", "攀崖遡源委，石竇鳴涓涓。", "摩挲兩石魚，變化定何年。"]'),
('813803ca-a701-4937-bee4-7c83770bd508','謝烏鵲','劉宰','宋','宋诗','song-poetry','','[]','朝來不成寢，啼烏繞西東。',72,'全唐诗/poet.song.182000.json','["朝來不成寢，啼烏繞西東。", "似欲砭我愚，無虞終有凶。", "挽衣行太息，飛鳴鵲當空。", "似欲慰我心，正直神所容。", "舉手謝烏鵲，憂喜當何從。", "吉凶兩不到，我在阿堵中。"]'),
('bb1bf092-7607-42c5-9edd-55db128989a5','訪陳廷瑞有感','劉宰','宋','宋诗','song-poetry','','[]','間維有常度，曜靈無停輈。',288,'全唐诗/poet.song.182000.json','["間維有常度，曜靈無停輈。", "翩翩葉辭柯，過眼綠已稠。", "弱榦不盈尺，忽已高岑樓。", "念昔過庭日，朋來悉良儔。", "我年未成童，子少無與侔。", "我質本駑駘，蹇步畏阻脩。", "子如渥洼駒，猛氣已食牛。", "當時二老人，笑語懽且酬。", "門戶各有托，寧計才與不。", "登門如昨日，星紀跡再周。", "二老安在哉，體魄歸山丘。", "隔屋聞讀書，玉樹鏘琳球。", "呼燈使來前，秀氣炯雙眸。", "問之垂九齡，屬對解冥搜。", "感此傷我心，淚下不可收。", "來者日已長，逝者挽不留。", "其間我與子，能閲幾春秋。", "寧復青衿佩，與子從親游。", "幸子齒猶壯，有母方白頭。", "刷翮凌青霄，足勝負米由。", "而我風樹悲，耿耿何時休。", "四十已無聞，過是夫何求。", "矧復病日侵，見面良可羞。", "竹實不療饑，芰製非寒裘。"]'),
('717f3a7a-f40a-49bf-bc53-c7fd0356feea','懷茅山寄句容江大夫','劉宰','宋','宋诗','song-poetry','','[]','昔謁三茅君，蹇步窮躋攀。',288,'全唐诗/poet.song.182000.json','["昔謁三茅君，蹇步窮躋攀。", "是時秋已高，爽氣薄千山。", "三峯斂神秀，突兀超塵寰。", "世變逮狂秦，風俗如髦蠻。", "舌在不敢語，冥默疑心訕。", "咸陽貴公卿，高門擁旗旛。", "牽犬上蔡門，回首涕空潸。", "積骸草木腥，流血川原殷。", "所以三君子，決去披榛菅。", "不以寸草榮，易我白日閒。", "徘徊茲山巔，放蕩紫翠間。", "數窮會有歸，山空水潺潺。", "高風起遐想，往躅芬芝蘭。", "想此弄明月，想此發清彈。", "茲壇梯玉京，茲臺凝金丹。", "羣仙或朋來，洞戶敞幽關。", "縹緲鈞天奏，依約雲旗翻。", "古澗會流泉，點筆依石闌。", "遺墨墮中流，染此亂石黫。", "世情喜虛誕，誑記誰能刪。", "峭壁起道邊，雨濕苔蘚斑。", "剝蘚訪舊題，歲月猶班班。", "當時往來人，逸翮超籠樊。", "應期後千載，綠鬢炯朱顔。"]'),
('15be6ffd-b6b0-456b-8909-dd43a712b8b8','松風軒晚望','劉宰','宋','宋诗','song-poetry','','[]','遠山亞歸雲，近山留夕照。',144,'全唐诗/poet.song.182000.json','["遠山亞歸雲，近山留夕照。", "澄江橫浄練，怒風收衆竅。", "東南佳山水，此地宅其要。", "連甍三萬家，金璧互輝耀。", "閒房列歌舞，傑觀富登眺。", "物理會有極，却慮成悲嘯。", "我家三茅峯，一室倚青峭。", "下有荆溪水，水深魚可釣。", "歸歟有成計，靜坐觀衆妙。", "功名付公等，連茹祇明詔。", "他年問無恙，短策寄嶺嶠。", "浩歌暢幽懷，狂斐君勿誚。"]'),
('4992ac41-d88a-4e97-802c-efbdab1b3e4a','漫塘晚望','劉宰','宋','宋诗','song-poetry','','[]','遠山亞歸雲，黯淡與天一。',72,'全唐诗/poet.song.182000.json','["遠山亞歸雲，黯淡與天一。", "近山過餘雨，浄掃峯已出。", "式喜鳩喚婦，寧憂月離畢。", "擔簦彼誰子，蹇步泥沒膝。", "舉頭望天末，一笑失愁疾。", "應知扶桑東，明朝浴晴日。"]'),
('841171db-c9c8-4a77-8ccf-f71f8215987d','漫塘觀雪分韻得遠字','劉宰','宋','宋诗','song-poetry','','[]','入臘甫自茲，得雪殊不晚。',288,'全唐诗/poet.song.182000.json','["入臘甫自茲，得雪殊不晚。", "凝寒祛厲氣，積潤滋麥本。", "清興浩無極，步屐忘足蹇。", "扣門呼石交，頸縮語猶謇。", "挾携事登眺，南去還北反。", "所向游目礙，窘若虎就圈。", "歸來漫塘上，四望與天遠。", "蓑重漁舟歸，煙橫樵舍飯。", "稜層敞瑶池，燦爛開瓊苑。", "玉龍擁寒城，銀海迷疊巘。", "頗喜漫翁貧，覽富逾北阮。", "呼兒具杯酌，採掇翻蔬畹。", "不辭多酌我，自愧飲河鼴。", "少焉斂夕氛，桂魄爭婉娩。", "翻思造化工，舒卷意難忖。", "方其陰風壯，一噫萬象偃。", "聚將藪澤平，散欲天壤混。", "端疑冰山固，可但拳石狠。", "及其遂離析，去去不可挽。", "日月麗太清，草木被餘煖。", "區分鏡出匣，渙散渠決堰。", "向來天壤間，了不計增損。", "呼吸一氣爾，人當解茲悃。", "恭惟聖明君，憂民中繾綣。"]'),
('3ff42521-0ed6-4671-91b5-3b1f4273c6c9','崇禧夜坐','劉宰','宋','宋诗','song-poetry','','[]','淮浙千萬山，茲山鍾秀異。',144,'全唐诗/poet.song.182000.json','["淮浙千萬山，茲山鍾秀異。", "山中四時好，雪景更佳耳。", "危登俯八荒，豈無超詣士。", "春游眩紅紫，秋賞挹蒼翠。", "衝寒繚冰崖，問訊世能幾。", "山神出奇觀，似慰遠來意。", "漫空飛六花，匝地掩蕪穢。", "頗疑羣玉府，飄墮人間世。", "又疑姑射僊，與物洗疵癘。", "意行輒有得，曠望了無際。", "便欲呼雲車，御風駕六氣。", "舉酒酹初平，逍遥聊卒歲。"]'),
('29a686a2-6326-45bc-86f7-8280955738e4','簡張槃齋以國朝四君子文易南華經','劉宰','宋','宋诗','song-poetry','','[]','我宋百年間，人物兩漢上。',228,'全唐诗/poet.song.182000.json','["我宋百年間，人物兩漢上。", "堂堂司馬公，奧學邁舒向。", "廬陵祖韓孟，首以六經唱。", "升堂子曾子，功亦孟氏抗。", "荆舒徇偏見，晚拂天下望。", "斯文價金玉，表表足相尚。", "一編誰纂聚，百世得宗匠。", "晴窗一開卷，璀璨羅萬象。", "餘功墮毫穎，雲煙起千嶂。", "老我憂患餘，苦學殊少壯。", "適越資章甫，篋笥增冗長。", "之子秀儒林，筆力錦江浪。", "九原如可作，四子推輩行。", "殷勤特送似，或可起遺忘。", "漆園有傲吏，所樂在閒曠。", "插架有全書，引領祈拜貺。", "所志逍遥游，不受鵾鵬誑。", "他年子奮飛，榮問日休暢。", "濠梁如有意，回首問無恙。"]'),
('00a16523-a0da-4411-be18-6a0593fdd93c','宿雲邊感懷','劉宰','宋','宋诗','song-poetry','','[]','虛館怯朝寒，幽夢不可續。',96,'全唐诗/poet.song.182000.json','["虛館怯朝寒，幽夢不可續。", "展轉復展轉，萬感起心曲。", "世塗嗟枘鑿，親養悲風木。", "悔往舌噬臍，念來弓擬鵠。", "悠悠穹壤間，方寸浪馳逐。", "西山有仙子，胸次湛寒玉。", "何年白鶴歸，就我雲邊宿。", "挽衣起凝睇，飛鷗下平綠。"]'),
('d996bc68-c541-41e4-82ea-b48dfa00d32a','東禪百韻','劉宰','宋','宋诗','song-poetry','','[]','羣居厭囂煩，兀坐悵離索。',288,'全唐诗/poet.song.182000.json','["羣居厭囂煩，兀坐悵離索。", "動靜兩何心，求端徯先覺。", "張氏好兄弟，同游得先諾。", "重以臨邛客，雍容出蓮幕。", "二難秀金枝，高會困酬酢。", "客來驚醉夢，倒屣出簾箔。", "符子方下帷，訓子傳家學。", "湯子方涉筆，詞賦工雕斵。", "閉門各有適，跫然聞剝啄。", "錢君丈人行，邂逅同出郭。", "衝飈翼飛蓋，宿潤沾芒屩。", "山僧迎戶外，蕭散出林鶴。", "升堂忽起敬，先正事超卓。", "於今國猶活，繄爾盡忠恪。", "禪房燈火闇，遺像丹青落。", "惟餘我輩人，往事記其略。", "緬懷百年後，賢愚一丘貉。", "風爐催煮茗，胸次澆磊落。", "開軒一凝睇，偉觀奪巖壑。", "古木矯龍蛇，藤蘿喧鳥雀。", "亭亭階前竹，左右森矛矟。", "老榦欲摩空，穉綠猶含籜。", "微風度疎櫺，萬竅呈笙籥。", "鼎來聞歌呼，冠带亦褒博。"]'),
('3267f53e-0922-458e-a22f-07d004537c0a','和丹陽徐文度令君','劉宰','宋','宋诗','song-poetry','','[]','微生嘆數奇，衰疾久見面。',180,'全唐诗/poet.song.182000.json','["微生嘆數奇，衰疾久見面。", "遥聞鄉大夫，今日潘懷縣。", "列宿羅胸中，可但書萬卷。", "撫字究衷曲，誅求無俗見。", "已多鍾子知，且上北海薦。", "顧以疾自歉，往見身如絆。", "緬想滄浪臺，吏退足清燕。", "詩壇建旗鼓，來往紛俊彥。", "未修維梓敬，徒起臨淵羨。", "邂逅得披承，英風起衰懦。", "靦顔謝不敏，多言幾誕謾。", "歸來飭泓穎，秋暑尚嚴憚。", "居然得新詩，大篇驚趣辦。", "瑟縮綴苦語，緘題寄回便。", "何當重扣門，一奏白石粲。"]'),
('2a1b6971-1c5a-440b-b71c-6ab7a4b0db83','送友人歸茅山','劉宰','宋','宋诗','song-poetry','','[]','峩峩三茅峯，秀出雲雨上。',120,'全唐诗/poet.song.182000.json','["峩峩三茅峯，秀出雲雨上。", "疑有避世士，卜築便幽曠。", "菊英當朝餐，蘭佩拂千障。", "我行未之見，徘徊幾惆悵。", "子居山之西，昔聞今見之。", "厭和下里曲，浩歌商山芝。", "山林久寂寥，遲子相發揮。", "間關整車軸，萬里端自茲。", "特苗天所扤，念此令人悲。", "毋爲舍靈龜，旁觀時朵頤。"]'),
('c3a897c9-9c3d-4e57-959f-676644bb6a13','因石令君行有感成古詩一章呈丞尉二丈不知退之亦肯效孟郊樊宗師以文滑稽否','劉宰','宋','宋诗','song-poetry','','[]','絕代有佳人，潔齊處深宮。',120,'全唐诗/poet.song.182000.json','["絕代有佳人，潔齊處深宮。", "組織成文章，黼黻可帝躬。", "蘭菊媚幽姿，桃李自春風。", "出門非所識，所識非所從。", "婉孌彼誰女，剪製了不工。", "膏沐倚市門，苟爲悅己容。", "顧盼若有得，芻雉靡不同。", "出門惟所之，諧笑繚西東。", "寄語道傍人，取舍須至公。", "榮華一時耳，禮義百年中。"]'),
('f5715555-4bc2-43fd-b97e-7c611e4dd39f','和李果州同遊茅山贈','劉宰','宋','宋诗','song-poetry','','[]','我家荆溪東，矮屋八九間。',192,'全唐诗/poet.song.182000.json','["我家荆溪東，矮屋八九間。", "石田人不耕，自占水一灣。", "十年去城市，樂此清晝閒。", "飽聞西州英，奧學窺孔顔。", "見賢豈無時，冰開水潺潺。", "朅來潔齊俟，一語開冥頑。", "錦機神所祕，啟示不吾慳。", "追隨妙高臺，勇往不作艱。", "蹇步驅弗前，逸駕杳難攀。", "惆悵默無言，詩卷慚空還。", "三茅在何許，天末聳髻鬟。", "勝處不可窮，老我嘗窺斑。", "幽人去不歸，夜鶴守松關。", "夫君金玉姿，秀氣超人寰。", "興來得同遊，句就知難刪。", "應同太史筆，有副藏名山。"]'),
('86d316b4-6426-4d5b-aff7-9240809c3d9f','喜客泉','劉宰','宋','宋诗','song-poetry','','[]','物我未忘情，無情惟止水。',72,'全唐诗/poet.song.182000.json','["物我未忘情，無情惟止水。", "底事山中泉，客來如有喜。", "悠然鏡面平，倏爾魚眼生。", "少焉開笑面，似與客逢迎。", "客喜泉豈知，泉笑客何有。", "邂逅深山中，聊結無情友。"]'),
('db7746a6-d10e-4493-ba9c-66719ae5c477','夜夢續句','劉宰','宋','宋诗','song-poetry','','[]','大化賦羣有，脩短亦天只。',96,'全唐诗/poet.song.182000.json','["大化賦羣有，脩短亦天只。", "彭殤誰得失，鵬鷃均適己。", "我今識其然，昏旦視生死。", "青青竹籬下，不種桃與李。", "老薺怙春柔，叢蒿薦芳旨。", "耘耡藉人力，四時自終始。", "屬饜幸朝夕，過計胡爲爾。", "勿笑趙孟偷，甚矣吾衰矣。"]'),
('dd98fa98-b06e-4fad-a9ef-7767a114a8b0','喜雨柬權邑蔡丞','劉宰','宋','宋诗','song-poetry','','[]','高槐障午暑，巨竹摇清風。',216,'全唐诗/poet.song.182000.json','["高槐障午暑，巨竹摇清風。", "中郎百世英，一官此從容。", "心事付盟鷗，年光占候蟲。", "客來欲有言，一笑撫雙松。", "曰余不負丞，哦詩有新工。", "天意亦憐才，要施及物功。", "適此歲薦饑，旱氣日藴隆。", "雨應長官祈，猶未周四封。", "鴈鶩抱文書，朋來立庭中。", "公曰旱既甚，此理貴感通。", "潔齊走羣望，精意格蒼穹。", "西山殷其雷，萬疊聳雲峯。", "南湖飛霹靂，彷彿追蛟龍。", "斯須天壤間，萬象俱晦蒙。", "飛湍連日夜，一洗旱魃空。", "樹藝走丁壯，讙呼沸兒童。", "歲功已權輿，餘閒清缿筩。", "行歌何所云，丞哉寧負公。"]'),
('046da9f6-577d-4632-8405-de2464485b2c','代柬寄當塗大夫王去非','劉宰','宋','宋诗','song-poetry','','[]','聞道王明府，仁聲已四傳。',96,'全唐诗/poet.song.182000.json','["聞道王明府，仁聲已四傳。", "催科能不擾，賦入自爭先。", "理到頑民服，仁漸黠吏悛。", "俊良搜士類，疾苦訪氓編。", "義役頒成制，巫風變昔年。", "已聞銷珥筆，直欲弛蒲鞭。", "未可徒寬治，還疑執德偏。", "碧雲江外合，愛助正拳拳。"]'),
('e6dcdc48-c5e2-4d4e-8bb3-549ed8e614f4','謝諸友移具游德及亭','劉宰','宋','宋诗','song-poetry','','[]','老去疎文會，朋來愜素心。',192,'全唐诗/poet.song.182000.json','["老去疎文會，朋來愜素心。", "結廬慚遠引，挈榼荷親臨。", "反旆孤成約，臨池得勝尋。", "鳥飛青嶂遠，魚戲碧波深。", "揮麈荷香度，開樽柳色侵。", "已欣年洊稔，猶冀雨爲霖。", "學道心無得，爲農力不任。", "每因情款款，常恐歲駸駸。", "坐久便徐步，觴頻怯滿斟。", "非因苦衰疾，豈憚豁煩襟。", "羈旅忘家食，辛勤念子衿。", "範模資伯父，燈火惜分陰。", "一第均兒戲，微言久陸沈。", "簞瓢誠有味，山水會知音。", "子事增吾感，吾言豈子箴。", "他年黄鵠舉，莫忘候蟲吟。"]'),
('5a61b412-e9f2-452d-bab4-3385f2ae2808','送李秀嵓歸蜀','劉宰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','平生秀嵓翁，嘉遯輕朝衣。',144,'全唐诗/poet.song.182000.json','["平生秀嵓翁，嘉遯輕朝衣。", "聖世重特招，趣駕不容違。", "我豈匏瓜哉，先聖固所睎。", "長江一萬里，舟行疾如飛。", "東南盛人物，十九飫甘肥。", "頗藉子公力，寧知伯玉非。", "秀嵓曰異哉，我本起布韋。", "豈比淮之水，東下雜於淝。", "論奏了不阿，正直鬼神依。", "讒言嗟止棘，曰歸詠采薇。", "歲晏江濤平，雨雪從霏微。", "懸知到家日，花竹遶山扉。"]'),
('a3fe70dd-6d1b-48ee-ba00-564a96e85320','趣劉倅聖與建第','劉宰','宋','宋诗','song-poetry','','[]','鷦鷯巢枝寬，大鵬溟海窄。',168,'全唐诗/poet.song.182000.json','["鷦鷯巢枝寬，大鵬溟海窄。", "不齊物之情，大小貴安宅。", "一區揚子雲，衡宇陶彭澤。", "何妨輪鞅稀，所憎廛市迫。", "吾宗携家來，寒暑已屢革。", "寓舍得賈區，開門即廣陌。", "四鄰共壁立，而無藩牆隔。", "晝通燔炙芬，夜悉笑語啞。", "麕至窘賓朋，雨立愧臧獲。", "傳聞三徑地，經始得長策。", "良材蔽川下，賤售非難索。", "露廩發陳積，香飯流匙白。", "羣工闖戶外，拱手聽規畫。", "願速大厦成，却展摶風翮。"]'),
('2e4de856-57b9-43a6-bae3-619ef554fed5','送胡伯量','劉宰','宋','宋诗','song-poetry','','[]','我本山澤人，飄然如野鶴。',192,'全唐诗/poet.song.182000.json','["我本山澤人，飄然如野鶴。", "夫君九臯來，氣類頗相若。", "相逢宿不再，別去天一角。", "君從浮丘游，度世得良藥。", "渴飲瑶池水，饑向芝田啄。", "引脰試一鳴，羣僊相唯諾。", "嗟余侶鷗鷺，迴翔一丘壑。", "刺天見羣飛，老氣鼓不作。", "客來傳好音，重會欣有約。", "追隨忽幾月，至哉天下樂。", "亦知僊凡異，所向終落落。", "分飛又茲始，後會杳難度。", "歸從浮丘侶，爲我試商略。", "雖愧毛骨凡，頗亦志念慤。", "願乞刀圭劑，一洗性昏濁。", "從君清都游，共聽鈞天樂。"]'),
('f9a98ede-846b-450f-b9ab-0354ce6e8f06','次聖與小兒啖虎脯篇','劉宰','宋','宋诗','song-poetry','','[]','折臂最小兒，骨聳顙微廣。',156,'全唐诗/poet.song.182000.json','["折臂最小兒，骨聳顙微廣。", "弗說螺螄小，可以吞大象。", "那敢謂其然，且幸日稍長。", "顧似陶家郎，智識殊不爽。", "强令侍師席，跳踉繞函丈。", "胡能辨滋味，舍魚取熊掌。", "但見蔬菓列，攫取如技癢。", "嘉餽得虎臠，新獵出林莽。", "對之懶下箸，殺氣猶可想。", "呼兒食之既，睥睨尚來往。", "饕餮我所羞，跌蕩或稱賞。", "服猛豈渠能，過奬謝吾黨。", "深慚如敝帚，有誤千金享。"]'),
('00cbb915-e1f0-4c50-b390-5d39c3b4f9cf','走筆謝王去非遣餽江鱭','劉宰','宋','宋诗','song-poetry','','[]','環坐正無悰，駢頭得嘉餽。',156,'全唐诗/poet.song.182000.json','["環坐正無悰，駢頭得嘉餽。", "鮮明訝銀尺，廉纖非蠆尾。", "肩聳乍驚雷，腮紅新出水。", "芼以薑桂椒，未熟香浮鼻。", "河魨愧有毒，江鱸慚寡味。", "更咨座上客，送歸煩玉指。", "飣餖雜青紅，百巧出刀匕。", "翩翩鶴來翔，粲粲花呈媚。", "頗疑壺中景，髣髴具盤底。", "又疑三神山，幻化出人世。", "更於屬饜餘，想像無窮意。", "知君束裝冗，不敢折簡致。", "厚賜何可忘，因筆聊舉似。"]'),
('cf821398-6872-46d0-80b5-c2c852159afd','再韻爲鱭鱠虎臠解嘲','劉宰','宋','宋诗','song-poetry','','[]','多病早休官，自是臺無餽。',156,'全唐诗/poet.song.182000.json','["多病早休官，自是臺無餽。", "東門享鶢鶋，寧若龜曳尾。", "有酒可斟酌，有力給薪水。", "朗詠淵明詩，如斲郢人鼻。", "所期免朝饑，敢幸嘗異味。", "大胾來隣邑，細縷出纖指。", "一見喜折屐，三思食失匕。", "珍非我可常，竈非吾敢媚。", "胡可狥口腹，有若囊無底。", "諸君有用學，土苴足經世。", "龍肝與鳳髓，何求不適意。", "此豈費萬錢，正自不難致。", "貴賤理則殊，氣味固相似。"]'),
('c83be8b5-8b9f-4283-9e74-4add7dda3a9c','次劉聖與遊土山韻','劉宰','宋','宋诗','song-poetry','','[]','巨浸邑東南，西北起培塿。',144,'全唐诗/poet.song.182000.json','["巨浸邑東南，西北起培塿。", "意恐七澤翻，遺此鎮其後。", "我來雪霜降，陽和開歲首。", "平波十萬頃，如鏡照妍醜。", "尚想雷霆擊，水立蛟龍走。", "微此一抔土，羣生魚鱉久。", "山人豈解此，采掇競薪槱。", "飛香識早梅，柴門深處有。", "攀條情正濃，催歸回鷁首。", "幽懷殊未愜，陶寫頼詩友。", "春事甫權輿，重來多載酒。", "會有不速客，带索老榮叟。"]'),
('bed2e526-f7f0-4ba2-98ea-82fb75ad22e7','分韻送王去非之官山陰得再字','劉宰','宋','宋诗','song-poetry','','[]','達官須親民，未竟法應再。',288,'全唐诗/poet.song.182000.json','["達官須親民，未竟法應再。", "昔君治姑孰，報政甫初載。", "桃李春正華，風木養不待。", "至今田里間，往往誦遺愛。", "薦章交公車，夷塗了無礙。", "自詭更治民，得邑仍勇退。", "坐看積薪上，笑謝及瓜代。", "赤縣官山陰，銅章喜重佩。", "平湖带城郭，崇山鎮溟海。", "道中勤顧接，何者非勝槩。", "鵞池湛清漣，蘭亭霏翠靄。", "溪流西走剡，夜雪曾訪戴。", "此地君故家，舊游詳往載。", "公餘信足樂，俗敝良可嘅。", "盜販人鬭狠，淫祀家禳禬。", "緩縱固不可，激之或生害。", "厥田惟中中，厥賦上上倍。", "豪家窘輸送，勺合無容貸。", "貧家慣逋負，符移費追逮。", "行之苟失中，上下交怨懟。", "臺府相鼎立，征求常意外。", "稽違速譴呵，抑絕虞冒昧。", "犴獄當盡心，夜寄或百輩。", "去來不敢詰，猶豫即招悔。"]'),
('dffdde2f-2981-40fc-82e7-a49a782d70d9','送王深道歸黄巖雲霞居并簡李微之周子靖吳毅夫蔣良貴','劉宰','宋','宋诗','song-poetry','','[]','之子雲霞居，地隔千萬山。',156,'全唐诗/poet.song.182000.json','["之子雲霞居，地隔千萬山。", "三年三過我，一見一開顔。", "袖出西游編，字字破天慳。", "可憐東門享，不及海上閒。", "後會不可期，天步方艱難。", "贈別可無言，鳥倦宜知還。", "白髮暮倚閭，山空水潺潺。", "道逢兩倫魁，風采照人寰。", "出處各有適，爲問二者間。", "李周兩太史，筆削凜二班。", "爲問靜中得，何方濟時艱。", "老我疾病餘，癙憂涕空潸。", "回鴈可寄書，勿諉殆且煩。"]'),
('6b7ffb3f-a661-4ec3-b30a-de3c345adb46','贈江西吳定夫','劉宰','宋','宋诗','song-poetry','','[]','定夫江海士，瘦骨如臞仙。',288,'全唐诗/poet.song.182000.json','["定夫江海士，瘦骨如臞仙。", "翩然及吾門，不假左右先。", "我方厭塵埃，一笑喜相延。", "肩懸兩破囊，既見始解纏。", "我欲具杯酒，割雞烹小鮮。", "自言乃長齋，不受世葷羶。", "少休入西山，幽尋徧崖顛。", "山空四無人，白眼問青天。", "洞口得老翁，守死易一編。", "高談慰寂寞，其然豈其然。", "去去不忍別，解衣示勤拳。", "及歸已彌旬，爲我少留連。", "道逢一病媼，背僂兩足攣。", "津頭見羈旅，數口依敗船。", "料理窮晨昏，奔走環市廛。", "足攣不良行，結廬倚牆垣。", "船敗不可航，買舟捐萬錢。", "爲慮極靡密，要使終安全。", "詰旦擬東還，既夕重周旋。", "嗟子塵外客，而結區中緣。", "吾衰不能爾，愧汗與涕漣。", "或疑破囊中，探用若流泉。", "子豈費長房，一壺掛簷前。", "或疑瞿曇老，濟世法無邊。"]'),
('ceacdb99-377f-4157-b68a-07dbc9588b0a','送潘兄謁李弘齋','劉宰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我欲遊廬山，江長水茫茫。',216,'全唐诗/poet.song.182000.json','["我欲遊廬山，江長水茫茫。", "我欲謁弘齋，老去力不遑。", "羨子勇決策，去若飛鴻翔。", "及登夫子門，必升夫子堂。", "想見七十翁，神清氣揚揚。", "客來語時事，慷慨激中腸。", "客去竟無言，高歌詠虞唐。", "子行當寄書，欲言浩難量。", "問我今何爲，爲言老農桑。", "論交四十年，會短別苦長。", "至今風雨夜，晤語思對床。", "所幸天壤間，日月同輝光。", "何妨一寸心，千里遥相望。", "小蟹有益友，勁氣摩穹蒼。", "及其即之溫，百卉粲朝陽。", "特苗天所扤，雙鳥鳴相將。", "閩嶠幾時歸，猿鶴久悲涼。", "憑將一語寄，毋使三徑荒。"]'),
('c56d7b0c-5a9f-4973-b18e-8fbcc7153768','吳門道歸書懷','劉宰','宋','宋诗','song-poetry','','[]','投閒三十年，日與木石俱。',168,'全唐诗/poet.song.182000.json','["投閒三十年，日與木石俱。", "暮景際休明，搜羅逮樵漁。", "洪造賜甄收，羣公交薦書。", "殷勤奉明詔，婉孌辭田廬。", "一寒不自揣，五窮暗揶揄。", "行行步京畿，迎勞多軒車。", "眼青見故人，皆歎此老臞。", "形容不自惜，奈此氣昏愚。", "席間迷舊識，筆底誤新書。", "十目所共睹，一語良非虛。", "儻昧知止戒，不反田園居。", "去去入脩門，蹇步接天衢。", "深虞眩聞見，狂易滋發舒。", "籲天寫真情，浩歌賦歸歟。"]'),
('eefeb99c-ebc9-4974-9670-07615da8d882','贈九華程兄','劉宰','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','君家九華山，山翠常在目。',156,'全唐诗/poet.song.182000.json','["君家九華山，山翠常在目。", "雞犬聲相聞，山腰幾隣曲。", "本固枝葉蕃，無若君之族。", "當年紫橐翁，一念要親睦。", "俸餘不自有，買田徧谿谷。", "計口給之食，昏旦常陸續。", "吉凶更資助，常使有餘畜。", "只今大江南，盛事君家獨。", "君歸廣此意，勝處新卜築。", "周遭植名花，中間敞家塾。", "少長驅之學，毋間親疏屬。", "庶幾子又孫，更衍無窮福。", "亦使紫橐翁，百世流清馥。"]'),
('38fca92e-878a-4877-a2ed-fbc215a2e3e6','送王穎叔分教山陽','劉宰','宋','宋诗','song-poetry','','[]','向來肉食昧遠謀，坐談欲復千古讎。',112,'全唐诗/poet.song.182000.json','["向來肉食昧遠謀，坐談欲復千古讎。", "良平不逐勝詭游，毛錐竟作書生羞。", "楚山蒼蒼楚水流，甲光向日金鱗稠。", "酒闌一笑看吳鈎，將軍意氣傾九州。", "先生身短智則脩，百鍊可使繞指柔。", "安邊端藉帷幄籌，泮宮還獻馘與囚。", "英聲南來動冕旒，貂蟬未必生兜鍪。"]'),
('735ff23f-6fda-488a-a9e8-03061dd930e0','再韻謝和章之辱','劉宰','宋','宋诗','song-poetry','','[]','老人抱甕真拙謀，五利多方無一讎。',112,'全唐诗/poet.song.182000.json','["老人抱甕真拙謀，五利多方無一讎。", "嗟予老矣盍倦游，犢鼻豈恤王孫羞。", "舍西白鳥湛清流，舍東古木鳴蟬稠。", "晚風徐來月一鈎，從渠飛鳶墮炎州。", "君門有詔道阻脩，饑來聊復擷芳柔。", "諸君行矣攄良籌，鍾儀不慮南冠囚。", "野人何自瞻前旒，所願邊封脫兜鍪。"]'),
('38ee43d5-6685-4518-bf17-cecfbfd3f904','再用韻呈同席者','劉宰','宋','宋诗','song-poetry','','[]','由來道同相爲謀，利交始合終相讎。',112,'全唐诗/poet.song.182000.json','["由來道同相爲謀，利交始合終相讎。", "灌竇空如父子游，耳餘莫刷千古羞。", "臞張不與俗同流，常棣相輝華萼稠。", "侯生得句魚上鈎，句法不減韋蘇州。", "王子簡古師穆脩，時亦枯枝蔓新柔。", "坐談不知改更籌，絕勝雙鳥各處囚。", "可能無策上凝旒，夕烽猶照萬兜鍪。"]'),
('f6be5dea-9ceb-4464-84a0-c8b9858b396f','舟過橫塘有感','劉宰','宋','宋诗','song-poetry','','[]','平波淺草橫塘路，曾挽扁舟衝急雨。',176,'全唐诗/poet.song.182000.json','["平波淺草橫塘路，曾挽扁舟衝急雨。", "朱顔綠鬢氣崔嵬，欲斥九關揮玉女。", "萬古功名付汗青，九天光寵生門戶。", "邯鄲一夢兩周星，霜壓孤蓬日始晴。", "風樹不停身已老，病容衰鬢鬼猶驚。", "東烏西兔自昏曉，北來南征幾時了。", "海上欲覓安期瓜，山間却值孫登笑。", "澤畔殷勤訊漁父，掉頭不言吾已悟。", "蚤求富貴晚長年，老少不同均計誤。", "連年旱魃失祈禳，人肝不厭犬豕腸。", "今年稻肥家有酒，萬事且付無何有。"]'),
('56b1e815-b4aa-461f-b091-6b2d9fb0af15','代賦三十韻呈李果州','劉宰','宋','宋诗','song-poetry','','[]','退之抗表出潮陽，高風萬世爲美談。',384,'全唐诗/poet.song.182000.json','["退之抗表出潮陽，高風萬世爲美談。", "衡開雲氣偶然爾，浪占顯晦吾所慚。", "皇華使者課第一，詔歸臺省陪朝參。", "獻疏豈止一痛哭，引去自言七不堪。", "留行隠几卧不應，一麾出守天西南。", "利名百念已灰冷，掃除不盡山水貪。", "行遍金焦到茅阜，知有佳處須窮探。", "春花秋葉事已過，惟有山髮呈䰐鬖。", "山神頗亦愧岑寂，夜奏萬谷笙鐘酣。", "起看瓊樹繞琳宇，更馳玉馬無停驂。", "子猷好事古無比，雪中求往固所諳。", "青鞋直上最高頂，天風縹緲吹楩楠。", "兩峯相對如拱立，上公衮冕朝子男。", "羣山斂退就平地，滅沒不見如紀譚。", "巨浸東連大洋海，浩蕩直與天涯涵。", "却顧淮源赤山下，僅若覆水盈罃甔。", "久留不奈景清絕，山腰下轉臨深潭。", "客來客去泉自湧，可能喜笑靜中含。", "嵌崖往往記遺蹟，舊雨剝蝕苔蘚篸。", "客懷感此重太息，學仙便欲老石龕。", "癡狂正復自譏笑，曠望聊爾依精藍。", "元符舊事不可問，翠微傑觀猶耽耽。", "有田連阡不輸稅，飽食豈計皇恩覃。", "渠儂不知游子恨，寶鑰屢啟彫龍函。"]'),
('cc3800a4-4e79-4fae-969b-06b1fe7a3d09','畏雨不出簡張端袤昆仲符伯壽諸兄','劉宰','宋','宋诗','song-poetry','','[]','我居市北子市南，中間萬口喧春蠶。',160,'全唐诗/poet.song.182000.json','["我居市北子市南，中間萬口喧春蠶。", "子來自南我自北，繚繞東西厭匍匐。", "塊坐不言中有得，谷鳥一聲驚晝息。", "翻然却念友多聞，獨有君家好弟昆。", "嘯軒團團朝至昏，古往今來入討論。", "興來握手眇乾坤，一鼓平沙萬馬奔。", "隔牆更喚符夫子，青眼相看忘汝爾。", "金丸屢墮銅壺冰，欲竟書囊了無底。", "不辭勇往問荀陳，脩竹亭前一欠伸。", "朝來好語聞行人，老龍駕雨上天津。"]'),
('2f5d44ae-6e3e-42f7-82ed-4558a6a7dc16','速陳李二居士還茅山','劉宰','宋','宋诗','song-poetry','','[]','髯李魁然玉抱璞，淡陳蕭散出林鶴。',157,'全唐诗/poet.song.182000.json','["髯李魁然玉抱璞，淡陳蕭散出林鶴。", "華陽洞口笑相逢，天風自奏鈞天樂。", "飛雲出岫本無心，大隠不必皆山林。", "朱絃自振山水音，王喬梅福古猶今。", "君不見洛之南涯溫生北涯石，明月灘頭弄澄碧。", "河陽御史一張羅，曉猿自掩松關寂。", "久旱得雨方一犁，山南種豆猶其時。", "山僮倚擔遲君歸，語君雨過黄獨肥，亦有晚笋穿疎籬。", "急歸燒笋煮黄獨，北山移文可無續。"]'),
('576eecf9-792d-488d-b460-ce7c23aab4da','喜西崗橋成并書邦美東西橋記後','劉宰','宋','宋诗','song-poetry','','[]','西崗水與洮湖通，脩梁自昔橫西東。',112,'全唐诗/poet.song.182000.json','["西崗水與洮湖通，脩梁自昔橫西東。", "百年興廢人不同，誰其記者竹庵翁。", "喜君架木續前功，朝曦夕照明垂虹。", "地脈不斷和氣鍾，紆朱曳紫還家風。", "邂逅歸來一畝宮，幽花野草迷青紅。", "躬耕會有年穀豐，笑詠五柳卑揚雄。", "可但日高花影重，羅帷醉起酣笙鐘。"]'),
('95be08ef-4f67-490c-b39d-6665dc668607','和劉聖與顧龍山約客韻','劉宰','宋','宋诗','song-poetry','','[]','詩筒四出走中涓，詩句萬選如青錢。',112,'全唐诗/poet.song.182000.json','["詩筒四出走中涓，詩句萬選如青錢。", "曰余借舟期七賢，共嗅梅花咀芳鮮。", "津頭幾度喚長年，晝眠乃若經笥邊。", "舉頭急雪風中旋，瞪視不見山之巔。", "八窗玲瓏繡佛前，同來且結西方緣。", "小軒宛若壺中天，玉琴不斷雨聲傳。", "諾君再宿余敢愆，從君索句發春妍。"]'),
('b8992ca4-420e-4473-b353-6acdd0107a5b','寄和趙章泉','劉宰','宋','宋诗','song-poetry','','[]','章泉先生虎豹章，餘子駭逐狐兔藏。',112,'全唐诗/poet.song.182000.json','["章泉先生虎豹章，餘子駭逐狐兔藏。", "少陵遊不返衡湘，孤吟風月老林塘。", "鴐鵞不送我置傍，悵望空勞水一方。", "廣文別日天未霜，殷勤寄音示無忘。", "新詩寫作鴻鴈行，憐我病骨猶嵇康。", "續貂聊復寄歸航，宮牆百雉如金湯。", "登門歲月知何當，江湖極目煙波滄。"]'),
('e8a9e679-c419-45d3-a792-9441c04d1ed2','寄呈王浩翁府判','劉宰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','天下江山推第一，多景名樓信端的。',304,'全唐诗/poet.song.182000.json','["天下江山推第一，多景名樓信端的。", "君家正占多景前，第一風光環燕席。", "梁邑歸來縣債了，驊騮得路乾坤小。", "錦衣聊復效晝游，戶庭鬰葱佳氣繞。", "手栽松菊成三徑，更敞軒楹臨綠沼。", "客來寧厭馬喧櫪，夜宴不知雞戒曉。", "辟書聞又上公車，連帥親題仲舉輿。", "只今淮上未安集，二虜南望猶睢盱。", "要知兩淮須保障，保障一撤長江孤。", "邊臣之慮不及此，但知椎剝供苞苴。", "紅女去機農釋耒，荆榛滿野號鼪鼯。", "君官其間踰十載，洞識本末知盈虛。", "願君亟分刺史符，稍回和氣還邊隅。", "盡收徂詐入赤籍，有功必賞罪必誅。", "招來耕桑徧隴畝，撫摩一意淪肌膚。", "人知親上死其長，荷戈不憚供前驅。", "闞如當道卧於菟，犬羊遯走寧復餘。", "更歸未用師黄石，且侍玉皇香案側。", "不惟文武見全才，要與清朝分淑慝。"]'),
('fb47a8e8-6265-40ed-8f13-9213143f2781','送魏華甫侍郎謫靖州','劉宰','宋','宋诗','song-poetry','','[]','靖州風物最五溪，畬田歲入人不饑，淘沙得金遨以嬉。',168,'全唐诗/poet.song.182000.json','["靖州風物最五溪，畬田歲入人不饑，淘沙得金遨以嬉。", "瘴煙不逐嶺雲西，六花瑞臘春臺熙，尤便逐客過往稀。", "理亂黜陟了不知，夫子豈欲居九夷，要尊主勢扶時危。", "有言不用時我違，翻然不受好爵縻，向來鄉行誰可睎。", "平生易名慕者誰，蘇陳凜凜百世師，畏塗萬折甘如飴。", "求仁得仁固其宜，大明當天照隠微，直前一疏可忘之。", "江湖後會端有期，暗香微動寒梅枝，臨別不用長嗟咨。"]'),
('7fdd98c0-42f7-41fe-bbc6-411cf40453d4','送王常博歸蜀','劉宰','宋','宋诗','song-poetry','','[]','東溟之水浩無窮，蜀江滾滾來朝宗。',128,'全唐诗/poet.song.182000.json','["東溟之水浩無窮，蜀江滾滾來朝宗。", "聖神天子坐法宮，日月所照梯航通。", "君才當代相如雄，雲煙落紙聲摩空。", "西來闡教臨辟雍，冠带濟濟如雲從。", "力排黨論開至公，鳳鳴駭矚朝陽桐。", "太常正徯肅臣工，歸舟却泝蜀江風。", "蜀天萬里車書同，不應一士無留中。", "篙師捩柁毋匆匆，趣回有詔紫泥封。"]'),
('efc91dc1-a300-4b42-b153-720dfb88a7b1','奉送符伯壽尉太平','劉宰','宋','宋诗','song-poetry','','[]','一年三伏秋後前，大火更借炎官權。',256,'全唐诗/poet.song.182000.json','["一年三伏秋後前，大火更借炎官權。", "竹林杖屨北窗眠，君方陸走水行船。", "君言半世苦迍邅，一官遲次安且便。", "瓜時驟及非偶然，今我不往人爭先。", "交承久宦思田園，側身東望心悁悁。", "民情厭舊期改絃，今我不往人煩冤。", "左符再下催行軒，欲挽君留胡得焉。", "君才明敏性靜專，天府四舉賢書連。", "民淳不假綵棒懸，定知學子來差肩。", "酌君薦藕侑新蓮，青白不受汙塗遷。", "贈君以筆并吳牋，官閒鐵硯勤磨研。", "敬亭山下有臞仙，耕雲釣雪老林泉。", "癢疴預欲知民編，少屈從之古道邊。", "長官報政將朝天，集英唱第吾同年。", "賸欲因君寄短篇，有言不盡中勤拳。", "相逢一笑開初筵，爲說故人今白顛。"]'),
('58458993-0b7b-45cb-a70e-db0a8d3a53ee','題解生山水圖','劉宰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江之水西南來，江北江南圖畫開。',96,'全唐诗/poet.song.182000.json','["長江之水西南來，江北江南圖畫開。", "君從何處得此景，錦帆似泛長江回。", "槎牙老樹連荒島，兩兩人家出林杪。", "鷗飛欲下洲渚寬，雲橫不斷關山杳。", "圖窮雙嶼金焦峙，仙宮縹緲浮寒水。", "柂樓捩轉吳波平，閶闔中天日月明。"]'),
('05738778-bad2-4849-bd58-fb5c010bde54','玉糝羊歌','劉宰','宋','宋诗','song-poetry','','[]','華陽洞口玉糝羊，世人傳得神人方。',80,'全唐诗/poet.song.182000.json','["華陽洞口玉糝羊，世人傳得神人方。", "雪團入口桂椒香，能令老者壽而康。", "瑶池玉佩正丁當，箬包聊薦九霞觴。", "世言神仙不鮮食，初平山中果何物。", "桃源更有避秦人，割雞爲黍迎來賓。"]'),
('25c236d9-ec5a-4cc8-9642-e1dcaad0788a','石翁姥','劉宰','宋','宋诗','song-poetry','','[]','采石江頭風晝息，掀天雪浪平如席。',104,'全唐诗/poet.song.182000.json','["采石江頭風晝息，掀天雪浪平如席。", "沿崖小泊客心寬，攀蘿曾看望夫石。", "天涯望斷人不歸，露寒猶想淚霑衣。", "爭似石翁携石姥，年年對峙夾岡道。", "人歸人去我何心，雨沐風餐人自老。", "比翼鳥，連理枝。", "年多物化徒爾爲，長生殿裏知不知。"]'),
('099e301f-eb3f-43c0-a471-9ac5c6050841','送趙居父入淮東漕幕','劉宰','宋','宋诗','song-poetry','','[]','儀真在昔發運司，承平舊事猶可稽。',98,'全唐诗/poet.song.182000.json','["儀真在昔發運司，承平舊事猶可稽。", "歲漕東南六百萬石米，自淮入汴趨京師。", "周原六轡光陸離，建臺想像因遺基。", "水浮陸走舟車馳，轉輸十九資殘寇。", "古今事異吁可悲，民力已困國不支。", "長才入幕宜深思，皇華使者須良規。"]'),
('65df97a4-f53d-4fc3-b827-aebd5e043c0e','雅去鵲來篇','劉宰','宋','宋诗','song-poetry','','[]','昨日雅鳴繞庭樹，道上行人色驚懼。',384,'全唐诗/poet.song.182000.json','["昨日雅鳴繞庭樹，道上行人色驚懼。", "試呼行者問如何，身爲戶長催殘稅。", "稅殘自昔稱難理，三年尤非四年比。", "加之逐保有逃戶，每一申明官長怒。", "人逃信矣田不逃，其奈逃田不知處。", "厥初經界失區畫，比近立租相什伯。", "大家置産錢欲輕，小家鬻産價欲增。", "上田只割下田賦，賦存田盡因逃去。", "或因土瘠遂流移，歲久田侵人不知。", "更有鄉胥迫科抑，多推少割隨胸臆。", "民愚而神難盡欺，往往增入逃戶籍。", "以茲逃戶日增多，戶長蚩蚩奈若何。", "向來差役多輕重，戶長之中中産衆。", "比來里正多義役，各欲供須有全力。", "搜羅中産無孑遺，戶長人人家四壁。", "官司禱雨徧明神，施行寬政蠲房緡。", "房緡僅可寬游手，那得實惠霑農民。", "千錢代輸猶可出，今日方輸又明日。", "父兮母兮叫不聞，遺體鞭笞同木石。", "日日雅鳴期會到，血洒公庭深不掃。", "遂令著處聽雅鳴，魂飛魄散心如擣。", "和氣致祥乖致異，已甘旱魃來爲祟。", "忽驚雅散鵲交飛，高枝報喜仍低枝。", "萬口懽呼聲動地，府今盡放三年稅。"]'),
('d0ebfe9d-5e5a-4e0f-8491-58da975eda16','秋日題儀真寓廨時秩滿俟代','劉宰','宋','宋诗','song-poetry','','[]','非崖非巔，壁立蒼然。',92,'全唐诗/poet.song.182000.json','["非崖非巔，壁立蒼然。", "野花炯炯媚朝日，樛木繚繞棲寒煙。", "歸乎歸乎，幽深此便。", "居乎居乎，市聲晝喧。", "紛去住於吾心，定取舍於吾言。", "竹色一軒秋雨後，荷花十里晚風前。", "錦城不似還家樂，獨立津頭欲問船。"]'),
('60666865-8438-4e18-83a5-be0b0f789aee','野犬行','劉宰','宋','宋诗','song-poetry','','[]','野有犬，林有烏。',175,'全唐诗/poet.song.182000.json','["野有犬，林有烏。", "犬餓得食聲咿嗚，烏驅不去尾畢逋。", "田舍無煙人跡疎，我欲言之涕淚俱。", "村南村北衢路隅，妻喚不省哭者夫，父氣欲絕孤兒扶。", "夜半夫死兒亦殂，屍橫路隅一縷無。", "烏啄眼，犬銜鬚，身上那有全肌膚。", "叫呼伍伯煩里閭，淺土元不蓋頭顱。", "過者且勿嘆，聞者且莫吁。", "生必有死數莫吁，饑凍而死非幸歟。", "君不見荒祠之中荆棘裏，臠割不知誰氏子。", "蒼天蒼天叫不聞，應羨道旁饑凍死。"]'),
('b2c7e12b-98cb-4a42-ad79-60aeb549c516','猛虎行','劉宰','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','市有虎，毋妄言。',147,'全唐诗/poet.song.182000.json','["市有虎，毋妄言。", "當關虎士森戈鋋，市上一呼人駕肩。", "虎雖猛，那得前。", "市有虎，言非妄。", "君不見左馮諸邑天下壯。", "斧斤聲斷林壑空，猛虎通衢恣來往。", "食人肉，飲人血，沈痛積冤何可說。", "凝香堂上紫煙浮，風流太守憂民憂。", "一朝下令開信賞，藉皮枕骨彌山丘。", "虎已滅，人患絕，夜永猶聞泣幽咽。", "泰山之側如可居，子後夫前甘死別。"]'),
('229752db-2c70-4062-92ee-3175143e163e','病鶴吟上黄尚書','劉宰','宋','宋诗','song-poetry','','[]','五湖浩蕩平沙暖，病鶴摧頹翅翎短。',160,'全唐诗/poet.song.182000.json','["五湖浩蕩平沙暖，病鶴摧頹翅翎短。", "萬里空懷宿昔心，忘機已結沙鷗伴。", "華表飛來遼海仙，人間嘉會恰千年。", "一聲嘹唳九關傳，虎豹辟易不敢前。", "盡推同類遊鈞天，浮丘王喬相後先。", "縹緲遺音墮雲際，應念沙頭苦憔悴。", "欲令弱羽更軒昂，共駕飛廉騎六炁。", "瑶池飲，芝田戲，五湖回首皆塵世。", "菰米熟，藕花鮮，五湖秋色正相便。", "寄聲青鳥謝勤拳，摧頹病鶴那能然。"]'),
('9e91c53f-c4c5-4978-992d-47700b6e6417','吳子隆兼隠齋歌','劉宰','宋','宋诗','song-poetry','','[]','前驅十里旌旗紅，後騎蹀躞如游龍。',268,'全唐诗/poet.song.182000.json','["前驅十里旌旗紅，後騎蹀躞如游龍。", "綺窗阿閣最深處，歸來燕坐圍香風。", "不如理掾吳夫子，岸幘高吟酒一中。", "嵩少山頭渭水邊，耕雲釣月老林泉。", "巢由不生沮溺死，魚蝦麋鹿俱忘年。", "不如理掾吳夫子，安閒寄傲庭西偏。", "富貴誠可樂，幽棲端足尚。", "牽黄復出上蔡門，李斯悔殺爲秦相。", "介推有母須求祿，不應決意歸綿上。", "吳夫子，聽我歌。", "當朝劍佩冠峩峩，趨營未免傷天和。", "古來隠者亦已多，潔身亂倫如彼何。", "君今非仕亦非隠，京塵不染白玉珂。", "青衫從事今十載，萬事忘懷真實在。", "但令堂上笑平反，豈計庭前羅翠黛。", "是中不減山中樂，底用青鞋游物外。", "吳夫子，吾所敬。", "兼隠名齋足相稱，誰其尸之勾漏令。"]'),
('bb533e4d-9c0c-49d4-8de3-f142a904226f','傲將軍歌贈周叔子馬帥','劉宰','宋','宋诗','song-poetry','','[]','君不見細柳將軍專號令，壁門不受天子命。',342,'全唐诗/poet.song.182000.json','["君不見細柳將軍專號令，壁門不受天子命。", "又不見隆中將畧天下奇，屈致不可就見之。", "丈夫意氣類如此，達則守官窮守己。", "齋壇未築國士去，軍令已申美人死。", "王翦定須六十萬，李牧必遵前日軌。", "掃門求見齊舍人，魏勃妄庸何足使。", "武皇踞厠對衛青，淮南君臣暗歡喜。", "寥寥古道不復見，後來捷徑何紛紛。", "炙手儻可熱，舐痔未爲勤。", "金珠要結徧奴隸，鈇鉞倒置由他人。", "傲將軍，今無矣。", "杜預苞苴通貴近，裴度浮沉聊卒歲。", "兩賢屹立尚如斯，噲等區區焉足計。", "傲將軍，今有之，我得見之喜可知。", "行年六十未爲老，三衙致位官非卑。", "毛錐子，毋我欺。", "妙年手折桂林枝，長鎗大劍爾胡爲。", "十載安邊功，書遍太常旗。", "周宣方歌境土復，吉甫已賦明哲詩。", "詔書星斗爛，馹騎風雷馳。", "平生許國心，日莫恐倒施。", "皂囊九扣閽，山立志不移。", "時携一樽酒，山水自娛嬉。", "傲將軍，誰與同。"]'),
('26002f29-b069-40b4-910a-82267b7f3d19','代同游者賦宿雲軒呈李果州','劉宰','宋','宋诗','song-poetry','','[]','君不見流金鑠石氣如焚，巫祝並禱天不聞。',102,'全唐诗/poet.song.182000.json','["君不見流金鑠石氣如焚，巫祝並禱天不聞。", "霶霈一雨洗乾坤，膚寸而合山中雲。", "又不見疾雷破山風助勢，八表同昏天地閉。", "峯頭一抹斂歸雲，赫日當空鬼神避。", "祇今歲杪雪霜餘，得向巖前自卷舒。", "等閒且伴幽人宿，明日春回須雨足。"]'),
('ac8ce6fc-1eca-4af8-b633-091ef5bf4409','送趙玉甫赴穿山鹽場','劉宰','宋','宋诗','song-poetry','','[]','辟書朝東來，海上便擬尋蓬萊，坐令斥鹵皆春臺。',224,'全唐诗/poet.song.182000.json','["辟書朝東來，海上便擬尋蓬萊，坐令斥鹵皆春臺。", "辟書暮西至，頒春又擬陪千騎，江水江花盡和氣。", "浮屠將就要合尖，洊雷喚起蟄中潛，東西惟命夫何嫌。", "諸么爭令出門下，意豈專爲一日雅。", "君姿秀整氣清遒，露華凝曉月澄秋。", "胸中武庫森戈矛，筆下倒瀉三峽流。", "甘泉持橐侍凝旒，青氊舊物唾手收。", "幡然正應側席求，東行西行寧久留。", "祖帳馳華軒，嗟余守環堵。", "贈言古有證，臨分敢無語。", "紛紛曳紫腰黄金，儼然望之真天人。", "萬世在其後，念之徒酸辛。", "富貴誠可樂，名義吁可畏。", "此意儻無忘，鴈來頻寄字。"]'),
('61067418-3f83-47f0-b347-2724b5f73589','觀瀑布圖','劉宰','宋','宋诗','song-poetry','','[]','仰觀山糢糊，俯視山歷歷。',248,'全唐诗/poet.song.182000.json','["仰觀山糢糊，俯視山歷歷。", "見卑不見高，此恨通今昔。", "觀者笑且言，畫手非用力。", "安知畫工心獨苦，世上悠悠幾人識。", "君看白練飛，杳不見來跡。", "疑從九霄中，直下恣噴激。", "六月天無風，大暑鑠金石。", "此景獨清涼，飛雪灑石壁。", "此豈銀河翻，餘派墮空碧。", "抑豈龍門決，洪波注八極。", "方知畫者心，不止存目擊。", "山上更有山，去天不盈尺。", "丹崖與翠巘，羣仙所游息。", "煙雲不可到，日星在几席。", "甘露被草木，醴泉出巖隙。", "流落人間者，萬派祇餘瀝。", "知畫豈予能，因畫重悽惻。", "聖賢言外意，未可紙上得。", "所以說詩者，要在以意逆。", "安得畫外觀山人，共向書中探端的。"]'),
('f15e2bd6-b514-46b3-a3fc-36713ae03039','贈芮醫','劉宰','宋','宋诗','song-poetry','','[]','乳母夜深紉故衣，針墮兒側姥不知。',254,'全唐诗/poet.song.182000.json','["乳母夜深紉故衣，針墮兒側姥不知。", "兒膚受針口啼哭，展轉無眠針入肉。", "明日啼聲甚夜來，問兒疾苦誰能猜。", "拊摩忽到傷針處，兒啼欲絕姥方悟。", "醫師睨視了無策，鄰母驚嗟悉來覩。", "羣兒竊聽聞，肩竦毛髮豎。", "芮生昻然來，自言醫此屢。", "探懷出良藥，布指揣針路。", "斯須穎脫出，肌理自如故。", "嗟哉此神術，小試輒如許。", "我聞在昔陳留市，刀鑷工中人避世。", "至今山谷後山詩，明月夜光光照地。", "又聞宋人有藥手不龜，世世澼絖無贏貲。", "客得其方說吳主，大敗越師因胙土。", "方今北境猶多虞，萬金良藥時所須，汝胡不往此踟躕。", "芮生莞爾笑，倖利吾所誚。", "喟彼陳留翁，異世或同調。"]'),
('67d62952-b97c-4081-b18b-32f1d2cca73e','天馬歌書劉漕子淮海秋思詩藁後','劉宰','宋','宋诗','song-poetry','','[]','貳師城空渥洼涸，百年徒費秦川榷。',88,'全唐诗/poet.song.182000.json','["貳師城空渥洼涸，百年徒費秦川榷。", "眼明見此玉花驄，畫工如山筆難貌。", "朔風號，朔雪舞，交河水冰連后土。", "一聲嘶入玉門關，掣斷陰雲日當午。", "超八駿，友六龍。", "天人一笑和鸞雍，駑駘百萬那能從。"]'),
('2efa7bca-2a42-43f9-97b0-1b758565d01f','賽龍謠寄陳倅校書兼呈黄堂','劉宰','宋','宋诗','song-poetry','','[]','重光協洽之歲夏四月，朱方不雨川源竭。',292,'全唐诗/poet.song.182000.json','["重光協洽之歲夏四月，朱方不雨川源竭。", "田家汲井灌新秧，綆短瓶羸汗流血。", "太守憂民一念深，欲決銀河起伏陰。", "彌月驅馳徧羣祀，雲捲碧霄呈象緯。", "聞說南洲有蟄龍，百年水旱資神功。", "民言直徹九天上，絲綸屢下恩光重。", "來往瞻言三百里，別乘親行古無此。", "潔蠲牢醴薦芬馨，願借英靈一瓢水。", "瓢水英靈亦何在，精誠自與神明會。", "炎官叱馭正當空，豐隆已駕隨飛蓋。", "歸軒暮扣古城闉，霈澤朝均千里外。", "秧田得雨變青青，麥田流水迷溝塍。", "擊壤歡呼紛老稚，慚愧今年又豐歲。", "典衣沽酒賽神龍，一飽權輿神所賜。", "神龍肸蠁意已傳，似言此賜非予專。", "一瓢汲水能回天，多謝紫府瀛洲仙。", "瀛洲仙人笑揮手，龍不言功我何有。", "祗今千騎擁朱輪，即是商家大旱作霖人。"]'),
('2c56f4b3-05e9-4128-a359-d0b39f76a224','再韻謝和章  其一','劉宰','宋','宋诗','song-poetry','','[]','萬竈連營橫塞月，委輸不繼官倉竭。',308,'全唐诗/poet.song.182000.json','["萬竈連營橫塞月，委輸不繼官倉竭。", "寇攘雖息尚游魂，胡虜已衰聞蹀血。", "赭衣開河深復深，青青蔓草生河陰。", "歲旱民饑神乏祀，故老言言徵讖緯。", "使君事業今夔龍，十年準擬調元功。", "銅虎分符又南國，北來更閲千山重。", "同寮有客居同里，憂國同心無彼此。", "既知東海之婦可致旱，又知疏勒井泉能涌水。", "釋囚祇有圜扉在，蠲租可但寬期會。", "日照齋盂食不葷，雨濕朝衣車却蓋。", "已罄祈禳徧國中，更遣緹車來郭外。", "荒祠蟲篆上丹青，平原龜兆坼田塍。", "拜手殷勤祝田穉，活國生民係茲歲。", "再宿爲期神效靈，三日爲霖民拜賜。", "長淮轉漕速郵傳，此賜豈獨吾邦專。", "雨餘亟欲披青天，那得駕鶴揚州仙。", "精意回天翻覆手，赫赫陽光均九有。", "但得兩君便携手，齊上紫清扶日輪。", "闔闢陰陽端有道，不妨風月屬閒人。"]'),
('cf6ef118-e5dc-4f06-862e-8c3b386d8e6b','再韻謝和章  其二','劉宰','宋','宋诗','song-poetry','','[]','公詩滄海生明月，草木光輝涯不竭。',288,'全唐诗/poet.song.182000.json','["公詩滄海生明月，草木光輝涯不竭。", "僕如拙匠運斧斤，顔汗淋漓指流血。", "心知短綆難汲深，拱把之木無繁陰。", "風雅墮地幾千祀，牢落荒林鳴絡緯。", "眼明紙上走虬龍，古錦囊中新奏功。", "搜奇往往魑魅泣，窮高不礙天門重。", "鵬飛羊角三萬里，筆勢翩翩有如此。", "渠儂辟易虎負嵎，公獨從容禹行水。", "端由萬卷胸中在，左右尋源無不會。", "詩壇獨上四無人，烏兔驅車天倚蓋。", "曹劉沈謝不支吾，陰何間隔孫山外。", "池塘不夢春草青，愚生已分老田塍。", "縣榻空煩禮徐穉，一笑相逢俄隔歲。", "不辭入府異龐公，祇恐言詩非木賜。", "朝來好語日邊傳，大惠寧許一州專。", "詔書絡繹催朝天，紫薇帝庭領列仙。", "釣船已入酒聖手，清風一枕無何有。", "遮留當道擁車輪，尚能喚起隨邦人。"]'),
('d18e96db-1679-415f-bf0b-7263903d89c2','和陳倅田婦刈麥韻因解嘲','劉宰','宋','宋诗','song-poetry','','[]','君不見山東健婦把犂耕，子美爲賦兵車行。',166,'全唐诗/poet.song.182000.json','["君不見山東健婦把犂耕，子美爲賦兵車行。", "我嘗一讀三歎息，尚想青天聞哭聲。", "又不見峽女生涯在兩脚，鬢髮飄蕭不堪掠。", "我嘗三復負薪篇，亦是子美夔州作。", "山東征戰苦未平，峽女家貧無斗升。", "吾邦之俗異於是，賦調不苛閭里寧。", "八月詩人歌載績，餘暇不如同力穡。", "况復樵枯良易易，自昔民生在勤力。", "通守於民情最親，勞農不憚行侵晨。", "他日席前須記取，要使深宮識苦辛。"]'),
('deeaea31-6ee1-494e-9096-c518485aa8ff','運河行','劉宰','宋','宋诗','song-poetry','','[]','運河岸，丁夫荷鍤聲繚亂。',380,'全唐诗/poet.song.182000.json','["運河岸，丁夫荷鍤聲繚亂。", "紅蓮幕府誰獻言，運河泄水由函管。", "函管掘開須到底，運材歸府供薪爨。", "庶幾一壞不可復，民田雖槁河長滿。", "民田爲私河則公，獻言幕府寧非忠。", "我聞此言爲民說，急趨上令毋中輟。", "小民再拜爲我言，函管由來幾百年。", "大者用錢且十萬，小者半此工非堅。", "厥初銖積費民力，厥後世世期相傳。", "豈但旱時須灌溉，亦憂久潦水傷田。", "向來久旱河流絕，放水練湖憂水洩。", "州家有令塞函管，函管雖存誰復决。", "小須雨澤又流通，函管猶存不費工。", "只今掘盡誰敢計，但恐民田從此廢。", "豐年餘水注江湖，涓滴不爲農畝利。", "有時驟雨浸民田，水不通流禾盡棄。", "况今農務正紛紜，高田須灌草須耘。", "盡驅丁壯折函管，更運木石歸城闉。", "呂城一百二十里，不知被擾凡幾人。", "太守仁民古無比，凝香閣下寧聞此。", "願傳新令到民間，函管須塞不須毀。", "已填函管無尾閭，大舶通行水有餘。", "函管不毀民歡娛，異時潴瀉無妨渠。", "憶昔採詩周太史，不間小夫并賤隸。"]'),
('7119c331-b096-4213-86c9-625ca205ee57','憶昨行寄呈劉法曹','劉宰','宋','宋诗','song-poetry','','[]','憶昨太守宣城陳，人物風流法從臣。',316,'全唐诗/poet.song.182000.json','["憶昨太守宣城陳，人物風流法從臣。", "太息官倉取無藝，要與邑民圖久計。", "總將一石計其贏，三斗八升爲定制。", "厥初號令如雷霆，奉行誰敢圭撮增。", "愚民不解深長慮，競喜當時斗斛平。", "新守迎來舊守去，號令雖嚴誰復顧。", "斛面坡陀斗面高，三斗八升作常賦。", "後來主簿辛君機，太學聲名盛一時。", "朅來意與上官合，委向倉中司出納。", "籌算親臨絕蔽欺，戶庭凜凜無喧雜。", "愚民乍喜見明官，槩量寧論加勺合。", "上供送使有成數，羨餘到底歸州府。", "明年按籍取之民，三斗八升更增五。", "往者不可諫，來者圖之猶未晚。", "只今太守龔黄比，千里癢疴如切己。", "公事勤勞絕燕私，私錢大半供公使。", "選官受秋輸，而得法曹賢。", "除弊幾十九，積羨踰三千。", "三千寧足州家用，祇恐從今還作俑。", "明年四斗三升之上更增科，三十六都之人將奈何。"]'),
('8f8aeb36-23da-4477-a8b1-0414e8db3a19','殺虎行謝宜興趙大夫惠虎皮虎腊虎睛','劉宰','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','君不見陽羨周將軍，射殺南山白額虎，千古萬古聲流聞。',238,'全唐诗/poet.song.182000.json','["君不見陽羨周將軍，射殺南山白額虎，千古萬古聲流聞。", "又不見宜興趙大夫，南山三十有六虎，令行殺取無復餘。", "一虎昔何少，三十六虎今何多。", "虎多人不患，所患政之苛。", "苛政滅人門，猛虎戕人命。", "擇禍莫若輕，泰山之人論已定。", "大夫性高明，下令走風雨。", "所知在田里，了不見臺府。", "既令民免政之虎，又與民除虎之苦，四境之民歌且舞。", "或云殺虎太傷和，胡不令渠自渡河。", "我聞此言笑且呵，大夫憂民憂，豈必限吾土。", "不然鄰國以爲壑，信也白圭愈於禹。", "古陽羨，今宜興。", "大夫邑之主，將軍邑之民。", "主賓多寡事不同，千古萬古同清芬。"]'),
('830ee3f8-023f-43cd-9038-a797e56ac7ac','過司徒墓','劉宰','宋','宋诗','song-poetry','','[]','司徒墓，荒塚纍纍不知數。',92,'全唐诗/poet.song.182000.json','["司徒墓，荒塚纍纍不知數。", "草中翁仲無復存，壟上牛羊自來去。", "想見當時百萬松，佳城在處鬰葱葱。", "車馬時來卿相子，鐘魚聲出梵王宮。", "年深事遠無留蹟，只與耕夫資墾闢。", "萬古同成一窖塵，官爵高卑誰汝識。"]'),
('df116ce3-8cd3-43d8-92ae-7cc53e225d5b','用前五字韻趣劉聖與建第','劉宰','宋','宋诗','song-poetry','','[]','君不見茅屋下，四壁床敷窄。',189,'全唐诗/poet.song.182000.json','["君不見茅屋下，四壁床敷窄。", "又不見朱門中，金碧鎖空宅。", "宅成更欲致良材，水浮陸走空山澤。", "茅屋區區誠已疎，朱門汲汲彼何迫。", "勸君勿學伏波老，自詭裹屍須馬革。", "又勿學金谷人，綺窗阿閣綿阡陌。", "但令庭宇潔，頗與塵囂隔。", "市聲不至亂琴書，厨煙可免衝咽啞。", "庶幾家人安，亦使我心獲。", "吾宗開敏姿，富有濟時策。", "棟宇著易象，義不假探索。", "况聞玉堂直，視草須元白。", "所期不日成，毋使中道畫。", "庶奉紫芝泥，即刷青雲翮。"]'),
('aea85e7d-297a-4b91-840a-d698feaa4b18','寄刑臺范黄中','劉宰','宋','宋诗','song-poetry','','[]','秋氣清，秋風高。',132,'全唐诗/poet.song.182000.json','["秋氣清，秋風高。", "想見刑臺舊居士，巾車獨往恣遊遨。", "偃仰戴公廬，逍遥焦公居。", "想前輩之風流，悲末俗之崎嶇。", "白眼睨視，抵掌嘻吁。", "酌之以漫塘之酒，侑之以漫塘之藕。", "酒之味醇而不漓，藕之性潔而不汙以泥。", "于以介眉壽，于以明素守。", "對此長歌，其樂如何。", "相望雖隔於秋水，明月幸同於千里。"]'),
('c51561b9-2be8-4234-bd4b-91d218c40b17','跋趙憲唐率更千字文蹟','劉宰','宋','宋诗','song-poetry','','[]','草非草，真非真。',143,'全唐诗/poet.song.182000.json','["草非草，真非真。", "柳之骨，顔之筋，歐張瘦硬可通神。", "衆體備，兼衆美。", "莫臻興嗣書，無首亦無尾。", "當年好事人，各欲徇所嗜。", "割截同至寶，得中固爲喜。", "莫將俗眼看，墨脫字已漫。", "當年寶匣中，什襲幾歲寒。", "祇今煙雲披，星斗尚闌干。", "麟角鳳觜毋輕棄，煎膠續弦端有冀。", "君不見四窗寶此不寶他，固應落筆驚風雨，走龍蛇。"]'),
('54aa6716-b8a2-4263-a987-ec3b01488d62','真西山贊','劉宰','宋','宋诗','song-poetry','','[]','中國相司馬，和氣滿華夏。',24,'全唐诗/poet.song.182000.json','["中國相司馬，和氣滿華夏。", "惜哉民始蘇，身已要人扶。"]'),
('063ae169-22fb-4a43-aeeb-3b203ff7bf3c','宴金壇邑官致語口號','劉宰','宋','宋诗','song-poetry','','[]','百里兒童沸誦聲，湖山堂上集群英。',64,'全唐诗/poet.song.182000.json','["百里兒童沸誦聲，湖山堂上集群英。", "德星欲應今宵瑞，霖雨先開昨夜晴。", "正是壺中銀漏永，不妨坐上玉山傾。", "明年此會君知否，冠佩蟬聯拱聖明。"]'),
('e2ae77b4-3a89-45d0-ac53-9205fb8185ec','挽齊齋倪尚書','劉宰','宋','宋诗','song-poetry','','[]','南山有孤松，屹立幾尋丈。',288,'全唐诗/poet.song.182000.json','["南山有孤松，屹立幾尋丈。", "雪根雨露滋，藤蘿巧相傍。", "高柯撐青空，落落不可上。", "遼東白鶴歸，城郭固無恙。", "饑烏拾餘粒，巢燕倚飛幌。", "芝田杳何許，鼓翮超蓬閬。", "尚書千載人，餘子豈輩行。", "方時鄙俗學，制行多矯亢。", "我獨道其常，曰彼非至當。", "世事有翻覆，陰陽日消長。", "誰其倡攻僞，欲使盡一網。", "我獨持其平，要辨直與枉。", "前瞻豈尚同，後顧亦非黨。", "介然兩不合，蘭佩拂千嶂。", "惟皇思建極，正直首延訪。", "幾趨鑾禁直，屢侍金華講。", "三黜柳士師，一念齊得喪。", "歲晚復來歸，舊德世所仰。", "文昌豈不貴，台星連兩掌。", "貞元朝士少，正始遺風蕩。", "淹留感時事，去去得初尚。", "湖光浮醆斚，巖花開步障。", "意行無物累，靜寄絕塵想。", "寥寥香山翁，勝處畧相倣。"]'),
('3e43caea-9b89-4c19-b9b9-d63a77c0e4f6','挽葉水心侍郎三首  其一','劉宰','宋','宋诗','song-poetry','','[]','北學源流遠，南來歲月遷。',48,'全唐诗/poet.song.182000.json','["北學源流遠，南來歲月遷。", "羣心知未昧，諸老屹相連。", "百歲同歸盡，斯文要有傳。", "宵長殘月墮，遺恨渺山川。"]'),
('eaffb26d-13d1-47e5-8cd9-bf20f5d2eb98','挽葉水心侍郎三首  其二','劉宰','宋','宋诗','song-poetry','','[]','嘉會欣千載，偏安隘一方。',48,'全唐诗/poet.song.182000.json','["嘉會欣千載，偏安隘一方。", "言言本周孔，草草笑隋唐。", "禁路無停轍，江流有巨防。", "空餘遺藁在，萬古日爭光。"]'),
('75e6a808-f9e8-461b-a551-df38f50551f5','挽葉水心侍郎三首  其三','劉宰','宋','宋诗','song-poetry','','[]','憶袖禰衡刺，嘗登元禮門。',48,'全唐诗/poet.song.182000.json','["憶袖禰衡刺，嘗登元禮門。", "相忘如舊識，一笑等春溫。", "東望山川遠，西歸歲月奔。", "遥憐人築室，烟鎖暮江昏。"]'),
('e612f9c7-cf94-4d1d-ac85-0ac9f39808fa','挽袁潔齋侍郎三首  其一','劉宰','宋','宋诗','song-poetry','','[]','國脈關吾道，邦基倚藎臣。',48,'全唐诗/poet.song.182000.json','["國脈關吾道，邦基倚藎臣。", "忠言炳蓍蔡，勁節挺松筠。", "歲晏名逾重，山頹蹟遽陳。", "光明如皦日，千載自常新。"]'),
('c3de07ed-56bf-4a72-b59f-c1bc61f2e690','挽袁潔齋侍郎三首  其二','劉宰','宋','宋诗','song-poetry','','[]','成己寧遺物，存心不外天。',48,'全唐诗/poet.song.182000.json','["成己寧遺物，存心不外天。", "典刑高一代，源派續諸賢。", "實理元無妄，斯文更有傳。", "澤流江漢遠，奎壁映魁躔。"]'),
('9123cb9b-32ef-43f5-a26f-6dca54b12054','挽袁潔齋侍郎三首  其三','劉宰','宋','宋诗','song-poetry','','[]','講學元無倦，繙書老更勤。',48,'全唐诗/poet.song.182000.json','["講學元無倦，繙書老更勤。", "能令神氣王，直到死生分。", "玉折經綸具，星垂翰墨勳。", "淒其知己地，灑淚濕寒雲。"]'),
('9bb7cd90-0665-4943-aaf7-db88fb83f2ec','挽湯參議三首  其一','劉宰','宋','宋诗','song-poetry','','[]','再協三刀夢，終孤五馬迎。',48,'全唐诗/poet.song.182000.json','["再協三刀夢，終孤五馬迎。", "行藏一委分，喜慍兩忘情。", "議幕臨邊瑣，籌帷頼老成。", "傷心江漢水，東下送銘旌。"]'),
('fecc205b-292f-466f-b4f7-76915a7941f7','挽湯參議三首  其二','劉宰','宋','宋诗','song-poetry','','[]','徇義千鈞重，論財一羽輕。',48,'全唐诗/poet.song.182000.json','["徇義千鈞重，論財一羽輕。", "大倫元有序，世祿我持平。", "外廡家如寄，東臯産半傾。", "謀生有如此，垂世祇清名。"]'),
('d8276437-a075-49f4-8308-7ea8aaeaf232','挽湯參議三首  其三','劉宰','宋','宋诗','song-poetry','','[]','婦黨君推重，鄉評我棄餘。',48,'全唐诗/poet.song.182000.json','["婦黨君推重，鄉評我棄餘。", "共嗟身計拙，直與世緣疎。", "種竹沿修隴，栽花傍小渠。", "南園重回首，濃綠上畦蔬。"]'),
('97dbad0e-8af1-44c8-89f6-cebfa1ec907f','挽賀運管二首  其一','劉宰','宋','宋诗','song-poetry','','[]','赫赫儒宗裔，堂堂公相家。',48,'全唐诗/poet.song.182000.json','["赫赫儒宗裔，堂堂公相家。", "清規凜冰雪，薦墨爛雲霞。", "未協生桑夢，俄興逝水嗟。", "遥憐遺愛在，月澹弋溪花。"]'),
('a2865c8a-8e95-4daa-b655-d54c9c7b2641','挽賀運管二首  其二','劉宰','宋','宋诗','song-poetry','','[]','妄擬絃歌樂，欣逢簿領賢。',48,'全唐诗/poet.song.182000.json','["妄擬絃歌樂，欣逢簿領賢。", "高明固天分，清白自家傳。", "雲望同凄切，星奔認後先。", "孤城重回首，愁鎖暮江烟。"]'),
('c6682540-5d26-42d5-b509-d1d26b1f4430','挽通倅劉由正二首  其一','劉宰','宋','宋诗','song-poetry','','[]','質粹言無玷，官清政有方。',48,'全唐诗/poet.song.182000.json','["質粹言無玷，官清政有方。", "能令邦國活，可但海沂康。", "別乘歸何早，閑堂樂未央。", "傷心瀨陽路，月澹水茫茫。"]'),
('5988e006-425b-414f-ac57-be99e45e9e3d','挽通倅劉由正二首  其二','劉宰','宋','宋诗','song-poetry','','[]','論姓君先薛，談經我愧匡。',48,'全唐诗/poet.song.182000.json','["論姓君先薛，談經我愧匡。", "同登太常第，更接鄭公鄉。", "別恨驚三紀，還書欠幾行。", "猶餘清夜夢，載月渡滄浪。"]'),
('571a4c4c-4832-4384-846b-391f8cf92b4a','挽趙知宗三首  其一','劉宰','宋','宋诗','song-poetry','','[]','孝廟垂衣日，宗工補衮時。',48,'全唐诗/poet.song.182000.json','["孝廟垂衣日，宗工補衮時。", "治推三輔最，名熟九重知。", "紫禁塗非遠，琳宮志自頤。", "眼看庭下玉，持橐侍丹墀。"]'),
('c107323e-030c-422c-825a-a0b24acd8172','挽趙知宗三首  其二','劉宰','宋','宋诗','song-poetry','','[]','就養京華去，聲馳日月旁。',48,'全唐诗/poet.song.182000.json','["就養京華去，聲馳日月旁。", "芝封三錫命，桂籍再傳芳。", "簜節光華遠，歸軒錦綉香。", "高閒塵不染，隠几到羲皇。"]'),
('ec79146d-6af8-4e04-bae1-d56733352465','挽趙知宗三首  其三','劉宰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','寓里身重到，孱生謁屢通。',48,'全唐诗/poet.song.182000.json','["寓里身重到，孱生謁屢通。", "儉欽行己素，健識養生功。", "歸旆廬山遠，清尊洛下同。", "遥憐猿鶴恨，蕙帳失仙翁。"]'),
('b82ec348-b050-4436-a1db-a47e5c447317','挽趙和仲侍郎三首  其一','劉宰','宋','宋诗','song-poetry','','[]','四載行都尹，當朝第一人。',48,'全唐诗/poet.song.182000.json','["四載行都尹，當朝第一人。", "中和宣上德，樂易本天真。", "論譔疏新寵，論思徯舊臣。", "履聲勤帝想，竟阻上星辰。"]'),
('a4bbbc5a-27c7-4234-ae32-4beff487f0b4','挽趙和仲侍郎三首  其二','劉宰','宋','宋诗','song-poetry','','[]','珍館萊衣侍，佳城孟母鄰。',48,'全唐诗/poet.song.182000.json','["珍館萊衣侍，佳城孟母鄰。", "去來哀樂異，孝愛死生均。", "寵渥昭宸翰，豐功勒翠珉。", "白蓮原上路，指日萬家春。"]'),
('9aa57cb7-d823-4a16-befd-bbd02852f9a4','挽趙和仲侍郎三首  其三','劉宰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','蚤愧斐然作，頻勞掩鼻書。',48,'全唐诗/poet.song.182000.json','["蚤愧斐然作，頻勞掩鼻書。", "升沉嗟契闊，問訊辱勤渠。", "鄉縣榮歸錦，侯門得曳裾。", "傷心鸞鶴御，竟不反匡廬。"]'),
('43c61c7a-c499-469a-a947-87d3d0a64145','代挽前人二首  其一','劉宰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','世德隆周翰，通才壓漢儒。',48,'全唐诗/poet.song.182000.json','["世德隆周翰，通才壓漢儒。", "花城頌遺愛，榆塞踵成模。", "浩穰須君重，論思協帝謨。", "匡廬游不及，寒月淡平蕪。"]'),
('0cf5317c-44bc-4e5b-95cf-17cc288d637f','代挽前人二首  其二','劉宰','宋','宋诗','song-poetry','','[]','反匶踰千里，平生念母慈。',48,'全唐诗/poet.song.182000.json','["反匶踰千里，平生念母慈。", "煙霞連傑觀，星斗下平池。", "地勝呈金像，神思伏寶龜。", "庭前雙玉樹，昌大可前知。"]'),
('84d1f08f-884e-4b20-a07e-541842696c4f','挽湘潭趙知縣二首  其一','劉宰','宋','宋诗','song-poetry','','[]','列將朱橫带，參軍綠染袍。',48,'全唐诗/poet.song.182000.json','["列將朱橫带，參軍綠染袍。", "崇卑知異位，取舍見吾曹。", "撫字功深著，歸休道更高。", "崑山埋玉去，春浪送行篙。"]'),
('5c92443f-e95c-4ab4-828f-a209f64e1535','挽湘潭趙知縣二首  其二','劉宰','宋','宋诗','song-poetry','','[]','念昔先君子，窮閻接寓居。',48,'全唐诗/poet.song.182000.json','["念昔先君子，窮閻接寓居。", "幾年鶑出谷，千里鴈傳書。", "執友嗟誰在，孤生愧久疎。", "臨風兩行淚，可但等鄉閭。"]'),
('4140e09a-3ddd-41ca-a07a-d5f7bbcde467','挽諸葛宣義二首  其一','劉宰','宋','宋诗','song-poetry','','[]','世積鄉閭望，公兼德齒尊。',48,'全唐诗/poet.song.182000.json','["世積鄉閭望，公兼德齒尊。", "謹身忘歲晚，接物等春溫。", "樂事人難比，餘功盜自奔。", "平生可無憾，一劄疏明恩。"]'),
('12af671a-8887-4ca4-9d87-a120f177f0bc','挽諸葛宣義二首  其二','劉宰','宋','宋诗','song-poetry','','[]','蘭階初擢秀，棣萼亦聯芳。',48,'全唐诗/poet.song.182000.json','["蘭階初擢秀，棣萼亦聯芳。", "幻化應難料，悲懽獨兩忘。", "達生知有道，養性更傳方。", "一笑乘雲去，誰知本不亡。"]'),
('f5dbff84-0ba6-4dc6-baac-8c1e11f5f5fa','挽江寧丁尉二首  其一','劉宰','宋','宋诗','song-poetry','','[]','蚤以才充賦，終焉學入官。',48,'全唐诗/poet.song.182000.json','["蚤以才充賦，終焉學入官。", "登名先杜牧，擇地得長干。", "南部威方振，橫山寇即安。", "仙遊定何許，烟鎖暮江寒。"]'),
('ca28d7f1-68cb-4d69-b97b-f9a3f7dce529','挽江寧丁尉二首  其二','劉宰','宋','宋诗','song-poetry','','[]','進秩膺丹詔，論功更紫樞。',48,'全唐诗/poet.song.182000.json','["進秩膺丹詔，論功更紫樞。", "九霄飛鶚奏，萬里入鵬圖。", "竟負丁年志，端符巳歲呼。", "向來延客處，落日澹平蕪。"]'),
('cc82f4cd-b377-4e6a-b150-2b8233e04e16','挽丁嘉正','劉宰','宋','宋诗','song-poetry','','[]','里選居前列，臚傳冠一科。',48,'全唐诗/poet.song.182000.json','["里選居前列，臚傳冠一科。", "一官期遠大，十載歎蹉跎。", "僅喜瓜時及，俄驚薤露歌。", "天高不可問，吾道竟如何。"]'),
('e52ac910-8b27-4539-9280-045a87c1facf','挽莊僉判','劉宰','宋','宋诗','song-poetry','','[]','宦路推才美，鄉邦敬老成。',48,'全唐诗/poet.song.182000.json','["宦路推才美，鄉邦敬老成。", "花封勤致理，蓮幕仰持平。", "弭棹驚歸夢，支筇話別情。", "蒲輪乖往事，一慟閉佳城。"]'),
('cd09a64b-36b5-48a3-bbb2-7a4f43b70104','挽湯貢士三首  其一','劉宰','宋','宋诗','song-poetry','','[]','鴈塔平生志，雞窗萬卷書。',48,'全唐诗/poet.song.182000.json','["鴈塔平生志，雞窗萬卷書。", "年雖踰六秩，勤不廢三餘。", "僅喜名天府，空傳賦子虛。", "盈虧天有定，我欲問何如。"]'),
('a685643d-c980-4d5f-aef7-4b0ec98a4e2c','挽湯貢士三首  其二','劉宰','宋','宋诗','song-poetry','','[]','謾足百金産，難忘九族貧。',48,'全唐诗/poet.song.182000.json','["謾足百金産，難忘九族貧。", "粢盛肅先祀，幣帛薦佳賓。", "月耿三秋夜，風回九陌春。", "親朋一樽酒，無復見斯人。"]'),
('48d86d88-3627-4000-913d-67d6fa6dfa4b','挽湯貢士三首  其三','劉宰','宋','宋诗','song-poetry','','[]','念昔先君子，論文到白頭。',48,'全唐诗/poet.song.182000.json','["念昔先君子，論文到白頭。", "對床同夜話，散策逐春遊。", "人物今何許，湖山空復秋。", "傷心珥陵月，依舊照行舟。"]'),
('6cef629d-4453-4657-93b5-85e2664372ae','挽考亭陳居士二首  其一','劉宰','宋','宋诗','song-poetry','','[]','八十人稀有，君年又過之。',48,'全唐诗/poet.song.182000.json','["八十人稀有，君年又過之。", "康强由學力，孝友自天資。", "瑞世芝三秀，承家桂一枝。", "萬山圍隴首，昌大看他時。"]'),
('41af456f-fb8f-4561-96fb-36768882e0f3','挽考亭陳居士二首  其二','劉宰','宋','宋诗','song-poetry','','[]','舊數同門友，尤推令子賢。',48,'全唐诗/poet.song.182000.json','["舊數同門友，尤推令子賢。", "登堂愧予晚，愛客莫君先。", "瘦馬青山外，孤帆落照邊。", "風流無復見，執紼涕潸然。"]'),
('deb0986a-919c-4924-87b1-b81e8a369d7a','挽劉季文','劉宰','宋','宋诗','song-poetry','','[]','斷岸扁舟去，中林好事家。',48,'全唐诗/poet.song.182000.json','["斷岸扁舟去，中林好事家。", "扣門無倦色，安土足生涯。", "國寵期金紫，家聲振玉砂。", "如何年不百，泣淚濕飛花。"]'),
('26afa313-a615-48db-9a7c-0b9b92f7c066','挽陳德亨','劉宰','宋','宋诗','song-poetry','','[]','宅枕烟波勝，人鍾風露清。',48,'全唐诗/poet.song.182000.json','["宅枕烟波勝，人鍾風露清。", "蟾宮孤壯志，蛻室悟浮生。", "月下扁舟去，花邊短策橫。", "錦囊遺藁在，端可振家聲。"]'),
('c63e7868-e00e-48b1-949c-83b264018998','挽王元佐','劉宰','宋','宋诗','song-poetry','','[]','先子同年友，鄉閭後進師。',48,'全唐诗/poet.song.182000.json','["先子同年友，鄉閭後進師。", "生涯書遶案，樂事酒盈巵。", "壁倚扶衰杖，窗留遣興詩。", "人焉在何許，丹旐出疎籬。"]'),
('48256558-54f2-44a4-bdf4-007bf3154167','挽孫府君二首  其一','劉宰','宋','宋诗','song-poetry','','[]','積累承三世，清修自一家。',48,'全唐诗/poet.song.182000.json','["積累承三世，清修自一家。", "窮通渠已定，悃愊我無華。", "秋野禾生穗，春園果著花。", "平生行樂處，未必愧烟霞。"]'),
('72a88f2b-b249-47e2-ae00-fc51ab7f9c9c','挽孫府君二首  其二','劉宰','宋','宋诗','song-poetry','','[]','鴈序均同氣，鴒原見此情。',48,'全唐诗/poet.song.182000.json','["鴈序均同氣，鴒原見此情。", "數椽忘爾汝，一飽共孤惸。", "綠綬方娛侍，黄粱已夢驚。", "無人知倚伏，風樹慘佳城。"]'),
('879df41d-cd90-48bc-9e1d-bde291cb40d1','挽雷處士','劉宰','宋','宋诗','song-poetry','','[]','別駕推前輩，當家得後昆。',48,'全唐诗/poet.song.182000.json','["別駕推前輩，當家得後昆。", "零丁問防墓，高大復于門。", "達觀吾忘我，儒風子又孫。", "閭閻耆舊盡，能復典刑存。"]'),
('dfdd2ade-12bb-450c-8a3a-43722fbad56a','挽蕭令君某氏孺人','劉宰','宋','宋诗','song-poetry','','[]','慷慨成夫志，勤拳教子功。',48,'全唐诗/poet.song.182000.json','["慷慨成夫志，勤拳教子功。", "母儀當世則，婦道古人風。", "象服宜偕老，魚軒忽馭空。", "惟餘千字碣，光照夜臺中。"]'),
('cf79b66e-90c6-4dd3-8756-da94a27b1d52','挽趙子野母梁氏太夫人','劉宰','宋','宋诗','song-poetry','','[]','元祐名家幾在亡，夫人懿德足傳芳。',64,'全唐诗/poet.song.182000.json','["元祐名家幾在亡，夫人懿德足傳芳。", "事夫生死終無負，教子艱辛昔備嘗。", "八秩燕頤天予壽，十行鸞誥月爭光。", "穹窿原上春風起，無復潘輿駐夕陽。"]'),
('d8c7d1eb-cc07-487f-9834-e21c00a3fb67','挽楊倉趙氏宜人','劉宰','宋','宋诗','song-poetry','','[]','赫奕金枝舊，光華玉節新。',48,'全唐诗/poet.song.182000.json','["赫奕金枝舊，光華玉節新。", "魚軒方稅駕，鶴馭已離塵。", "百歲雖遺恨，雙珠自可人。", "通家思往事，老淚一沾巾。"]'),
('61d98a1d-fe9a-4f07-9bda-fb99f57ff684','挽徐夫人','劉宰','宋','宋诗','song-poetry','','[]','奕世居公輔，齊眉肅婦儀。',48,'全唐诗/poet.song.182000.json','["奕世居公輔，齊眉肅婦儀。", "魚軒中歲樂，鸞鏡暮年悲。", "象笏子方貴，韋編孫有師。", "懸知五花誥，不負蓼莪詩。"]'),
('2972e35d-5335-4afb-a5d1-76cbf55f6fdc','挽范氏孺人二首  其一','劉宰','宋','宋诗','song-poetry','','[]','蘭砌秋風早，萊衣晚歲孤。',48,'全唐诗/poet.song.182000.json','["蘭砌秋風早，萊衣晚歲孤。", "天乎軫劬瘁，季也足歡娛。", "得算幾中壽，生孫競遠圖。", "平生憂喜事，落日澹平蕪。"]'),
('7c331d2e-5185-4371-b9bf-d4f2db9a87dd','挽范氏孺人二首  其二','劉宰','宋','宋诗','song-poetry','','[]','侍見嗟親健，論姻動母懷。',48,'全唐诗/poet.song.182000.json','["侍見嗟親健，論姻動母懷。", "殷勤留北棹，飣餖出東齋。", "回首流年速，升堂往事乖。", "遣車門外去，老淚墮賓階。"]'),
('f4315a5e-397f-4bbe-9aa2-d256b0afe9e9','挽潘校尉','劉宰','宋','宋诗','song-poetry','','[]','一經知教子，三釜擬榮親。',24,'全唐诗/poet.song.182000.json','["一經知教子，三釜擬榮親。", "風樹存亡恨，迷茫北渚津。"]'),
('561a31d4-cda5-49ca-93e3-8e12f3546f53','代梁總挽鄭舜舉侍郎四首  其一','劉宰','宋','宋诗','song-poetry','','[]','幾度除書下紫宸，從容千騎擁朱輪。',32,'全唐诗/poet.song.182000.json','["幾度除書下紫宸，從容千騎擁朱輪。", "聖朝若第循良課，公是當時第一人。"]'),
('abefa521-6e72-4eef-8b2c-a18d2d01f8ee','代梁總挽鄭舜舉侍郎四首  其二','劉宰','宋','宋诗','song-poetry','','[]','九重虛己竚論思，千載風雲彼一時。',32,'全唐诗/poet.song.182000.json','["九重虛己竚論思，千載風雲彼一時。", "貝錦誰爲當日事，角招空賦昔人詩。"]'),
('dac84066-20d5-42a3-9e51-b8945a907325','代梁總挽鄭舜舉侍郎四首  其三','劉宰','宋','宋诗','song-poetry','','[]','由來樂事在田園，歸路無人早著鞭。',32,'全唐诗/poet.song.182000.json','["由來樂事在田園，歸路無人早著鞭。", "見一堂中誰是伴，亭亭修竹鎖蒼烟。"]'),
('f2844c3e-fa19-4c28-a82e-65285c030d18','代梁總挽鄭舜舉侍郎四首  其四','劉宰','宋','宋诗','song-poetry','','[]','慷慨論交酒一鍾，別來木末幾西風。',32,'全唐诗/poet.song.182000.json','["慷慨論交酒一鍾，別來木末幾西風。", "歸歟擬趁雞豚社，太息無因見此公。"]'),
('ee42c3d4-d042-4641-83ac-fa8df40456a8','挽京口使君豐郎中十首  其一','劉宰','宋','宋诗','song-poetry','','[]','先帝龍飛第一春，銀袍鵠立對嚴宸。',32,'全唐诗/poet.song.182000.json','["先帝龍飛第一春，銀袍鵠立對嚴宸。", "當時舊侶能多少，又向風前哭此人。"]'),
('e97d3d6d-f26c-45b5-85b3-b024b0694d05','挽京口使君豐郎中十首  其二','劉宰','宋','宋诗','song-poetry','','[]','妙年意氣已橫秋，不爲身謀爲國謀。',32,'全唐诗/poet.song.182000.json','["妙年意氣已橫秋，不爲身謀爲國謀。", "斥去佞臣談笑裏，英名高壓漢朱浮。"]'),
('24a81617-eee1-4e29-993a-0684f7aaed25','挽京口使君豐郎中十首  其三','劉宰','宋','宋诗','song-poetry','','[]','開邊爲計苦匆匆，淮水東流戰血紅。',32,'全唐诗/poet.song.182000.json','["開邊爲計苦匆匆，淮水東流戰血紅。", "軍令一申人百勇，議郎當日佐元戎。"]'),
('e4ceeb83-df3d-4d01-96c5-d347c28be319','挽京口使君豐郎中十首  其四','劉宰','宋','宋诗','song-poetry','','[]','再向江淮把一麾，民情可但不能欺。',32,'全唐诗/poet.song.182000.json','["再向江淮把一麾，民情可但不能欺。", "來時叔度嗟何暮，去日何公苦見思。"]'),
('5a525357-871f-49c4-96f5-e82322b1a084','挽京口使君豐郎中十首  其五','劉宰','宋','宋诗','song-poetry','','[]','牢盆利散海隅空，一念焦勞軫聖衷。',32,'全唐诗/poet.song.182000.json','["牢盆利散海隅空，一念焦勞軫聖衷。", "萬井春回和氣滿，皇華玉節到淮東。"]'),
('74adda3b-1ea5-450b-a41c-562b6bb966af','挽京口使君豐郎中十首  其六','劉宰','宋','宋诗','song-poetry','','[]','慘澹胡沙草木腥，長淮坐斷倚賢城。',32,'全唐诗/poet.song.182000.json','["慘澹胡沙草木腥，長淮坐斷倚賢城。", "策勳歸去猶遺憾，未挽天河洗甲兵。"]'),
('97ffcc00-d491-4f9d-96df-472c0314034b','挽京口使君豐郎中十首  其七','劉宰','宋','宋诗','song-poetry','','[]','殘胡失馭走群雄，人物爭歸掌握中。',32,'全唐诗/poet.song.182000.json','["殘胡失馭走群雄，人物爭歸掌握中。", "河洛祇今修舊貢，凌烟端合首羣公。"]'),
('0ea0b3f9-b423-4fbd-a7b7-caa327cc88d5','挽京口使君豐郎中十首  其八','劉宰','宋','宋诗','song-poetry','','[]','持橐無由侍玉皇，含香僅長漢諸郎。',32,'全唐诗/poet.song.182000.json','["持橐無由侍玉皇，含香僅長漢諸郎。", "豐碑不用書成績，自有司勳紀太常。"]'),
('f81a7c5c-f281-437b-919e-27a0f5fb5ddc','挽京口使君豐郎中十首  其九','劉宰','宋','宋诗','song-poetry','','[]','南徐開府未旬時，一掃煩苛布惠慈。',32,'全唐诗/poet.song.182000.json','["南徐開府未旬時，一掃煩苛布惠慈。", "孺子竟孤懸榻望，伯牙空有絕絃悲。"]'),
('cf1cec2f-19ff-4b71-ac39-0fd4187aa1a2','挽京口使君豐郎中十首  其一○','劉宰','宋','宋诗','song-poetry','','[]','問訊時來野叟家，細書整整復斜斜。',32,'全唐诗/poet.song.182000.json','["問訊時來野叟家，細書整整復斜斜。", "江湖老矣何人記，淚逐西風染釣車。"]'),
('f69e3de4-7e64-4af1-9772-c6cc82347186','挽葛簽判二首  其一','劉宰','宋','宋诗','song-poetry','','[]','先帝龍飛第一春，霜袍濟濟對嚴宸。',32,'全唐诗/poet.song.182000.json','["先帝龍飛第一春，霜袍濟濟對嚴宸。", "祇今舊侶能多少，又對西風哭此人。"]'),
('0570e016-06bf-4d28-a972-b7e4d0f8bbfa','挽葛簽判二首  其二','劉宰','宋','宋诗','song-poetry','','[]','少長相望十五年，君鬚未白我華顛。',32,'全唐诗/poet.song.182000.json','["少長相望十五年，君鬚未白我華顛。", "擬求勾漏還丹術，忍賦山陽懷舊篇。"]'),
('0e0c8652-5dc8-4c24-b9d2-f5d282e88325','挽恭靖司法兄九首  其一','劉宰','宋','宋诗','song-poetry','','[]','雪壓茅茨半欲傾，夜闌猶聽讀書聲。',32,'全唐诗/poet.song.182000.json','["雪壓茅茨半欲傾，夜闌猶聽讀書聲。", "蒼苔翠竹迷遺址，尚想寒窗對短檠。"]'),
('ca7d678d-b060-46cb-b785-6334cc7ce316','挽恭靖司法兄九首  其二','劉宰','宋','宋诗','song-poetry','','[]','日晏炊烟冷屋山，典書糴米奉慈顔。',32,'全唐诗/poet.song.182000.json','["日晏炊烟冷屋山，典書糴米奉慈顔。", "祇今童稚便安養，一飽誰知有許艱。"]'),
('e45ac147-566f-4d6c-8908-96cc79a901ec','挽恭靖司法兄九首  其三','劉宰','宋','宋诗','song-poetry','','[]','賢書五上動宸旒，鵰鶚橫飛正得秋。',32,'全唐诗/poet.song.182000.json','["賢書五上動宸旒，鵰鶚橫飛正得秋。", "老去劉蕡終不第，時來校尉幾封侯。"]'),
('4883a8df-f0a2-4226-b04a-be4efbb83ff7','挽恭靖司法兄九首  其四','劉宰','宋','宋诗','song-poetry','','[]','詞場士氣久衰頹，得喪關心日九迴。',32,'全唐诗/poet.song.182000.json','["詞場士氣久衰頹，得喪關心日九迴。", "但使聖朝聞鯁論，不妨夫子遜倫魁。"]'),
('bd89c4ee-dfd7-48a0-a84a-a8d19988d7b8','挽恭靖司法兄九首  其五','劉宰','宋','宋诗','song-poetry','','[]','踏遍山崖與水邊，要教皇澤下氓編。',32,'全唐诗/poet.song.182000.json','["踏遍山崖與水邊，要教皇澤下氓編。", "祇今桐汭民猶活，問訊南昌尉已仙。"]'),
('3f651025-63f2-424c-8a3b-f8b4b100211f','挽恭靖司法兄九首  其六','劉宰','宋','宋诗','song-poetry','','[]','羊勝公孫兩者間，端人著脚固應難。',32,'全唐诗/poet.song.182000.json','["羊勝公孫兩者間，端人著脚固應難。", "法曹賸有梅花句，拂袖何妨載月還。"]'),
('d91f5d1e-d031-4617-a94c-bc41f9c23267','挽恭靖司法兄九首  其七','劉宰','宋','宋诗','song-poetry','','[]','沉酣博塞兩防微，男業詩書女治絲。',32,'全唐诗/poet.song.182000.json','["沉酣博塞兩防微，男業詩書女治絲。", "遺訓一編昭日月，宗門於此卜興衰。"]'),
('ffdcd627-f61c-4c50-87bd-a9ee228d93dd','挽恭靖司法兄九首  其八','劉宰','宋','宋诗','song-poetry','','[]','雙劍齊飛下九淵，更驚白璧墮黄泉。',32,'全唐诗/poet.song.182000.json','["雙劍齊飛下九淵，更驚白璧墮黄泉。", "世間何用知非福，獨立斜陽意惘然。"]'),
('eb68f55f-bd80-4f61-bd44-eabb6bcaa616','挽恭靖司法兄九首  其九','劉宰','宋','宋诗','song-poetry','','[]','論心海內幾親朋，歲晚相依祇弟兄。',32,'全唐诗/poet.song.182000.json','["論心海內幾親朋，歲晚相依祇弟兄。", "夜雨對床無復昔，春風回首獨傷情。"]'),
('6fc737ec-f3fe-4bf2-a0d6-ed7c91760748','挽許馬帥二首  其一','劉宰','宋','宋诗','song-poetry','','[]','萬旅雲屯獨鼓行，將軍誓死不求生。',32,'全唐诗/poet.song.182000.json','["萬旅雲屯獨鼓行，將軍誓死不求生。", "祇今淮浦耕桑滿，膽落胡兒不敢爭。"]'),
('5078a1ce-a786-4e32-b405-a1cc8f670fdd','挽許馬帥二首  其二','劉宰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','南歸更擁碧油幢，指點羣兒受虜降。',32,'全唐诗/poet.song.182000.json','["南歸更擁碧油幢，指點羣兒受虜降。", "猛志不應同逝水，英名千古鎮長江。"]'),
('3b2d87e2-6320-4379-94e9-8b100cf46baf','悼里中百歲張翁','劉宰','宋','宋诗','song-poetry','','[]','銘旌一丈裊寒烟，淚逐西風洒道邊。',32,'全唐诗/poet.song.182000.json','["銘旌一丈裊寒烟，淚逐西風洒道邊。", "縱使後人能百歲，太平誰識靖康年。"]'),
('51700f0e-5d09-4b59-bc50-b243f04a9d1b','挽師虞卿三首  其一','劉宰','宋','宋诗','song-poetry','','[]','淵源師友鄴侯門，赫奕家聲漢相孫。',32,'全唐诗/poet.song.182000.json','["淵源師友鄴侯門，赫奕家聲漢相孫。", "冠带僅容遊璧水，姓名竟不上慈恩。"]'),
('b0c6b9b6-fa2d-4fe5-9a3f-97bed9c2ac92','挽師虞卿三首  其二','劉宰','宋','宋诗','song-poetry','','[]','蚤歲謀生愧弟昆，一窗容膝眇乾坤。',32,'全唐诗/poet.song.182000.json','["蚤歲謀生愧弟昆，一窗容膝眇乾坤。", "田園歲晚非能事，祇有詩書遺子孫。"]'),
('48578c84-b8ec-4a51-99de-6161501d1e2e','挽師虞卿三首  其三','劉宰','宋','宋诗','song-poetry','','[]','年時床下拜龐公，雞黍留連日正中。',32,'全唐诗/poet.song.182000.json','["年時床下拜龐公，雞黍留連日正中。", "客子倦遊歸計速，傷心先友轉頭空。"]'),
('28874222-ea36-4cc7-a4df-23caf1b3c9cf','挽王德彰','劉宰','宋','宋诗','song-poetry','','[]','籃輿咿軋不辭貧，烏帽離披當幅巾。',32,'全唐诗/poet.song.182000.json','["籃輿咿軋不辭貧，烏帽離披當幅巾。", "一劑沖和療寒疾，鄉間不復見斯人。"]'),
('5f2f022a-a9cf-4ce1-84e1-ebff1d44f5b7','挽錢承事','劉宰','宋','宋诗','song-poetry','','[]','藥市能推此念誠，一言爲重萬金輕。',32,'全唐诗/poet.song.182000.json','["藥市能推此念誠，一言爲重萬金輕。", "特書會有河東柳，爲記嘉名埒宋清。"]'),
('90978b66-8580-4a03-ad40-7f275aa5fba9','挽殷君二首  其一','劉宰','宋','宋诗','song-poetry','','[]','汗衣亭午亞紅塵，中有池塘得句人。',32,'全唐诗/poet.song.182000.json','["汗衣亭午亞紅塵，中有池塘得句人。", "雅趣終難混塵俗，匆匆歸卜太初鄰。"]'),
('2194eced-522c-4eef-83d7-968c0a6b9923','挽殷君二首  其二','劉宰','宋','宋诗','song-poetry','','[]','市人於利較毫釐，之子能權取與宜。',32,'全唐诗/poet.song.182000.json','["市人於利較毫釐，之子能權取與宜。", "此去窮閻風雨夜，幾多愁坐憶年時。"]'),
('0e8ccb98-d199-45cd-b3cb-7d4b1366bc5e','挽葛知錄母二首  其一','劉宰','宋','宋诗','song-poetry','','[]','人間盛事古難并，結髮相看兩壽寧。',32,'全唐诗/poet.song.182000.json','["人間盛事古難并，結髮相看兩壽寧。", "彤管忽成賢母傳，紫霄獨耀老人星。"]'),
('8e9cceb8-ceae-4f0a-aef1-9483b225db33','挽葛知錄母二首  其二','劉宰','宋','宋诗','song-poetry','','[]','青袍綠髮映斑衣，幕府風流彼一時。',32,'全唐诗/poet.song.182000.json','["青袍綠髮映斑衣，幕府風流彼一時。", "雲馭歸歟可無憾，承家猶有寧馨兒。"]'),
('452fee9c-ace9-4fa4-ab1d-b56c3246617a','代挽趙工侍湯氏令人三首  其一','劉宰','宋','宋诗','song-poetry','','[]','傳柑歸遺惹天香，折桂重看膝上郎。',32,'全唐诗/poet.song.182000.json','["傳柑歸遺惹天香，折桂重看膝上郎。", "貝葉經中空世念，菱花鏡裏謝宮裝。"]'),
('6af17f42-0161-4b60-9035-73ce2dd84677','代挽趙工侍湯氏令人三首  其二','劉宰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖野樹上林花，行樂誰知大尹家。',32,'全唐诗/poet.song.182000.json','["西湖野樹上林花，行樂誰知大尹家。", "簾幕垂垂人兀坐，金猊香散日西斜。"]'),
('a6a05d0e-b075-44c3-be92-2649c74c99c8','代挽趙工侍湯氏令人三首  其三','劉宰','宋','宋诗','song-poetry','','[]','白蓮塘下成新灧，綠柳堤邊散密陰。',32,'全唐诗/poet.song.182000.json','["白蓮塘下成新灧，綠柳堤邊散密陰。", "精舍拂雲松柏繚，死生何地不娛心。"]'),
('b4d10f68-977c-456f-8c10-b7305f2bd148','挽李閩帥母夫人三首  其一','劉宰','宋','宋诗','song-poetry','','[]','夫人天賦與神靈，初度祥光燭戶庭。',32,'全唐诗/poet.song.182000.json','["夫人天賦與神靈，初度祥光燭戶庭。", "歸去足知躔次在，九霄還要老人星。"]'),
('bcc4f1ea-e279-4005-b682-25cf1d5a2eca','挽李閩帥母夫人三首  其二','劉宰','宋','宋诗','song-poetry','','[]','旌旗直指陣雲開，文駟雕軒壽母來。',32,'全唐诗/poet.song.182000.json','["旌旗直指陣雲開，文駟雕軒壽母來。", "萬古歡呼和氣蕩，胡兒不戰倒戈回。"]'),
('9075dc31-50f3-4409-ba78-9b16dd1c1cea','挽李閩帥母夫人三首  其三','劉宰','宋','宋诗','song-poetry','','[]','九十餘齡地上仙，人間五福信兼全。',32,'全唐诗/poet.song.182000.json','["九十餘齡地上仙，人間五福信兼全。", "可憐閩部思賢牧，猶恨夫人不百年。"]'),
('73ac6ef9-d6a3-424e-bde0-aa1dfe51a19f','挽衛氏孺人','劉宰','宋','宋诗','song-poetry','','[]','兩家濟濟秀孫枝，九秩巍巍享壽巵。',32,'全唐诗/poet.song.182000.json','["兩家濟濟秀孫枝，九秩巍巍享壽巵。", "厚福人間無處著，驂鸞一笑上瑶池。"]'),
('cd18414a-dfdf-437d-a7fb-2cc76939467b','挽錢賢良','劉宰','宋','宋诗','song-poetry','','[]','奏篇重徹冕旒前，欲挽銀河蕩八埏。',64,'全唐诗/poet.song.182000.json','["奏篇重徹冕旒前，欲挽銀河蕩八埏。", "六計不爲當世用，一編空受老人傳。", "規恢漢祚天方啟，問訊南昌尉已仙。", "遇合無人會成數，故山松柏慘寒烟。"]'),
('5e5e0bda-ba33-4451-8527-513aa255be77','挽太平趙倅三首  其一','劉宰','宋','宋诗','song-poetry','','[]','大雅如公信不羣，書藏萬卷筆如神。',64,'全唐诗/poet.song.182000.json','["大雅如公信不羣，書藏萬卷筆如神。", "再從鶚表騰霄漢，直上龍門振羽鱗。", "蓮幕今無居右客，花封舊有去思民。", "從來姑孰佳山水，可惜題輿失偉人。"]'),
('40f58bd5-ca02-4fbe-8c41-eaa45922a39d','挽太平趙倅三首  其二','劉宰','宋','宋诗','song-poetry','','[]','薄俗紛紛不再淳，吁嗟公子獨振振。',64,'全唐诗/poet.song.182000.json','["薄俗紛紛不再淳，吁嗟公子獨振振。", "從知爲善身心樂，不憚分財手足親。", "韋布幾人勤禮遇，杯盤一笑見天真。", "蒼蒼誰謂渾無信，千里名駒已絕塵。"]'),
('5a836af1-c19c-4b1f-b6e5-5abdded410b6','挽太平趙倅三首  其三','劉宰','宋','宋诗','song-poetry','','[]','當年垂橐叩天閽，自笑唯餘舌尚存。',64,'全唐诗/poet.song.182000.json','["當年垂橐叩天閽，自笑唯餘舌尚存。", "下榻勤君延孺子，加餐愧我異王孫。", "歸歟益軫門闌舊，至止頻承笑語溫。", "一日佳城符吉兆，千年福地鎖靈根。"]'),
('ce16c256-6b72-4d82-b484-4d1dd4103bf0','挽許通判二首  其一','劉宰','宋','宋诗','song-poetry','','[]','妙年故府接英游，盍上周行展壯猷。',64,'全唐诗/poet.song.182000.json','["妙年故府接英游，盍上周行展壯猷。", "再命去天仍不遠，此心於世澹無求。", "奏功僅許臨巖邑，投老纔能貳大州。", "總爲當時人物惜，於公行止一虛舟。"]'),
('cb618ee2-688e-4d9f-9e82-966d4fe4974a','挽許通判二首  其二','劉宰','宋','宋诗','song-poetry','','[]','問訊吾邦鶴髮翁，惟公遺愛百年中。',64,'全唐诗/poet.song.182000.json','["問訊吾邦鶴髮翁，惟公遺愛百年中。", "輕刑競喜椼楊脫，薄賦誰嗟杼軸空。", "遠卜雖孤桐邑望，貞游還喜葛仙同。", "從今枌社添尸祝，一念遥應肸蠁通。"]'),
('0afaf633-2b0c-4c31-a765-c8567e63173f','挽陶宣義二首  其一','劉宰','宋','宋诗','song-poetry','','[]','歷數陰功滿巨編，皇天佑善信昭然。',64,'全唐诗/poet.song.182000.json','["歷數陰功滿巨編，皇天佑善信昭然。", "金閨密勿身通籍，雲路連翩子著鞭。", "貝葉經中無別想，白蓮社裏得真筌。", "忽驚薤露傳新唱，愁鎖松陵柳澤烟。"]'),
('8b8dcce7-6d04-4d18-a1e3-295207c4ee82','挽陶宣義二首  其二','劉宰','宋','宋诗','song-poetry','','[]','季方當日締華姻，曾款門闌列衆賓。',64,'全唐诗/poet.song.182000.json','["季方當日締華姻，曾款門闌列衆賓。", "一別清臺頻換歲，重逢上苑正回春。", "白頭自嘆形容改，青眼相看笑語真。", "回首不堪成永訣，西風吹淚墮衣巾。"]'),
('ca4c85a6-c9af-4000-9091-5dbda5251dd7','挽楊提舉','劉宰','宋','宋诗','song-poetry','','[]','寶經堂上集儒紳，尚記囊書走下陳。',64,'全唐诗/poet.song.182000.json','["寶經堂上集儒紳，尚記囊書走下陳。", "學業如公本天得，笑談於我最情親。", "連床風雨寒窗夜，杯酒湖山上國春。", "壞壁無由見題字，舊游回首重傷神。"]'),
('24b94093-665e-470a-aa3e-9d8d97810707','挽知府趙開國','劉宰','宋','宋诗','song-poetry','','[]','青衫試據憶當年，傾蓋欣逢令尹賢。',64,'全唐诗/poet.song.182000.json','["青衫試據憶當年，傾蓋欣逢令尹賢。", "一遠朋從忘歲月，相思客路渺山川。", "政成郡國君何憾，病卧閭閻我自憐。", "誤喜鴈來猶寄字，傷心鶴駕已騰天。"]'),
('f46d1f49-deb9-4a13-bf93-f2e1666335e2','挽陳運幹','劉宰','宋','宋诗','song-poetry','','[]','三載毗陵舊長官，棠陰猶鎖暮烟寒。',64,'全唐诗/poet.song.182000.json','["三載毗陵舊長官，棠陰猶鎖暮烟寒。", "紅蓮幕下籌方運，細柳營中食已寬。", "家近不妨同晝錦，才難正合整朝冠。", "如何又作堂堂去，只有新詩付不刊。"]'),
('91bd0309-33ee-4aaf-97fc-671fa58d8042','挽戴主簿','劉宰','宋','宋诗','song-poetry','','[]','妙年筆勢已飛揚，便合收功翰墨場。',64,'全唐诗/poet.song.182000.json','["妙年筆勢已飛揚，便合收功翰墨場。", "黄甲未容登上第，青衫聊用慰高堂。", "一同簿領棠猶在，三逕歸來菊未荒。", "下榻忍思疇昔事，送車空憶水雲鄉。"]'),
('07cb6ac4-8d69-4701-8fd5-cd0bd2d6273d','挽姚政遠','劉宰','宋','宋诗','song-poetry','','[]','尚記僑居憶故園，俄聞華屋聳榱椽。',64,'全唐诗/poet.song.182000.json','["尚記僑居憶故園，俄聞華屋聳榱椽。", "連檣大舶回前浦，皓齒清歌出廣筵。", "得喪已齊身外物，安閒自樂性中天。", "岳莊原上歸全處，手種松杉起綠烟。"]'),
('98373818-2a1a-429a-9e72-094fb09c52c1','挽楊真州母夫人二首  其一','劉宰','宋','宋诗','song-poetry','','[]','江頭千騎肅傳呼，五馬東來侍板輿。',64,'全唐诗/poet.song.182000.json','["江頭千騎肅傳呼，五馬東來侍板輿。", "賸欲平反供母笑，不妨寬大奉君書。", "凝香堂上榮何限，戲綵圖中畫不如。", "底事乘鸞天上去，固教遺恨滿鄉閭。"]'),
('183f9952-841b-4e05-af72-c1b206eef9fc','挽楊真州母夫人二首  其二','劉宰','宋','宋诗','song-poetry','','[]','祥烟霽日麗重闈，尚記升堂拜母時。',64,'全唐诗/poet.song.182000.json','["祥烟霽日麗重闈，尚記升堂拜母時。", "楚楚賓朋環綺席，翩翩仙子奉瑶巵。", "五花天上疏恩寵，九秩人間仰壽祺。", "盛事只今難彷彿，送車千乘擁靈輀。"]'),
('b02c40fc-1483-4076-b43e-853e1ac80ae7','挽桂山君王伯奇','劉宰','宋','宋诗','song-poetry','','[]','桂山山在天台上，秋風吹雲列屏障。',64,'全唐诗/poet.song.182000.json','["桂山山在天台上，秋風吹雲列屏障。", "山中有客芙蓉裳，日日來看桂叢長。", "老我住在京江湄，光芒夜夜占少微。", "哀哉死者不可作，薤露忽更招隠詞。"]'),
('bb32f5e5-de81-413a-98fc-f3f291c17af2','周侯古祠','劉宰','宋','宋诗','song-poetry','','[]','廟宇巍峩對古墳，將軍英氣宛如存。',64,'全唐诗/poet.song.182000.json','["廟宇巍峩對古墳，將軍英氣宛如存。", "當時改行除民害，歷代封功沐寵恩。", "虎穴雲埋山寂寞，蛟溪波冷月黄昏。", "我來吊古追行樂，駐馬花前酹一樽。"]'),
('a0d0bcf7-fea3-41a7-b747-9266c76af65e','句','劉宰','宋','宋诗','song-poetry','','[]','選詩非選官，論詩非論人。',12,'全唐诗/poet.song.182000.json','["選詩非選官，論詩非論人。"]'),
('9ba534db-1fec-4a4a-b1d8-eaeb7834fd50','賀太常黄少卿','呂聲之','宋','宋诗','song-poetry','','[]','自從朝奏一封還，便整歸裝問故山。',64,'全唐诗/poet.song.182000.json','["自從朝奏一封還，便整歸裝問故山。", "剩得清名千載重，何妨晚節十年閒。", "慣尋夜雪逵溪路，却謝春風漢殿班。", "國史舊編加簡討，春秋直筆任詩刪。"]'),
('7ed11ca1-7903-4e5a-97e4-d0793262fc8a','次新邑錢宰黄丞韻','呂聲之','宋','宋诗','song-poetry','','[]','一邑何期獲二賢，花開滿縣總翩翩。',64,'全唐诗/poet.song.182000.json','["一邑何期獲二賢，花開滿縣總翩翩。", "賦詩各出新機錦，裕國還饒內府錢。", "槐竹兩行公事辦，絲桐三弄政聲傳。", "作成和氣農家好，多稼如雲詠大田。"]'),
('a8c6ef82-9ca5-4e30-a5b8-093ba45ff4e8','過杜潭題曾祖慶源庵','呂聲之','宋','宋诗','song-poetry','','[]','橫江灝氣欲欺裘，木落千林水露洲。',64,'全唐诗/poet.song.182000.json','["橫江灝氣欲欺裘，木落千林水露洲。", "偶爲搜荒投隴畝，因而展省到松楸。", "神駒已應當年兆，祥筍還爲後裔留。", "寄與老僧勤灑掃，庭前橘綠桂香浮。"]'),
('021e6b21-f631-4f6a-bd70-56adbaf096e2','和張主簿喜雪','呂聲之','宋','宋诗','song-poetry','','[]','夜讀書窗未覺貧，朝看萬瓦沒魚鱗。',64,'全唐诗/poet.song.182000.json','["夜讀書窗未覺貧，朝看萬瓦沒魚鱗。", "飄來灞岸春風絮，瀉下瀛洲玉斛塵。", "笑我冗懷多俗事，羨君清思獨凝神。", "遥憐夜月山陰道，還有扁舟乘興人。"]'),
('e6157522-74bb-403a-ab36-da4d97960142','題南巖寺','呂聲之','宋','宋诗','song-poetry','','[]','誰把長竿釣巨魚，至今蹲石倚空虛。',64,'全唐诗/poet.song.182000.json','["誰把長竿釣巨魚，至今蹲石倚空虛。", "蜂房愛向山崖結，鳥跡疑從海島居。", "入座翠嵐生晝寂，夾川紅樹照春餘。", "任公此去三千載，爲看芳碑一嘅吁。"]'),
('c2fc7bbe-05ae-4643-9ba4-571e56a4bc32','遊石佛寺','呂聲之','宋','宋诗','song-poetry','','[]','金吾不必問行由，此去逍遥物外遊。',64,'全唐诗/poet.song.182000.json','["金吾不必問行由，此去逍遥物外遊。", "半塢白雲藏宿霧，一聲橫笛下歸牛。", "喜瞻傑閣三生像，藐視叢林四海州。", "爲寫濯纓疎拙句，誰言墨跡至今留。"]'),
('e8f128e5-5758-499e-a172-9c7e4a749bbc','題陳巖庵寄諸兄弟','呂聲之','宋','宋诗','song-poetry','','[]','地接丹丘姥嶺賒，山盤曲折狀如蛇。',64,'全唐诗/poet.song.182000.json','["地接丹丘姥嶺賒，山盤曲折狀如蛇。", "每因過此瞻雙隴，何必從旁置萬家。", "孝弟本根時潤澤，詩書種子日萌芽。", "到來豈但春秋祀，酌水何妨一獻花。"]'),
('f6bb7902-00f2-4119-b416-95c767554d5a','開禧丁卯重過龍門有懷方丈老子','呂聲之','宋','宋诗','song-poetry','','[]','翠屋交空結夏陰，征鞍亭午喜登臨。',64,'全唐诗/poet.song.182000.json','["翠屋交空結夏陰，征鞍亭午喜登臨。", "披開草棘千重路，洗出冰壺一片心。", "禪老還尋江浙去，詩家誰作楚梁吟。", "須知珠玉元無踵，不惜西風惠我音。"]'),
('219a435b-5081-4204-87cd-1597df1e9c68','謝張漕薦剡','呂聲之','宋','宋诗','song-poetry','','[]','誰人洗甲挽天河，玉宇無塵海不波。',64,'全唐诗/poet.song.182000.json','["誰人洗甲挽天河，玉宇無塵海不波。", "漢使褰帷將命出，淮民挾纊被恩多。", "流離豈但身安集，凋瘵親曾手拊摩。", "惠利纔施催召亟，其如席未及溫何。"]'),
('aefcd568-2d74-4132-af8e-dac3b351452b','賀葉司業兼中書舍人','呂聲之','宋','宋诗','song-poetry','','[]','英妙才華四十年，山林朝市姓名傳。',64,'全唐诗/poet.song.182000.json','["英妙才華四十年，山林朝市姓名傳。", "何妨萬斛橫江上，不礙千帆過目前。", "我肯尾書干木紙，人饒首著祖生鞭。", "金鑾何日商風雅，伴直能呼孟浩然。"]'),
('f040bda7-5fd4-416c-b0ae-bf28a9614812','寄太湖黄縣尉','呂聲之','宋','宋诗','song-poetry','','["\u592a\u6e56"]','立頃談餘袂輒分，乖離數數異朋羣。',64,'全唐诗/poet.song.182000.json','["立頃談餘袂輒分，乖離數數異朋羣。", "君如天揭行空日，我亦風吹過嶺雲。", "不許范張同飯黍，空慙李杜共論文。", "睽違動涉經年裏，棋壘詩壇要策勳。"]'),
('0ef0380c-67dc-41ac-b798-a7e0bd0fdf0b','與丁撫幹','呂聲之','宋','宋诗','song-poetry','','[]','兩年肥水喜相逢，託契門牆今已重。',64,'全唐诗/poet.song.182000.json','["兩年肥水喜相逢，託契門牆今已重。", "士有禰衡心肯薦，侯如雍齒首先封。", "更看謀略稱籌幄，會見精神坐折衝。", "敗走苻堅兵百萬，圍棋別墅意從容。"]'),
('7917a288-1db1-42c4-baae-c09cde40b01f','悼止齋陳先生','呂聲之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬里長江發自岷，作興一代有斯人。',64,'全唐诗/poet.song.182000.json','["萬里長江發自岷，作興一代有斯人。", "六經疑難言前解，千古興亡筆下陳。", "愛向田間看耜耒，肯留天上掌絲綸。", "如公到處鎸佳句，今日池塘草自春。"]'),
('63ea5ccd-5f85-4943-b260-45fa03cc0b72','舒城道中','呂聲之','宋','宋诗','song-poetry','','[]','還轅天作十分晴，瀉出秋光一派清。',64,'全唐诗/poet.song.182000.json','["還轅天作十分晴，瀉出秋光一派清。", "走筆欲題人到跡，揚鞭不住馬嘶聲。", "頃禾晚熟黄雲色，籬菊朝含白露英。", "得似淵明便歸去，候門童稚出歡迎。"]'),
('4edb44d1-0773-40af-a987-d4a2ce5ce51f','重陽桐城道中','呂聲之','宋','宋诗','song-poetry','','[]','萬古長淮一带流，從來戰地不容休。',64,'全唐诗/poet.song.182000.json','["萬古長淮一带流，從來戰地不容休。", "間關千里軍前餉，牢落重陽客裏秋。", "悵望白衣來送酒，了無黄菊與簪頭。", "何人早斷樓蘭首，試解君王宵旰憂。"]'),
('e9bb09f3-a2cf-436b-82c8-79872b7c186c','九日登資福山呈胡宣教','呂聲之','宋','宋诗','song-poetry','','[]','飛屐來登最上峰，千山擁翠景無窮。',64,'全唐诗/poet.song.182000.json','["飛屐來登最上峰，千山擁翠景無窮。", "遥看雲影參差外，靜聽泉聲斷續中。", "今日黄花重九約，何時青眼一尊同。", "好天風月閒相寄，早晚南來有過鴻。"]'),
('82ff6e97-91f8-475c-b3b3-5d524c3fe55c','西寺留題','呂聲之','宋','宋诗','song-poetry','','[]','白石孤雲自在閒，紅塵一事不相關。',64,'全唐诗/poet.song.182000.json','["白石孤雲自在閒，紅塵一事不相關。", "寺遮翠靄青蘿外，人到落花流水間。", "欲效錦囊收勝概，慚無玉带鎮名山。", "白蓮喜結當年社，未厭朝來暮便還。"]'),
('a926993e-0274-4a8a-a66b-6d964d50f359','題龍翔觀','呂聲之','宋','宋诗','song-poetry','','[]','曾到龍翔不記年，兩峰巍壓水中天。',64,'全唐诗/poet.song.182000.json','["曾到龍翔不記年，兩峰巍壓水中天。", "潮生潮落青蕪外，人去人來白鷺邊。", "四接遠遊僧萬笠，重新舊觀屋千椽。", "東南送目秋無際，隔岸人家問釣船。"]'),
('fd632465-a66b-4f6a-b099-9de2bc5fd515','和黄教授山堂招飲','呂聲之','宋','宋诗','song-poetry','','[]','鼎彝事業未渠休，鷗鷺尋盟暫與儔。',64,'全唐诗/poet.song.182000.json','["鼎彝事業未渠休，鷗鷺尋盟暫與儔。", "路入芝巖真絕地，客延蓬島盡名流。", "不辭一洗陶巾醉，更擬雙飛謝屐遊。", "誰賞洪都高閣句，落霞孤鶩唱漁舟。"]'),
('4357ab51-f7b1-46e6-8dcd-1808c21351ec','謝石主簿和章','呂聲之','宋','宋诗','song-poetry','','[]','多君養就大椿年，便腹詩書晝欲眠。',64,'全唐诗/poet.song.182000.json','["多君養就大椿年，便腹詩書晝欲眠。", "絳闕當年名藉甚，白雲他日迹飄然。", "千軍筆掃人誰敵，九轉丹成世莫傳。", "倦眼功名旁袖手，剩看月露出新篇。"]'),
('c509ab65-4ded-4bb8-83dc-bebf3e9ae726','詠桂花','呂聲之','宋','宋诗','song-poetry','','[]','獨占三秋壓衆芳，何誇橘綠與橙黄。',64,'全唐诗/poet.song.182000.json','["獨占三秋壓衆芳，何誇橘綠與橙黄。", "自從分下月中種，果若飄來天際香。", "清影不嫌秋露白，新叢偏带晚烟蒼。", "高枝已折郄生手，萬斛奇芬貯錦囊。"]'),
('cc6344f7-82e6-49a4-a7d0-685309bd93b5','和王子寬韵','呂聲之','宋','宋诗','song-poetry','','[]','綠蔭千重竹，清流一带溪。',48,'全唐诗/poet.song.182000.json','["綠蔭千重竹，清流一带溪。", "子真耕谷口，楊震講關西。", "手摘星辰近，名登泰華齊。", "古來公相業，誰不起鋤犂。"]'),
('4d87522e-5b10-4425-841c-8b754f9c735e','春郊','呂聲之','宋','宋诗','song-poetry','','[]','勝日遊郊外，嵐光入眼新。',24,'全唐诗/poet.song.182000.json','["勝日遊郊外，嵐光入眼新。", "桃花開萬樹，又是一年人。"]'),
('9d52e668-34a1-4bb6-95d5-ad5bd82ad110','山行','呂聲之','宋','宋诗','song-poetry','','[]','山花雨後紅，野草風前綠。',24,'全唐诗/poet.song.182000.json','["山花雨後紅，野草風前綠。", "浩歌歸去來，不辱在知足。"]'),
('5e0eade6-680a-41f8-8ff9-bbfc2dcf8a9b','先春','呂聲之','宋','宋诗','song-poetry','','[]','不把春光較後先，清香自是壓羣妍。',32,'全唐诗/poet.song.182000.json','["不把春光較後先，清香自是壓羣妍。", "微酸一點功成日，桃李從他逞少年。"]'),
('a2261ddd-9830-4a44-b8db-3c18eb0afffa','雲錦','呂聲之','宋','宋诗','song-poetry','','[]','擁盖難遮萬臉紅，爛然雲錦直連空。',32,'全唐诗/poet.song.182000.json','["擁盖難遮萬臉紅，爛然雲錦直連空。", "更看雨過新妝洗，百媚都含一笑中。"]'),
('e6d736e5-7e94-4582-a023-1a99f9853616','紫霄亭  其一','呂聲之','宋','宋诗','song-poetry','','[]','半空烟雨有無間，碧玉屏開四面山。',32,'全唐诗/poet.song.182000.json','["半空烟雨有無間，碧玉屏開四面山。", "我欲紫霄亭上望，吹笙人去幾時還。"]'),
('386f94eb-4ed8-478c-abf9-acebf7b9eb0a','紫霄亭  其二','呂聲之','宋','宋诗','song-poetry','','[]','未把浮漚閲世間，蓬萊一水隔三山。',32,'全唐诗/poet.song.182000.json','["未把浮漚閲世間，蓬萊一水隔三山。", "試窮千里登臨目，望斷青山白鳥還。"]'),
('7f562150-8f8d-4275-88c9-cd8d2c2e3323','芙蓉','呂聲之','宋','宋诗','song-poetry','','[]','楓葉飄林竹隔牆，偏于冷淡逞濃粧。',32,'全唐诗/poet.song.182000.json','["楓葉飄林竹隔牆，偏于冷淡逞濃粧。", "天教不趁繁華月，要是秋來獨耐霜。"]'),
('1151fe5e-df72-4bba-9d03-b51e7be86001','括蒼山行','呂聲之','宋','宋诗','song-poetry','','[]','微風吹雨濕欄干，薄霧籠晴带淺寒。',32,'全唐诗/poet.song.182000.json','["微風吹雨濕欄干，薄霧籠晴带淺寒。", "一樹紅梅牆外發，誰家美麗倩人看。"]'),
('86032a2d-5f3c-4ca8-a4c9-023388d03ca4','丹丘道中','呂聲之','宋','宋诗','song-poetry','','[]','夜宿溪頭十里村，數星漁火照籬門。',32,'全唐诗/poet.song.182000.json','["夜宿溪頭十里村，數星漁火照籬門。", "雁山峭絕經行處，猶带烟霞入夢魂。"]'),
('6ed1ae78-9992-4025-b427-7cd612ca80be','縉雲道中','呂聲之','宋','宋诗','song-poetry','','[]','縉雲通道入皇都，花滿京城水滿湖。',32,'全唐诗/poet.song.182000.json','["縉雲通道入皇都，花滿京城水滿湖。", "借問今來丞相府，後園人有醉歌無。"]'),
('0615662d-9c66-44fe-830b-bdad6d83f4ca','遊石城山','呂聲之','宋','宋诗','song-poetry','','[]','祇因尋勝到林泉，四抱迴峰萬景連。',64,'全唐诗/poet.song.182000.json','["祇因尋勝到林泉，四抱迴峰萬景連。", "僧過不知山隠寺，客來方見洞開天。", "浮圖照水光相映，古木依崖影倒懸。", "風露了非人世界，濯纓秋後玉壺天。"]'),
('424df1cf-4163-410e-948b-b6ddab41751c','過七里瀨懷古','呂聲之','宋','宋诗','song-poetry','','[]','七里灘頭訪子陵，水光山色見生平。',64,'全唐诗/poet.song.182000.json','["七里灘頭訪子陵，水光山色見生平。", "欲爲臣子定出處，知與君王分重輕。", "一介草茅真自負，三公軒冕未爲榮。", "我來想像高風在，釣石巖前烟浪生。"]'),
('bfe3cd6b-9f9c-490f-965d-4b78ba9074c9','皆山西爽二亭','姚東','宋','宋诗','song-poetry','','[]','華亭百尺跨嶙峋，照眼風光自吐吞。',64,'全唐诗/poet.song.182000.json','["華亭百尺跨嶙峋，照眼風光自吐吞。", "閒數炊烟分聚落，坐收奇觀入壺尊。", "岡巒繞戶雲生袂，鐃柝無聲月在軒。", "更有何人佩黄犢，耕鋤已徧落霞村。"]'),
('861fa2ea-83ff-4e9e-988c-98f60f9f4f45','麻姑巖','葉發','宋','宋诗','song-poetry','','[]','怪石倚空碧，傳有神仙迹。',48,'全唐诗/poet.song.182000.json','["怪石倚空碧，傳有神仙迹。", "元放古來游，孝先舊曾歷。", "山前無斷碑，往事杳難覓。", "麻姑去不來，青鳥無消息。"]'),
('54647691-0a34-4575-bde4-b17a3a3310ef','留題吳氏園','何渷','宋','宋诗','song-poetry','','[]','傍晚秋暉靜，穿松石路微。',48,'全唐诗/poet.song.182000.json','["傍晚秋暉靜，穿松石路微。", "山川起幽興，杖屨款高扉。", "白首偶成趣，素懷欣未違。", "故園今草棘，飄泊幾時歸。"]'),
('2e90568c-be17-41fc-8275-08505d1e4e3e','遊洞霄宮','鄒杞','宋','宋诗','song-poetry','','[]','天柱古名山，形勢友列嶽。',60,'全唐诗/poet.song.182000.json','["天柱古名山，形勢友列嶽。", "神人巢其巔，咳唾半天落。", "白晝見雲旗，清夜聞笙鶴。", "花源或流紅，仙禽猶搗藥。", "長歌不可見，清風灑寥廓。"]'),
('13ab82bf-406a-4a41-a36f-0e6cd156e7ea','蓬萊山','連三益','宋','宋诗','song-poetry','','[]','蓬萊一境最奇哉，門外坑流傍石隈。',64,'全唐诗/poet.song.182000.json','["蓬萊一境最奇哉，門外坑流傍石隈。", "巨竹不知何日裂，喬松總是昔年栽。", "石移莫匪神功運，巖築更無山鬼來。", "料得衆僧行道處，天花馥郁遍蒼苔。"]'),
('aae0b67e-6af6-4d6d-8dc1-654e52e65df6','泛舟','詹師文','宋','宋诗','song-poetry','','[]','九曲烟霞景若何，移舟曲曲泛清波。',64,'全唐诗/poet.song.182000.json','["九曲烟霞景若何，移舟曲曲泛清波。", "丹峯絕頂籠花木，碧洞當門掛薜蘿。", "仙逕鶴翻松露下，古潭龍蟄水雲多。", "紫陽去後閒風月，獨向平林倚櫂歌。"]'),
('9a1fcb67-105b-40cd-b390-2db01199edda','詠鶴','史彌遜','宋','宋诗','song-poetry','','[]','縞衣湖上月明天，雪影飄飄意欲仙。',32,'全唐诗/poet.song.182000.json','["縞衣湖上月明天，雪影飄飄意欲仙。", "世網從來禁不得，高飛沖破晚秋煙。"]'),
('50964e8c-5e4c-46f1-b0ba-7b950bb6292b','梅花','惠端方','宋','宋诗','song-poetry','','[]','美人在空谷，抱志苦貞潔。',120,'全唐诗/poet.song.182000.json','["美人在空谷，抱志苦貞潔。", "不學桃李顔，甘在枯朽列。", "素衣飄白雲，玉佩綴明月。", "肌膚炯凝脂，容色眩春雪。", "臨風一笑粲，皓齒何瑩澈。", "破鏡忽上天，寒影浸瑶闕。", "少時看玉立，相視已華髮。", "人陳花自新，花巧人更拙。", "勿言花不耐，人竟被花閲。", "付之一尊酒，調以三寸舌。"]'),
('8bb71210-9331-4dd5-9322-3fe77398950e','句','陳渙','宋','宋诗','song-poetry','','[]','炊餠擔頭挑取去，白衣鋪上喝將來。',16,'全唐诗/poet.song.182000.json','["炊餠擔頭挑取去，白衣鋪上喝將來。"]'),
('5d664d3e-5775-4bb3-976b-a8f98daa5ea4','寄從弟善','邱和','宋','宋诗','song-poetry','','[]','海上扶桑散曉暉，荷衣共喜換簑衣。',32,'全唐诗/poet.song.182000.json','["海上扶桑散曉暉，荷衣共喜換簑衣。", "浮雲天外弄濃淡，好趁輕陰未雨歸。"]'),
('d1c44ec9-6cfe-4233-8167-ee5e5a06c95a','天聰洞','周茂良','宋','宋诗','song-poetry','','[]','一竅虛靈異谷神，達聰何事在紅塵。',32,'全唐诗/poet.song.182000.json','["一竅虛靈異谷神，達聰何事在紅塵。", "人間莫道無聞處，天聽從今自我民。"]'),
('310b01f0-b854-4d34-8568-77af5e8ed57f','戲題洞霄','鍾震','宋','宋诗','song-poetry','','[]','之徑縈紆略彴橫，松風和作步虛聲。',64,'全唐诗/poet.song.182000.json','["之徑縈紆略彴橫，松風和作步虛聲。", "泉流碧玉千年潤，山作靈丹九轉成。", "瓊館向曾迎帝輦，冰銜今尚带朝纓。", "若非憫世天留與，那得華胥夢也清。"]'),
('84c938f0-e9d2-409e-9f78-feea913b5d69','題翠蛟亭','鍾震','宋','宋诗','song-poetry','','[]','雙柱蒼寒倚碧天，六鰲駕海湧層巔。',32,'全唐诗/poet.song.182000.json','["雙柱蒼寒倚碧天，六鰲駕海湧層巔。", "東風吹瀑成飛雨，知是潛蛟起晝眠。"]'),
('a8b07752-4360-4111-b4a1-381a7dff8515','翠蛟峰','鍾震','宋','宋诗','song-poetry','','[]','九鎖峯尖不隔霄，翠蛟飛舞挾扶摇。',64,'全唐诗/poet.song.182000.json','["九鎖峯尖不隔霄，翠蛟飛舞挾扶摇。", "氣涵秦嶺千秋雪，聲撼錢塘八月潮。", "頓使形魂生羽翼，安知人世有塵囂。", "此行似了仙槎夢，惟恨來賢不可招。"]'),
('3ac772bf-2ce6-4d78-8b93-ec5a53341689','句','鍾震','宋','宋诗','song-poetry','','[]','君今如鴻鵠，萬里去勇决。',12,'全唐诗/poet.song.182000.json','["君今如鴻鵠，萬里去勇决。"]'),
('05a9d9aa-786a-40e6-917d-f5f123171d77','寄鍾子充','錢厚','宋','宋诗','song-poetry','','[]','倦倚吳門思泬寥，懷人清致詩滿瓢。',64,'全唐诗/poet.song.182000.json','["倦倚吳門思泬寥，懷人清致詩滿瓢。", "池塘芳草夢初斷，風雨落花魂正銷。", "一百五日寒食節，二十四浦春江潮。", "遥知藥圃曉經劚，舍後蘼蕪添綠苗。"]'),
('848182d8-7fb2-451d-a743-aa6dc80bc050','漱石軒  其一','錢厚','宋','宋诗','song-poetry','','[]','危石參差上霄漢，中涵萬壑冰玉清。',32,'全唐诗/poet.song.182000.json','["危石參差上霄漢，中涵萬壑冰玉清。", "與誰流出洗塵滓，遺我一林風雨聲。"]'),
('0e33d286-18ea-4fec-ad63-9d864a7cfa43','漱石軒  其二','錢厚','宋','宋诗','song-poetry','','[]','石竇鳴泉自招隠，故邀風月到林扃。',32,'全唐诗/poet.song.182000.json','["石竇鳴泉自招隠，故邀風月到林扃。", "我今欲去尚回首，多少人來不肯聽。"]'),
('48a70bab-13a0-4672-b03e-0212eaab2cf1','梅亭','錢厚','宋','宋诗','song-poetry','','[]','東風吹雨雨吹花，洗却陰沉放月華。',128,'全唐诗/poet.song.182000.json','["東風吹雨雨吹花，洗却陰沉放月華。", "俗眼總嫌梅太白，嫦娥勾引莫雲遮。", "雲濃更欲催詩句，風急花飛留不住。", "使君喚客早評章，趁渠未點蒼苔路。", "夜闌留月遲春酌，生怕樓頭吹畫角。", "更推銀蠟上寒梢，冷艷燒春春未覺。", "燭光炯炯花冥冥，花前醉倒喚不醒。", "南枝自與北枝語，今夜詩工眼倍清。"]'),
('e844fe8e-896a-4c2c-9c56-b7ab886ee90a','登玲瓏山賦呈章冠叟俞安伸陳安世','錢厚','宋','宋诗','song-poetry','','[]','林扉日日爲誰開，底用潛驅俗駕回。',64,'全唐诗/poet.song.182000.json','["林扉日日爲誰開，底用潛驅俗駕回。", "路有險夷休跌蕩，山無今古只崔嵬。", "千章佳木凌雲上，萬壑清流湧月來。", "寄語游人莫遄邁，世間何處不塵埃。"]'),
('2f1d347e-df5c-451e-9c60-66c6e60979a5','山亭','錢厚','宋','宋诗','song-poetry','','[]','又踏君山路，來驅陌上塵。',48,'全唐诗/poet.song.182000.json','["又踏君山路，來驅陌上塵。", "江仍舊時面，我是去年人。", "愛聽松聲古，休催柳色新。", "片雲銜落日，梅與月爭春。"]'),
('17f1e9da-bb43-4d47-8636-23f5cb07314c','句','錢厚','宋','宋诗','song-poetry','','[]','暮靄不知天遠近，閒雲休礙月升沉。',16,'全唐诗/poet.song.182000.json','["暮靄不知天遠近，閒雲休礙月升沉。"]'),
('0e35297b-9043-4dd0-bf7d-51dc8d0775d4','題太平興國宮','宋德之','宋','宋诗','song-poetry','','[]','殷勤此別幾時還，結足應須巖洞間。',64,'全唐诗/poet.song.182000.json','["殷勤此別幾時還，結足應須巖洞間。", "卒歲在家貧亦好，何人似我老來閑。", "九天使者邀歸艇，五嶽丈人分半山。", "已是南回行脚了，歸休穩坐聽潺湲。"]'),
('fa4c928c-792f-4b46-8f8b-cda9806509bc','句','宋德之','宋','宋诗','song-poetry','','[]','昔人豪侈徒爲爾，得似章華田舍翁。',16,'全唐诗/poet.song.182000.json','["昔人豪侈徒爲爾，得似章華田舍翁。"]'),
('4bccb59a-692c-431c-889c-614775d88ee9','護國寺','周振','宋','宋诗','song-poetry','','[]','碧雲紅樹萬山秋，躡蹬攀蘿徑轉幽。',64,'全唐诗/poet.song.182000.json','["碧雲紅樹萬山秋，躡蹬攀蘿徑轉幽。", "斜日荒荒巖際下，細泉淺淺寺前流。", "蕭梁賜額名猶在，石塔藏碑字尚留。", "千載廢興真夢幻，青燈夜雨思悠悠。"]'),
('bec8993b-1407-49ef-a0cf-dba2646c103c','出疆','林仲虎','宋','宋诗','song-poetry','','[]','去時不敢留姓名，一身萬里鴻毛輕。',128,'全唐诗/poet.song.182000.json','["去時不敢留姓名，一身萬里鴻毛輕。", "征鞭不返長淮水，正恐來者愁此行。", "吁嗟此行良獨難，出門兒女更辛酸。", "平生崛强身是膽，自許虎口能生還。", "犬羊異種猶人類，惟有肝膽傾相示。", "此語歷歷端不誣，畢竟言之無二意。", "從前鷗鷺奮不飛，機心一動成驚疑。", "願言嘻嗑噉兒齒，直到齒落兒不知。"]'),
('df94fb23-cbd5-42c7-a0d6-06584f058896','龍鼻水泉','宋習之','宋','宋诗','song-poetry','','[]','老龍倦雷霆，奔山化爲石。',24,'全唐诗/poet.song.182000.json','["老龍倦雷霆，奔山化爲石。", "惟有鼻不枯，尚留雲雨迹。"]'),
('c57d61d8-7312-4348-8cbd-ad6c82fe0ecf','求先人墨迹呈表兄黄季文','戴復古','宋','宋诗','song-poetry','','[]','我翁本詩仙，游戲滄海上。',276,'全唐诗/poet.song.182000.json','["我翁本詩仙，游戲滄海上。", "引手掣鯨鯢，失脚墮塵網。", "身窮道則腴，年高氣彌壯。", "平生無長物，飲盡千斛釀。", "傳家古錦囊，自作金玉想。", "篇章久零落，人間眇餘響。", "搜求二十年，痛淚濕黄壤。", "君家圖書府，墨色照青嶂。", "我翁有遺迹，數紙古田樣。", "髣髴鍾王體，吟句更豪放。", "把玩竹林間，寒風凜悽慘。", "昂昂野鶴姿，愧無中散狀。", "兒孤襁褓中，家風隨掃蕩。", "於茲見筆法，可想翁無恙。", "幽居寂寞鄉，風月共來往。", "衆醜成獨妍，群瘖怪孤唱。", "一生既蹉跎，人琴遂俱喪。", "託君名不朽，斯文豈天相。", "舊作忽新傳，識者動慨賞。", "嗟予忝厥嗣，朝夕愧俯仰。", "敢墜顯揚思，幽光發草莽。", "假此見諸公，丐銘松柏壙。", "君其啟惠心，慰彼九泉望。"]'),
('6d120f63-7550-4552-8817-3a53b24891a6','夢中亦役役','戴復古','宋','宋诗','song-poetry','','[]','半夜群動息，五更百夢殘。',72,'全唐诗/poet.song.182000.json','["半夜群動息，五更百夢殘。", "天鷄啼一聲，萬枕不遑安。", "一日一百刻，能得幾刻閒。", "當其閒睡時，作夢更多端。", "窮者夢富貴，達者夢神仙。", "夢中亦役役，人生良鮮歡。"]'),
('7645d413-73e7-48da-8a2f-882d9e3473f2','飲馬長城窟','戴復古','宋','宋诗','song-poetry','','[]','朔風凜高秋，黑霧翳白日。',60,'全唐诗/poet.song.182000.json','["朔風凜高秋，黑霧翳白日。", "漢兵來伐胡，飲馬長城窟。", "古來長城窟，中有戰士骨。", "骨久化爲泉，馬來喫不得。", "聞說華山陽，水甘春草長。"]'),
('3b952a6c-6a40-4ccd-9528-5426a217ba6c','白苧歌','戴復古','宋','宋诗','song-poetry','','[]','雪爲緯，玉爲經。',40,'全唐诗/poet.song.182000.json','["雪爲緯，玉爲經。", "一織三滌手，織成一片冰。", "清如夷齊，可以爲衣。", "陟彼西山，于以采薇。"]'),
('84ef45ae-044e-4639-b425-13185926699b','羅敷詞','戴復古','宋','宋诗','song-poetry','','[]','妾本秦氏女，今春嫁王郎。',114,'全唐诗/poet.song.182000.json','["妾本秦氏女，今春嫁王郎。", "夫家重蠶事，出採陌上桑。", "低枝採易殘，高枝手難扳。", "踏踏竹梯登樹杪，心思蠶多苦葉少。", "舉頭桑枝掛鬢唇，轉身桑枝勾破裙。", "辛苦事蠶桑，實爲良家人。", "使君奚所爲，見妾駐車輪。", "使君口有言，羅敷耳無聞。", "蠶饑蠶饑，采葉急歸。"]'),
('18878f7a-5a86-4822-a20d-c716b893fd93','題陳毅甫家壁','戴復古','宋','宋诗','song-poetry','','[]','朱門金叵羅，九醖葡萄春。',48,'全唐诗/poet.song.182000.json','["朱門金叵羅，九醖葡萄春。", "酌貴不酌賤，酌富不酌貧。", "君家破茅屋，飄摇河水濱。", "中有一樽淥，醉盡天下人。"]'),
('f919efbb-63e2-4675-903d-eacdee4fd8df','答婦詞','戴復古','宋','宋诗','song-poetry','','[]','江山阻且長，矯首鄉關隔。',192,'全唐诗/poet.song.182000.json','["江山阻且長，矯首鄉關隔。", "空閨泣幼婦，顦顇失顔色。", "隠閔鸛鳴篇，寄彼西飛翼。", "剝封覽情素，既喜復凄惻。", "別時梅始花，傷今食梅實。", "覽古帝王州，結交游俠窟。", "千金沽美酒，一飲連十日。", "春風吹酒醒，始知身是客。", "杜宇啼一聲，行人淚橫臆。", "衣破誰與紉，髮垢孰與櫛。", "勿謂遊子心，而不念家室。", "新交握臂行，肝膽猶楚越。", "醜婦隔江山，千里情弗絕。", "慇懃揮報章，歸計何時决。", "今夕知何夕，覩此纖纖月。", "此月再圓時，門前候歸轍。"]'),
('b0e2f95d-d953-4963-b7c5-98acadac4e2b','都中書懷呈滕仁伯祕監','戴復古','宋','宋诗','song-poetry','','[]','北風朝暮寒，園林日蕭條。',120,'全唐诗/poet.song.182000.json','["北風朝暮寒，園林日蕭條。", "自非松柏姿，何葉不飄摇。", "儒衣歷多難，陋巷困簞瓢。", "無地可躬耕，無才仕王朝。", "一饑驅我來，騎馿吟灞橋。", "通名丞相府，數月不見招。", "欲登五侯門，非皓齒細腰。", "索米長安街，滿口讀詩騷。", "時人試靜聽，霜枝囀寒蜩。", "倘可悅人耳，安望如簫韶。"]'),
('2422ebfa-93d4-4288-8c44-86fbcebb1d70','桐廬舟中','戴復古','宋','宋诗','song-poetry','','[]','吳山青未了，桐江綠相迎。',48,'全唐诗/poet.song.182000.json','["吳山青未了，桐江綠相迎。", "扁舟問何之，往訪巖子陵。", "高風凜千古，卧蹴萬乘主。", "富貴直浮雲，羊裘釣烟雨。"]'),
('25adc79f-47ab-4d47-9b32-40d5c03e63d4','湖北上吳勝之運使有感而言非詩也','戴復古','宋','宋诗','song-poetry','','[]','蒼生積釁久，天欲盡殺之。',132,'全唐诗/poet.song.182000.json','["蒼生積釁久，天欲盡殺之。", "干戈殺不盡，繼以大旱饑。", "田野委餓莩，道路紛流離。", "衆人識天意，不敢加扶持。", "公懷佛子性，逆天救民命。", "擅移太倉粟，衆拂生塵甑。", "全活十萬家，九州詠仁政。", "逆天天弗怒，鬼神胡不恕。", "白玉尚指瑕，青蠅工點素。", "秋風動蓴鱸，公亦思歸去。", "問公歸去兮，蒼生誰怙恃。"]'),
('86f834fa-3f1e-4612-8055-2920b1613fd0','所館小樓見山可喜','戴復古','宋','宋诗','song-poetry','','[]','茲樓非我有，久居如主人。',48,'全唐诗/poet.song.182000.json','["茲樓非我有，久居如主人。", "雖無往來客，青山當佳賓。", "君看樓下路，三尺軟紅塵。", "失脚踏此塵，汩沒多終身。"]'),
('ac036981-0212-4ccb-a138-fb501e20bacb','客行河水東','戴復古','宋','宋诗','song-poetry','','[]','客行河水東，客行河水西。',72,'全唐诗/poet.song.182000.json','["客行河水東，客行河水西。", "客行河水南，客行河水北。", "行行無已時，朱顔變老色。", "至人棲一方，庭戶羅八極。", "保心如止水，不受萬物役。", "有道肥其軀，故能適所息。"]'),
('ca955795-0940-4665-8a33-781978ed71ee','和山谷上東坡古風二首見一朝士今取一篇','戴復古','宋','宋诗','song-poetry','','[]','自鬻非奇貨，强鳴非好聲。',84,'全唐诗/poet.song.182000.json','["自鬻非奇貨，强鳴非好聲。", "法當老山林，松根斷茯苓。", "朅來長安道，霜鬢迫衰齡。", "窮吟無知音，祇覺太瘦生。", "公詩妙一世，風雅見根蔕。", "比興千萬篇，已作不朽計。", "窮達雖不同，嗜好迺相似。"]'),
('dfb30777-a9c3-4d69-b523-0ea4a95859b6','題古源棠和尚送青軒','戴復古','宋','宋诗','song-poetry','','[]','南山色射窗，北山光照戶。',108,'全唐诗/poet.song.182000.json','["南山色射窗，北山光照戶。", "道人處其中，冰玉爲肺腑。", "茲山自開闢，荒翳幾年所。", "一朝得主人，荆榛化庭宇。", "手披風月藏，目極烟霞趣。", "居然獲奇觀，人境賀相遇。", "道人詩更高，不作蔬筍語。", "朝對北山吟，暮對南山賦。", "聞說玉堂仙，擊節賞佳句。"]'),
('8cf3f8be-30eb-44cc-a66a-c1e5fbc14a08','大熱五首  其一','戴復古','宋','宋诗','song-poetry','','[]','天地一大窯，陽炭烹六月。',60,'全唐诗/poet.song.182000.json','["天地一大窯，陽炭烹六月。", "萬物此陶鎔，人何怨炎熱。", "君看百穀秋，亦自暑中結。", "田水沸如湯，背汗濕如潑。", "農夫方夏耘，安坐吾敢食。"]'),
('340d2d8e-f97e-40c2-b035-62109a35c520','大熱五首  其二','戴復古','宋','宋诗','song-poetry','','[]','左手遮赤日，右手招清風。',60,'全唐诗/poet.song.182000.json','["左手遮赤日，右手招清風。", "揮汗不能已，扇笠競要功。", "南山龍吐雲，騰騰滿虛空。", "一雨變清凉，萬物隨疏通。", "向人無德色，大哉造化工。"]'),
('a13079a9-788e-4166-bc79-7566deaadb31','大熱五首  其三','戴復古','宋','宋诗','song-poetry','','[]','大渴遇甘井，汲多井欲竭。',60,'全唐诗/poet.song.182000.json','["大渴遇甘井，汲多井欲竭。", "入喉化爲汗，不救胸中熱。", "吾聞三危露，迥與衆水別。", "其色瑩琉璃，其冷勝冰雪。", "安得一杯來，爲我解此渴。"]'),
('3e67d4eb-9b13-448b-8c7d-1214e0c8a9b3','大熱五首  其四','戴復古','宋','宋诗','song-poetry','','[]','吾家老茅屋，破漏尚可住。',60,'全唐诗/poet.song.182000.json','["吾家老茅屋，破漏尚可住。", "門前五巨樟，枝葉龍蛇舞。", "半空隔天日，六月不知暑。", "西照坐東偏，南薰開北戶。", "胡爲捨是居，受此炮炙苦。"]'),
('62f1cd4c-1b87-43bf-9f9b-e259942a469c','大熱五首  其五','戴復古','宋','宋诗','song-poetry','','[]','天嗔吾面白，晒作鐵色深。',60,'全唐诗/poet.song.182000.json','["天嗔吾面白，晒作鐵色深。", "天能黑我面，豈能黑我心。", "我心有冰雪，不受暑氣侵。", "推去北窗枕，思鼓南風琴。", "千古叫虞舜，遺我以好音。"]'),
('06c9bab9-ec31-4885-bfb4-470b7c29b169','久寓泉南待一故人消息桂隠諸葛如晦謂客舍不可住借一園亭安下即事凡有十首  其一','戴復古','宋','宋诗','song-poetry','','[]','寄跡小園中，自笑客異鄉。',60,'全唐诗/poet.song.182000.json','["寄跡小園中，自笑客異鄉。", "東家送檳榔，西家送檳榔。", "咀嚼唇齒赤，亦能醉我腸。", "南人敬愛客，以此當茶湯。", "慇懃謝其來，此意不可忘。"]'),
('95a1767d-c926-47ad-a934-767b77cd1a40','久寓泉南待一故人消息桂隠諸葛如晦謂客舍不可住借一園亭安下即事凡有十首  其二','戴復古','宋','宋诗','song-poetry','','[]','寄跡小園中，豈不勝旅舍。',60,'全唐诗/poet.song.182000.json','["寄跡小園中，豈不勝旅舍。", "俗事無交加，客身自閑暇。", "鄰家有酒沽，杯盤亦可借。", "吟侶適相過，新詩堪膾炙。", "足以慰我懷，留連日至夜。"]'),
('e5ab5e3d-0276-4902-85ad-45889e471296','久寓泉南待一故人消息桂隠諸葛如晦謂客舍不可住借一園亭安下即事凡有十首  其三','戴復古','宋','宋诗','song-poetry','','[]','寄跡小園中，數椽亦瀟灑。',60,'全唐诗/poet.song.182000.json','["寄跡小園中，數椽亦瀟灑。", "主人既相知，此地可久假。", "縣官送月糧，鄰翁供菜把。", "咫尺是屠門，亦有賣鮮者。", "里巷通往來，欲結雞豚社。"]'),
('9565cf6e-bebb-497b-be6c-a55506140ea6','久寓泉南待一故人消息桂隠諸葛如晦謂客舍不可住借一園亭安下即事凡有十首  其四','戴復古','宋','宋诗','song-poetry','','[]','寄跡小園中，餘春接初夏。',60,'全唐诗/poet.song.182000.json','["寄跡小園中，餘春接初夏。", "問木木成陰，問花花已謝。", "黄鸝出幽谷，杜鵑叫長夜。", "把酒酌園婆，遠客此稅駕。", "有時吟聲高，鬼神莫驚怕。"]'),
('51df0e2d-1efb-4ccd-8e68-91fb6089b260','久寓泉南待一故人消息桂隠諸葛如晦謂客舍不可住借一園亭安下即事凡有十首  其五','戴復古','宋','宋诗','song-poetry','','[]','寄跡小園中，一心安淡薄。',60,'全唐诗/poet.song.182000.json','["寄跡小園中，一心安淡薄。", "每坐竹間亭，不知近城郭。", "昨日看花開，今日見花落。", "靜中觀物化，妙處在一覺。", "委身以順命，無憂亦無樂。"]'),
('e1b9cad4-c0d7-41e0-b567-3cab5e712548','久寓泉南待一故人消息桂隠諸葛如晦謂客舍不可住借一園亭安下即事凡有十首  其六','戴復古','宋','宋诗','song-poetry','','[]','寄跡小園中，第一薪水便。',60,'全唐诗/poet.song.182000.json','["寄跡小園中，第一薪水便。", "逐一炊黄粱，兼得魚蝦賤。", "飽飯日無營，遮眼有書卷。", "時逢好客來，應接不知倦。", "最苦風雨時，有人招夜宴。"]'),
('cb30ecf8-4068-4452-8fc1-395941a01e2d','久寓泉南待一故人消息桂隠諸葛如晦謂客舍不可住借一園亭安下即事凡有十首  其七','戴復古','宋','宋诗','song-poetry','','[]','寄跡小園中，新晴風日麗。',60,'全唐诗/poet.song.182000.json','["寄跡小園中，新晴風日麗。", "好鳥竹間鳴，野鶴空中唳。", "悠然動詩興，行吟撫松桂。", "久客若忘歸，此身笑匏繫。", "五月倘未行，尚及食丹荔。"]'),
('e3ac8f20-ca10-4482-be0e-295d5e597c68','久寓泉南待一故人消息桂隠諸葛如晦謂客舍不可住借一園亭安下即事凡有十首  其八','戴復古','宋','宋诗','song-poetry','','[]','寄跡小園中，頗欲閟形影。',60,'全唐诗/poet.song.182000.json','["寄跡小園中，頗欲閟形影。", "誰爲饒舌者，太守忽相請。", "開心論時務，細語及詩境。", "坐中有蠻客，狂言事馳騁。", "明日酒醒來，熟思令人癭。"]'),
('5b8afc0e-3e36-4575-9a2d-ea18d03bc35f','久寓泉南待一故人消息桂隠諸葛如晦謂客舍不可住借一園亭安下即事凡有十首  其九','戴復古','宋','宋诗','song-poetry','','[]','寄跡小園中，忽有烏衣至。',60,'全唐诗/poet.song.182000.json','["寄跡小園中，忽有烏衣至。", "手中執圓封，州府特遣饋。", "羅列滿吾前，禮數頗周緻。", "四隣來聚觀，若有流涎意。", "呼童急開樽，四隣同一醉。"]'),
('0239cc3a-6c18-400f-9de3-750442590070','久寓泉南待一故人消息桂隠諸葛如晦謂客舍不可住借一園亭安下即事凡有十首  其一○','戴復古','宋','宋诗','song-poetry','','[]','寄跡小園中，倒指五十日。',60,'全唐诗/poet.song.182000.json','["寄跡小園中，倒指五十日。", "既得故人書，南游吾事畢。", "再拜謝主翁，奉還此一室。", "雲萍聚復散，欲住住不得。", "折柳當馬鞭，明朝有行色。"]'),
('10b38a4b-43b4-46a4-b8da-142034e1d87b','題鄭寧夫玉軒詩卷','戴復古','宋','宋诗','song-poetry','','[]','良玉假雕琢，好詩費吟哦。',96,'全唐诗/poet.song.182000.json','["良玉假雕琢，好詩費吟哦。", "詩句果如玉，沈謝不足多。", "玉聲貴清越，玉色愛純粹。", "作詩亦如之，要在工夫至。", "辨玉先辨石，論詩先論格。", "詩家體固多，文章有正脈。", "細觀玉軒吟，一生良苦心。", "雕琢復雕琢，片玉萬黄金。"]'),
('87e5d0d4-2cbf-4eb1-a8b6-d2b7edc8e009','滸以秋蘭一盆爲供','戴復古','宋','宋诗','song-poetry','','[]','吾兒來侍側，供我一秋蘭。',84,'全唐诗/poet.song.182000.json','["吾兒來侍側，供我一秋蘭。", "蕭然出塵姿，能禁風露寒。", "移根自巖壑，歸我几案間。", "養之以水石，副之以小山。", "儼如對益友，朝夕共盤桓。", "清香可呼吸，薰我老肺肝。", "不過十數根，當作九畹看。"]'),
('e9e20cfe-09c4-4bdf-987b-34116c48497f','和高常簿暮春','戴復古','宋','宋诗','song-poetry','','[]','世變日以薄，無從見雍熙。',108,'全唐诗/poet.song.182000.json','["世變日以薄，無從見雍熙。", "閉門讀古書，聊以道自怡。", "桃李春盎盎，風雨秋凄凄。", "於春何足喜，於秋何用悲。", "人生一世間，所忌立志卑。", "終身有不遇，千載皆明時。", "我生無所解，肥遯滄海沂。", "一朝遇名勝，朽腐生光輝。", "歛衽贊明德，非公誰與歸。"]'),
('900b7308-3b76-477c-90fe-b00eac199474','和鄭潤甫提舉見寄  其一','戴復古','宋','宋诗','song-poetry','','[]','出門欲求仁，取友必勝己。',48,'全唐诗/poet.song.182000.json','["出門欲求仁，取友必勝己。", "寥寥雲海鄉，所幸有君爾。", "胸蟠三萬卷，智先三十里。", "相與定詩盟，誰能執牛耳。"]'),
('d664a019-ccab-4491-bc06-d0de6e9aed63','和鄭潤甫提舉見寄  其二','戴復古','宋','宋诗','song-poetry','','[]','長身如病鶴，吟苦如蟋蟀。',48,'全唐诗/poet.song.182000.json','["長身如病鶴，吟苦如蟋蟀。", "顧此顦顇姿，癡生年八秩。", "舉世皆好竽，老夫方鼓瑟。", "梅花莫笑人，茅簷炙朝日。"]'),
('d66a780c-7607-4533-ab62-8725c322f2d8','送吳伯成歸建昌二首  其一','戴復古','宋','宋诗','song-poetry','','[]','老夫脚病瘡，閉門作僧夏。',72,'全唐诗/poet.song.182000.json','["老夫脚病瘡，閉門作僧夏。", "麥麵不療饑，冬衣猶未卸。", "喜讀吳融詩，窮愁退三舍。", "無因暗投璧，有味倒餐蔗。", "冥搜琢肺肝，苦吟忘晝夜。", "工夫到深處，非王亦非霸。"]'),
('d3713e91-08d7-47e4-89af-0ecb146dbe8b','送吳伯成歸建昌二首  其二','戴復古','宋','宋诗','song-poetry','','[]','吾友嚴華谷，實爲君里人。',72,'全唐诗/poet.song.182000.json','["吾友嚴華谷，實爲君里人。", "多年入詩社，錦囊貯清新。", "昨者袁蒙齋，招爲入幙賓。", "千里有遇合，隔牆不見親。", "君歸訪其家，說我老病身。", "別有千萬意，付之六六鱗。"]'),
('1029d7bc-b0e0-478f-84ee-9c5c7c8de20b','謝東倅包宏父三首癸卯夏  其一','戴復古','宋','宋诗','song-poetry','','[]','詩文雖兩途，理義歸乎一。',72,'全唐诗/poet.song.182000.json','["詩文雖兩途，理義歸乎一。", "風騷凡幾變，晚唐諸子出。", "本朝師古學，六經爲世用。", "諸公相羽翼，文章還正統。", "晦翁講道餘，高吟復超絕。", "巽巖許其詩，鳳凰飛處別。"]'),
('1bfd0bc1-4e06-4399-b57b-a9caf58f93b8','謝東倅包宏父三首癸卯夏  其二','戴復古','宋','宋诗','song-poetry','','[]','君家名父子，爲晦翁嫡傳。',72,'全唐诗/poet.song.182000.json','["君家名父子，爲晦翁嫡傳。", "嘗見黄勉齋，極口稱其賢。", "師友相琢磨，南軒惜無年。", "翁之爲汝翁，文字相周旋。", "溟渤深見底，泰華高及天。", "宏齋有鳳髓，可續欲斷弦。"]'),
('2d85d791-58d9-4e26-b9f9-4f4a2a6c495d','謝東倅包宏父三首癸卯夏  其三','戴復古','宋','宋诗','song-poetry','','[]','平生不識字，把筆學吟詩。',72,'全唐诗/poet.song.182000.json','["平生不識字，把筆學吟詩。", "舊說韋蘇州，於余今見之。", "每遭饑寒厄，出吐辛酸辭。", "候蟲鳴屋壁，風蟬囀枯枝。", "但有可憐聲，入耳終無奇。", "宏齋誤題品，恐貽識者譏。"]'),
('7aece505-a18b-46d9-b84b-5d54a4bbc5be','題姚雪蓬使君所藏蘇野塘畫','戴復古','宋','宋诗','song-poetry','','[]','高者爲山，坳者爲壑。',92,'全唐诗/poet.song.182000.json','["高者爲山，坳者爲壑。", "爲烟爲雲，渺渺漠漠。", "水鳥樹林，人家聚落。", "騎者何之，舟者未泊。", "三尺紙上，萬象交錯。", "天機自然，神驚鬼愕。", "嗚呼，此吾故人野塘蘇元龍之墨迹。", "中有石屏老淚痕，又與野塘添一筆。"]'),
('01c9739f-239e-486a-bb41-b1f43dd943a7','烏鹽角行','戴復古','宋','宋诗','song-poetry','','[]','鳳簫鼉鼓龍鬚笛，夜宴華堂醉春色。',160,'全唐诗/poet.song.182000.json','["鳳簫鼉鼓龍鬚笛，夜宴華堂醉春色。", "艷歌妙舞蕩人心，但有歡娛別無益。", "何如村落捲桐吹，能使時人知稼穡。", "村南村北聲相續，青郊雨後耕黄犢。", "一聲催得大麥黄，一聲喚得新秧綠。", "人言此角只兒戲，孰識古人吹角意。", "田家作勞多怨咨，故假聲音召和氣。", "吹此角，起東作。", "吹此角，田家樂。", "此角上與鄒子之律同宮商，合鍾呂。", "形甚朴，聲甚古，一吹寒谷生禾黍。"]'),
('452a3622-cc8d-4b0a-a78e-c76f6c9633ca','靈壁石歌爲方巖王侍郎作','戴復古','宋','宋诗','song-poetry','','["\u592a\u6e56"]','靈壁一峰天下奇，體勢雄偉身巍巍，巨靈怒拗天柱擲。',250,'全唐诗/poet.song.182000.json','["靈壁一峰天下奇，體勢雄偉身巍巍，巨靈怒拗天柱擲。", "平地蒼龍驤首尾，兩片黑雲腰夾之。", "聲如青銅色碧玉，秀潤四時嵐翠濕。", "乾坤所寶落世間，鬼神上訴天公泣。", "謂有非常人，致此非常物。", "可磨斫賊劍，可倚擊姦笏。", "可祝不老年，可比至剛德。", "自從突兀在眼前，溪山日夜生顔色。", "君不見杭州風流白使君，雅愛天竺雙雲根。", "又不見奇章公家太湖碧，高下品題分甲乙。", "二公名與石不磨，今到方巖有靈壁。", "我來欲作靈壁歌，擊石一唱三摩挲。", "秋風蕭蕭淮水波，中分南北橫干戈。", "胡塵埋沒漢山河，泗濱靈壁今如何。", "安得此石來巖阿，鬰然盤礴中原氣，對此令人感慨多。"]'),
('b9ce4007-ed05-4a36-ad97-b09f36e9bf9f','章泉二老歌','戴復古','宋','宋诗','song-poetry','','[]','在昔商山傳四皓，又聞香山圖九老。',262,'全唐诗/poet.song.182000.json','["在昔商山傳四皓，又聞香山圖九老。", "異鄉異姓適同時，爭如章泉一家兄弟登耆頤。", "章泉之上兩山下，有地可宮田可稼。", "伯也早休官，季也相約歸林泉。", "名動京口耕谷口，山中有詩天下傳。", "一生得閑兼得壽，皓首龐眉世稀有。", "竹隠先生八十三，定庵居士七十九。", "客從遠方來，亦是六十叟。", "手把一枝梅，奉勸兩翁酒。", "問公何以致遐齡，請翁細說吾細聽。", "不燒丹，不學仙。", "五行有常數，天所稟賦焉。", "人生一氣統四體，衆人斲喪吾能全。", "要知養生無他術，日多喫飯夜獨眠。", "承翁見教謝翁去，兩翁慇懃留我住，是夜醉眠苔竹軒。", "夢見山靈向我言，翁之所說皆不然。", "兩翁盛德合乎天，天與遐齡五百年。"]'),
('570cf04d-b410-40de-bf58-93d094f98aa5','京口喜雨樓落成呈史固叔侍郎','戴復古','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','京口畫樓三百所，第一新樓名喜雨。',160,'全唐诗/poet.song.182000.json','["京口畫樓三百所，第一新樓名喜雨。", "大鵬展翼到中天，化作簷楹不飛去。", "一日登臨天下奇，華燈照夜萬琉璃。", "上與星辰共羅列，下映十里蓮花池。", "泰山爲麴海爲釀，手挈五湖爲甕盎。", "銀糟香沸碧瑶春，歌舞當壚多麗人。", "使君歌了人皆飲，更賞谷中花似錦。", "五兵不用用酒兵，折衝樽俎邊塵寢。", "茲樓屹作東南美，孰識黄堂命名意。", "特將此酒噀爲霖，四海九州同一醉。"]'),
('f59d5ecb-e0e8-48fe-bf51-383bc27e068b','觀陸士龍作顧彥先婦答夫二首有感韵  其一','戴復古','宋','宋诗','song-poetry','','[]','北風吹歲暮，空閨獨棲止。',72,'全唐诗/poet.song.182000.json','["北風吹歲暮，空閨獨棲止。", "夙興淚盈掬，夕息夢千里。", "妾生胡不仁，失身從浪子。", "嚼蘗苦我心，餐冰噤我齒。", "離異何足愁，險澀可勝紀。", "寄書西飛鴈，反覆話終始。"]'),
('51897951-9df7-4f6c-9566-6512cba1c4e5','觀陸士龍作顧彥先婦答夫二首有感韵  其二','戴復古','宋','宋诗','song-poetry','','[]','鼠璞竊美名，冠玉假外觀。',120,'全唐诗/poet.song.182000.json','["鼠璞竊美名，冠玉假外觀。", "良人誇意氣，下妾愁歲晏。", "念君始行邁，雪嶺梅初粲。", "春風桃已紅，光陰等飛彈。", "相思果如何，金環寬玉腕。", "昔爲連理枝，今作摶沙散。", "惜哉牛與女，脉脉阻河漢。", "特棲良獨難，守堅祇自讚。", "雙劍幾時合，寄聲問華煥。", "勿聽五羊歌，富貴忘貧賤。"]'),
('41e1bda4-6fc0-46f7-afe8-56f08ff05737','栗齋鞏仲至以元結文集爲韵','戴復古','宋','宋诗','song-poetry','','[]','尋常被酒時，歸到急投枕。',108,'全唐诗/poet.song.182000.json','["尋常被酒時，歸到急投枕。", "爲愛次山文，今夜醉忘寢。", "偉哉浯溪碑，千載氣凜凜。", "舂陵賊退篇，少陵猶歛衽。", "文章自一家，其意則古甚。", "大羹遺五味，純素薄文錦。", "聱牙不同俗，斯人異所稟。", "君君望堯舜，人人欲倉廩。", "古道不可行，時對窊樽飲。"]'),
('673bcb12-1389-4e3c-a8f1-0b8874761ca3','杜甫祠','戴復古','宋','宋诗','song-poetry','','[]','嗚呼杜少陵，醉卧春江漲。',152,'全唐诗/poet.song.182000.json','["嗚呼杜少陵，醉卧春江漲。", "文章萬丈光，不隨枯骨葬。", "平生稷契心，致君堯舜上。", "時兮弗我與，屹然抱微尚。", "干戈奔走蹤，道路饑寒狀。", "草中辨君臣，筆端誅將相。", "高吟比興體，力救風雅喪。", "如史數十篇，才氣一何壯。", "到今五百年，知公尚無恙。", "麒麟守高阡，貂蟬入畫像。", "一死不幾時，聲迹兩塵莽。", "何如耒陽江頭三尺荒草墳，名如日月光天壤。"]'),
('f3cfe399-f206-4717-a7c2-dc813dbd67eb','阿奇晬日','戴復古','宋','宋诗','song-poetry','','[]','窮居少生涯，養子如種穀。',192,'全唐诗/poet.song.182000.json','["窮居少生涯，養子如種穀。", "寸苗方在手，想像秋禾熟。", "吾兒天所惠，骨相頗豐碩。", "娟娟懷抱中，一歲至週日。", "願汝無災害，長大庶可必。", "十歲聰明開，二十蚤奮發。", "胸蟠三萬卷，手握五色筆。", "策勳文字場，致君以儒術。", "不然學孫吳，縱橫萬人敵。", "爲國取中原，闢地玄冥北。", "他年汝成就，料我頭已白。", "光華照老眼，甘旨不可缺。", "爲子必純孝，爲人必正直。", "以我期望心，一日必一祝。", "勿爲癡小兒，茫然無所識。", "胎教尚有聞，斯言豈無益。"]'),
('bc78bc88-d395-4372-b644-0bd84162d60f','琵琶行','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','潯陽江頭秋月明，黄蘆葉底秋風聲。',120,'全唐诗/poet.song.182000.json','["潯陽江頭秋月明，黄蘆葉底秋風聲。", "銀龍行酒送歸客，丈夫不爲兒女情。", "隔船琵琶自愁思，何預江州司馬事。", "爲渠感激作歌行，一寫六百六十字。", "白樂天，白樂天，平生多爲達者語，到此胡爲不釋然。", "弗堪謫宦便歸去，廬山政接柴桑路。", "不尋黄菊伴淵明，忍泣青衫對商婦。"]'),
('83ec73e9-adcf-450b-b8a4-46d79443d4f3','毗陵太平寺畫水呈王君保使君','戴復古','宋','宋诗','song-poetry','','[]','何人筆端有許力，捲來一片瀟湘碧。',80,'全唐诗/poet.song.182000.json','["何人筆端有許力，捲來一片瀟湘碧。", "摩挲老眼看不真，怪見層波湧虛壁。", "天慶觀中雙黑龍，物色雖殊妙處同。", "能將此水畜彼龍，方知畫手有神通。", "龍兮水兮終會遇，天下蒼生待霖雨。"]'),
('476845f3-b7e0-4a8b-949f-4304ba6accfa','南嶽','戴復古','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南雲漂渺連蒼穹，七十二峰朝祝融。',80,'全唐诗/poet.song.182000.json','["南雲漂渺連蒼穹，七十二峰朝祝融。", "凌空棟宇赤帝宅，脩廊翼翼生寒風。", "朝家遣使嚴祀典，御香當殿開宸封。", "願四海，扶九重，干戈永息年屢豐。", "五嶽惟今見南嶽，北望乾坤雙淚落。"]'),
('10b1dff1-6e04-4cfa-bf2b-c96a7a5f68df','送來賓宰','戴復古','宋','宋诗','song-poetry','','[]','君作來賓宰，聽我說來賓。',144,'全唐诗/poet.song.182000.json','["君作來賓宰，聽我說來賓。", "蠻俗無王化，當爲行化人。", "有民無租賦，租賦出商旅。", "逐利遭重徵，商旅亦良苦。", "能放一分寬，可減十分怨。", "不愛資囊橐，但愛了支遣。", "民窮頼撫摩，官貧俸不多。", "但得百姓安，俸薄其柰何。", "勿謂朝廷遠，官職易遷轉。", "律己貴廉勤，御事要明斷。", "自縣辟爲州，指日爲太守。", "須知早歸來，瘴鄉不可久。"]'),
('e39da5cb-0c49-49de-8069-2e0414a2b458','題四祖山榮老月窟','戴復古','宋','宋诗','song-poetry','','[]','一室虛生白，中作滿月形。',120,'全唐诗/poet.song.182000.json','["一室虛生白，中作滿月形。", "山中三萬戶，玉斧新修成。", "時人指爲月，雲卧亦强名。", "似月有圓相，不西沉東升。", "浮雲不能蔽，又無虧與盈。", "是爲大圓鏡，由師心地明。", "一圓走無礙，光芒照八紘。", "可以破諸暗，可以續祖燈。", "明透雙峰頂，輝映慧雲亭。", "此鏡實無臺，請師問老能。"]'),
('dae00c46-1bee-4c07-944e-6398e347a43c','出閩','戴復古','宋','宋诗','song-poetry','','[]','千山萬山閩中路，六尺枯藤兩芒屨。',64,'全唐诗/poet.song.182000.json','["千山萬山閩中路，六尺枯藤兩芒屨。", "去歲梅花迎我來，今歲梅花送我去。", "梅花豈解管送迎，白髮胡爲又南征。", "天荒地老終無情，歸去歸兮老石屏。"]'),
('e6570bcd-3a3b-4d42-8365-eeaef44e6a88','劉折父爲吳子才索賦雲山燕居','戴復古','宋','宋诗','song-poetry','','[]','燕居適所息，非懷傲世心。',96,'全唐诗/poet.song.182000.json','["燕居適所息，非懷傲世心。", "白雲自舒卷，青山無古今。", "中有動靜機，杳眇諧素襟。", "以時爲出處，懷人撫瑶琴。", "平生披短褐，時來或華簪。", "世論倘不合，矢口不如瘖。", "避影長松下，洗耳清溪潯。", "慎勿出雲外，黄塵三尺深。"]'),
('0ce69b96-227a-4861-a9a0-a087533711cf','玉華洞','戴復古','宋','宋诗','song-poetry','','[]','憶昨游桂林，巖洞甲天下。',108,'全唐诗/poet.song.182000.json','["憶昨游桂林，巖洞甲天下。", "奇奇怪怪生，妙不可模寫。", "玉華東西巖，具體而微者。", "神功巧穿鑿，石壁生孔罅。", "玲瓏透風月，宜冬復宜夏。", "中有補陀僊，坐斷此瀟洒。", "空山茅葦區，無地可稅駕。", "舉目忽此逢，心駭見希詫。", "題詩媿不能，行人亦無暇。"]'),
('f85e9e0a-cb18-4267-8c11-e1778e382aa7','祝二嚴','戴復古','宋','宋诗','song-poetry','','[]','僕本山野人，漁樵共居處。',204,'全唐诗/poet.song.182000.json','["僕本山野人，漁樵共居處。", "小年學父詩，用心亦良苦。", "搜索空虛腹，綴緝艱辛語。", "糊口走四方，白頭無伴侶。", "前年得嚴粲，今年得嚴羽。", "我自得二嚴，牛鐸諧鍾呂。", "粲也苦吟身，束之以簪組。", "遍參百家體，終乃師杜甫。", "羽也天姿高，不肯事科舉。", "風雅與騷些，歷歷在肺腑。", "持論傷太高，與世或齟齬。", "長歌激古風，自立一門戶。", "二嚴我所敬，二嚴亦我與。", "我老歸故山，殘年能幾許。", "平生五百篇，無人爲之主。", "零落天地間，未必是塵土。", "再拜祝二嚴，爲我收拾取。"]'),
('02fbd296-5aef-4626-a818-73e679941b21','市舶提舉管仲登飲于萬貢堂有詩','戴復古','宋','宋诗','song-poetry','','[]','七十老翁頭雪白，落在江湖賣詩冊。',64,'全唐诗/poet.song.182000.json','["七十老翁頭雪白，落在江湖賣詩冊。", "平生知己管夷吾，得爲萬貢堂前客。", "嘲吟有罪遭天厄，謀歸未辦資身策。", "雞林莫有買詩人，明日煩公問蕃舶。"]'),
('1a3df019-aeba-4e39-af6c-9e2ab3ebc7e5','懶不作書急口令寄朝士','戴復古','宋','宋诗','song-poetry','','[]','老病懶作書，行藏詩上見。',132,'全唐诗/poet.song.182000.json','["老病懶作書，行藏詩上見。", "一心不相忘，千里如對面。", "我已八十翁，此身寧久絆。", "諸君才傑出，玉石自有辯。", "隨才供任使，小大皆衆選。", "明君用良弼，治道方一變。", "與之致太平，朝廷還舊觀。", "老夫眼尚明，細把諸君看。", "試將草草書，用寫區區願。", "一願善調燮，二願强加飯。", "三願保太平，官職日九轉。"]'),
('c8e46a78-224e-4c32-9494-b46bd6248094','鳳鳴有吉凶','戴復古','宋','宋诗','song-poetry','','[]','鵲噪令人喜，鴉噪令人憎。',60,'全唐诗/poet.song.182000.json','["鵲噪令人喜，鴉噪令人憎。", "人心自分別，吉凶屬禽聲。", "舜時有鳳鳴，文王時亦鳴。", "漢時鳳亦鳴，六朝時亦鳴。", "鳳鳴有吉凶，人不子細聽。"]'),
('a65fbcc8-7098-424c-8549-a12e70aef882','婕妤詞','戴復古','宋','宋诗','song-poetry','','[]','紈扇六月時，似妾君恩重。',84,'全唐诗/poet.song.182000.json','["紈扇六月時，似妾君恩重。", "避暑南薰殿，清風隨扇動。", "妾時侍君王，常得沾餘凉。", "秋風颯庭樹，團團無用處。", "妾亦寵顧衰，栖栖度朝暮。", "扇爲無情物，用捨不知恤。", "妾有深宮怨，無情不如扇。"]'),
('90c6b620-64e3-4008-bae5-444ab4d5aab0','江南新體','戴復古','宋','宋诗','song-poetry','','[]','郎船江下泊，妾家樓上住。',36,'全唐诗/poet.song.182000.json','["郎船江下泊，妾家樓上住。", "朝朝暮暮間，上下兩相顧。", "相顧不相親，風波愁殺人。"]'),
('fd1d2e95-e909-4fc5-b329-536596f4fb99','感寓四首  其一','戴復古','宋','宋诗','song-poetry','','[]','采薇人固高，飲露蟬遂清。',72,'全唐诗/poet.song.182000.json','["采薇人固高，飲露蟬遂清。", "謀茲一粒粟，舉世共營營。", "營營亦多塗，中有虧與盈。", "陋巷一簞食，朱門九鼎烹。", "窮達各有命，繄誰主權衡。", "吾生未可必，秋風白髮生。"]'),
('ca8252dc-9202-4740-bd87-22f7690a8208','感寓四首  其二','戴復古','宋','宋诗','song-poetry','','[]','蛛網羃虛簷，一飽羅群飛。',72,'全唐诗/poet.song.182000.json','["蛛網羃虛簷，一飽羅群飛。", "寒蠶齧枯桑，一身終繭絲。", "物物巧生理，我生拙奚爲。", "貂裘日以弊，石田歲長饑。", "一貧已到骨，一氣儻未衰。", "舉目送飛鴻，悠悠知我誰。"]'),
('789dcace-35cf-46cb-970e-1d4422586dc7','感寓四首  其三','戴復古','宋','宋诗','song-poetry','','[]','夜雨挾西風，摵摵撼庭樹。',72,'全唐诗/poet.song.182000.json','["夜雨挾西風，摵摵撼庭樹。", "浮生堪幾秋，青鬢忽已素。", "鉛刀刲九牛，策蹇望長路。", "所操莽無奇，自好徒自誤。", "改絃調新聲，履道易故步。", "收功在桑榆，其敢怨遲莫。"]'),
('104e9507-95dd-48bd-9944-d08a819dbe34','感寓四首  其四','戴復古','宋','宋诗','song-poetry','','[]','紅紫委路塵，綠樹有嘉色。',72,'全唐诗/poet.song.182000.json','["紅紫委路塵，綠樹有嘉色。", "刳心晚聞道，玩物若有得。", "青春坐銷歇，方茲見真實。", "人生到中年，胡不保明德。", "秋風墮庭梧，棲鳳去無迹。", "矯首碧雲端，一語三歎息。"]'),
('2035eb6c-737a-47d3-a8c5-b031c82185a9','寄章泉先生趙昌父','戴復古','宋','宋诗','song-poetry','','[]','靈鳳鳴朝陽，神龍不泥蟠。',120,'全唐诗/poet.song.182000.json','["靈鳳鳴朝陽，神龍不泥蟠。", "時兮不可爲，昌父乃在山。", "思君二十年，見君良獨難。", "時於邸報上，屢見得祠官。", "祠官祿不多，一貧其柰何。", "采芝亦可食，當作采芝歌。", "近者李侍郎，直言遭逐去。", "人皆笑其疎，君獨有詩句。", "君爲山中人，世事安得聞。", "入山恐未深，更入幾重雲。"]'),
('3b339dc2-17c2-4824-ad0a-55378f593d56','頻酌淮河水','戴復古','宋','宋诗','song-poetry','','[]','有客游濠梁，頻酌淮河水。',48,'全唐诗/poet.song.182000.json','["有客游濠梁，頻酌淮河水。", "東南水多鹹，不如此水美。", "春風吹綠波，鬰鬰中原氣。", "莫向北岸汲，中有英雄淚。"]'),
('5102c4d0-1c09-4f2d-86a3-f6604530de9f','元宵雨','戴復古','宋','宋诗','song-poetry','','[]','窮人不謀歡，元夜如常時。',72,'全唐诗/poet.song.182000.json','["窮人不謀歡，元夜如常時。", "晴雨均寂寞，蚤與一睡期。", "朱門粲燈火，歌舞臨酒池。", "酒闌歡不足，九街恣游嬉。", "前呵驚市人，簫鼓逐後隨。", "片雲頭上黑，翻得失意歸。"]'),
('28772f6d-5fd5-4784-bad4-286fe50a5ba2','小孤山阻風因成小詩適舟中有浦城人寫寄真西山','戴復古','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','群山勢如奔，欲渡長江去。',48,'全唐诗/poet.song.182000.json','["群山勢如奔，欲渡長江去。", "孤峰拔地起，毅然能遏住。", "屹立大江干，仍能障狂瀾。", "人不知此山，有功天地間。"]'),
('81ecaf84-b0ba-4b13-8b14-9d053646c27f','松江舟中四首荷葉浦時有不測末句故及之  其一','戴復古','宋','宋诗','song-poetry','','[]','夜聽楓橋鐘，曉汲松江水。',36,'全唐诗/poet.song.182000.json','["夜聽楓橋鐘，曉汲松江水。", "客行信匆匆，少住亦可喜。", "且食鱖魚肥，莫問鱸魚美。"]'),
('9866bf16-3161-4d9e-99c7-9142bbff0643','松江舟中四首荷葉浦時有不測末句故及之  其二','戴復古','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u5cb3\u9633\u697c"]','垂虹五百步，太湖三萬頃。',36,'全唐诗/poet.song.182000.json','["垂虹五百步，太湖三萬頃。", "除却岳陽樓，天下無此景。", "范蠡挾西施，功名付煙艇。"]'),
('c0686b38-6274-45c6-8ae8-15de105b975b','松江舟中四首荷葉浦時有不測末句故及之  其三','戴復古','宋','宋诗','song-poetry','','[]','秋風吹客衣，歸興浩難寫。',36,'全唐诗/poet.song.182000.json','["秋風吹客衣，歸興浩難寫。", "寒林噪晚鴉，紅日墮平野。", "篙師解人意，檥棹酒旗下。"]'),
('a9e2bd64-d11f-4f65-a8b2-7d01b8cbb5ea','松江舟中四首荷葉浦時有不測末句故及之  其四','戴復古','宋','宋诗','song-poetry','','[]','扁舟乃官差，舟子吾語汝。',36,'全唐诗/poet.song.182000.json','["扁舟乃官差，舟子吾語汝。", "汝爲我作勞，吾亦不汝負。", "好向上塘行，莫過荷葉浦。"]'),
('eb51cbc8-e492-4d19-9a93-fe23b5c5ee6e','趙尊道郎中出示唐畫四老飲圖滕賢良有詩亦使野人著句','戴復古','宋','宋诗','song-poetry','','[]','采芝商山秦四皓，象戲橘中爲四老。',242,'全唐诗/poet.song.182000.json','["采芝商山秦四皓，象戲橘中爲四老。", "我疑此畫即其人，有時以酒陶天真。", "丹青不知誰好手，作此飲態妙入神。", "摩挲半世江湖眼，古錦軸中舒復卷。", "細將物色辨人物，迺是晉時劉畢與陶阮。", "一琴無絃橫膝上，一琴團團明月樣。", "一人持杓坐甕邊，一人手携文一編，是中必寫酒德篇。", "諸君傷時强自遣，麴生風味况不淺。", "五胡妖氣蔽神州，誓江不救中原亂。", "新亭舉目愁山河，萬事何如一樽滿。", "一杯一杯醉復醉，天地陶陶盡和氣。", "道術相忘禮法疎，形骸懶散無機事。", "此畫流傳知幾載，生綃剝落精神在。", "何人爲我更作杜陵飲中八仙歌，將與冰壺主人爲此對。"]'),
('89b8f121-7a82-4d5e-bb6a-72b35f73f249','伏龍山民宋正甫湖山清隠迺唐詩人陳陶故圃曾景建作記俾僕賦詩','戴復古','宋','宋诗','song-poetry','','[]','故人昔住金華峰，面带雙溪秋水容。',216,'全唐诗/poet.song.182000.json','["故人昔住金華峰，面带雙溪秋水容。", "故人今住伏龍山，陳陶故圃茅三間。", "千載清風徐孺子，門前共此一湖水。", "百花洲上萬垂楊，白鷗群裏歌滄浪。", "故人心事孺子高，故人詩句今陳陶。", "短衣飯牛不逢堯，何如繡鞍上著錦宮袍。", "瓦盆對客酌松醪，何如紫霞觴泛碧葡萄。", "豆萁然火度寒宵，何如玉堂夜照金蓮膏。", "吟成禿筆寫芭蕉，何如沉香亭北醉揮毫。", "再三問君君不對，目送飛鴻楚天外。", "細讀山中招隠篇，超然意與烟霞會。", "照影湖邊雙鬢皓，此計知之悔不早。", "三椽可辦願卜隣，荷鍤相隨種瑶草。"]'),
('651f1b8f-f9ef-4fff-8d14-d2b52b957e65','會稽山中','戴復古','宋','宋诗','song-poetry','','[]','曉風吹斷花稍雨，青山白雲無唾處。',64,'全唐诗/poet.song.182000.json','["曉風吹斷花稍雨，青山白雲無唾處。", "嵐光滴翠濕人衣，踏碎瓊瑶溪上步。", "人家遠近屋參差，半成圖畫半成詩。", "若使山中無杜宇，登山臨水定忘歸。"]'),
('73f8c6fb-6959-43a3-a223-8ea41f54106e','高九萬見示落星長句賦此答之','戴復古','宋','宋诗','song-poetry','','[]','天星墮地化爲石，老佛占作青蓮宮。',154,'全唐诗/poet.song.182000.json','["天星墮地化爲石，老佛占作青蓮宮。", "東來海若獻秋水，瓊以碧波千萬重。", "雲根直下數百丈，時吐光燄驚魚龍。", "鳳凰群飛擁其後，對面廬阜之諸峰。", "陰晴風雨多態度，日日舉目看不同。", "高髯能詩復能畫，自說此景難形容。", "且好收拾藏胸中，養成筆力可扛鼎，然後一發妙奪造化功。", "高髯高髯須貌取，萬物昇沉元有數。", "吾聞此石三千年，復化爲星上天去。"]'),
('c9b4783d-b8f1-4ba1-b36f-d6a429178ce2','題申季山所藏李伯時畫村田樂圖','戴復古','宋','宋诗','song-poetry','','[]','春秧夏苗秋遂穫，官賦私逋都了却。',128,'全唐诗/poet.song.182000.json','["春秧夏苗秋遂穫，官賦私逋都了却。", "鷄豚社酒賽豐年，醉唱村歌舞村樂。", "鼓笛有聲無曲譜，布衫顛倒傞傞舞。", "欲識太平真氣象，試看此畫有佳趣。", "管絃聲按宮商發，細轉柳腰花十八。", "羅幃綉幙拂香風，九醖葡萄金盞滑。", "王孫公子巧歡娛，勿將富貴笑田夫。", "非渠耕稼飽君腹，問有黄金可樂無。"]'),
('1104fb43-4388-423e-b4c8-a675463c8ff5','嘉定甲戌孟秋二十有七日起居舍人兼直學士院真德秀上殿直前奏邊事不顧忌諱一疏萬言援引古今鋪陳方略忠誼感激辭章浩瀚誠有補於國家天台戴復古獲見此疏伏讀再三竊有所感敬效白樂天體以紀其事錄于野史','戴復古','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','禁城鷄唱金門開，起居舍人携疏來。',359,'全唐诗/poet.song.182000.json','["禁城鷄唱金門開，起居舍人携疏來。", "榻前一奏一萬字，歷歷寫出忠義懷。", "頓首惶恐臣昧死，越錄敢言天下事。", "百年河洛行胡朔，恨滿東南天一角。", "夷甫諸人責未酬，志士愁眠劍鋒落。", "天意未回事難舉，鄉來一試成千誤。", "犬羊頻歲自相屠，盛衰大抵由天數。", "昨臣銜命出疆時，自期有去必無歸。", "屈膝穹廬當憤死，天相孤忠半道回。", "金山之下長江水，擊檝中流書壯志。", "東風吹上妙高臺，畧望江淮見形勢。", "形勢從來祇如此，幾年待得天時至。", "朝廷爲計保萬全，往往忘却前朝耻。", "臣今未暇論規恢，胡虜已亡何慮哉。", "中原曠地無人管，政恐英雄生草萊。", "北方苦饑民骨立，萬一東來竊吾粟。", "邊頭諸州無鐵壁，借問誰能備倉卒。", "請朝廷厲精兵，擇良將。", "辦多多，策上上。", "更選人材，老練通達。", "分守要衝，講明方畧。", "一賢可作萬里城，一人可當百萬兵。", "坐令國勢九鼎重，所頼君心一點明。", "長牋奏徹龍顔悅，繼言臣愚進此說。"]'),
('e7a8db78-73a1-4a6f-a61a-9cc46f432ec5','盧申之正字得春郊牧養圖二本有樓攻媿先生題詩且徵予作  其一','戴復古','宋','宋诗','song-poetry','','[]','竹弓鳴，鴈鴨驚。',88,'全唐诗/poet.song.182000.json','["竹弓鳴，鴈鴨驚。", "飛來別浦無人境，春風不摇楊柳影。", "長頸紛紛占作家，半游波面半眠沙。", "或行或立或如舞，或隻或雙或群聚。", "飲啄浮沉多態度，物情閑暇世忘機。", "分明一片太古時，巧僞不作民熙熙。"]'),
('814b88d6-caf3-4959-9532-a8b0fe3630e4','盧申之正字得春郊牧養圖二本有樓攻媿先生題詩且徵予作  其二','戴復古','宋','宋诗','song-poetry','','[]','我之居，元在野，平生慣識牛羊者。',96,'全唐诗/poet.song.182000.json','["我之居，元在野，平生慣識牛羊者。", "今見蒲江出此圖，半日不知渠是畫。", "一犍當前轉頭立，一犍度浦毛猶濕。", "中有一蒼騎以牧，𦍩羜相隨數十足。", "殿後兩枚黄觳觫，分明如活下前坡。", "路轉南山春草多，耳根只欠牧兒歌。"]'),
('388eb718-4072-4a4c-9225-37597ecbe1c0','鄂州南樓','戴復古','宋','宋诗','song-poetry','','[]','鄂州州前山頂頭，上有縹緲百尺樓。',96,'全唐诗/poet.song.182000.json','["鄂州州前山頂頭，上有縹緲百尺樓。", "大開窗戶納宇宙，高插欄干侵斗牛。", "我疑脚踏蒼龍背，下瞰八方無內外。", "江渚鱗差十萬家，淮楚荆湖一都會。", "西風吹盡庾公塵，秋影涵空動碧雲。", "欲識古今興廢事，細看文簡李公文。"]'),
('7dcf3128-5228-4bf2-b113-4bc7306fdc6d','題曾無疑飛龍飲秣圖','戴復古','宋','宋诗','song-poetry','','[]','雲巢示我良馬圖，一騎欲水一騎芻。',114,'全唐诗/poet.song.182000.json','["雲巢示我良馬圖，一騎欲水一騎芻。", "竹批雙耳目摇電，毛色純一骨相殊。", "何人貌此真權奇，筆端疑有渥洼池。", "駑駘當用驊騮老，贏得畫圖人看好。", "盆中飲，槽中秣，無用霜蹄空立鐵。", "何如渴飲長城濠上波，饑則飽喫天山禾。", "振首長鳴載猛士，龍荒踏碎犬羊窠。"]'),
('c785f6bf-e963-4f9a-9119-17e18c59161d','儒衣陳其姓工於畫牛馬魚一日持六簇爲贈以換詩','戴復古','宋','宋诗','song-poetry','','[]','生絹六幅淡墨圖，伊人筆端有造化。',192,'全唐诗/poet.song.182000.json','["生絹六幅淡墨圖，伊人筆端有造化。", "驊騮汗血捉電光，牯牸倦耕眠草下。", "陂塘漠漠烟雨後，出水群魚戲瀟洒。", "細看物物有生意，不比尋常能畫者。", "請君就此三景中，揮毫添我作漁翁。", "岸頭孤石持竿坐，白鷺同居蒲葦叢。", "有時尋詩出游衍，款段徐行山路遠。", "奚奴逐後背錦囊，木杪斜陽鴉噪晚。", "有時簑笠過田間，農婦農夫相往還。", "手放鉏犂吹短笛，日暮青郊黄犢閑。", "王孫貴人不識此，此是吾儂佳絕處。", "掛君圖畫讀吾詩，令人懶踏長安路。"]'),
('539bdf13-fb40-4278-b3b8-01b26300db41','黄州棲霞樓即景呈謝深道國正','戴復古','宋','宋诗','song-poetry','','[]','朝來欄檻倚晴空，暮來烟雨迷飛鴻。',144,'全唐诗/poet.song.182000.json','["朝來欄檻倚晴空，暮來烟雨迷飛鴻。", "白衣蒼狗易改變，淡粧濃抹難形容。", "蘆洲渺渺去無極，數點斷山橫遠碧。", "樊山諸峰立一壁，非烟非霧籠秋色。", "須臾黑雲如潑墨，欲雨不雨不可得。", "須臾雲開見落日，忽展一機雲錦出。", "一態未了一態生，愈變愈奇人莫測。", "使君把酒索我詩，索詩不得呼畫師。", "要知作詩如作畫，人力豈能窮造化。"]'),
('20fd4304-e677-4a98-b472-830e38638292','題上虞縣信芳堂','戴復古','宋','宋诗','song-poetry','','[]','河陽種桃彭澤柳，歲歲春風誇不朽。',96,'全唐诗/poet.song.182000.json','["河陽種桃彭澤柳，歲歲春風誇不朽。", "何如君種一池蓮，開向五月六月天。", "紅粧當暑清無汗，綠葉染風香不斷。", "坐令百里盡清凉，天乃贈君雲錦段。", "此花不可無此堂，主人姓字同芬芳。", "更看堂後參差竹，醉倚炎空舞寒綠。"]'),
('efe8608f-dc2a-4f66-bbe1-6604cc622f5e','衡山何道士有詩聲楊伯子監丞盛稱之以楊所取之詩求跋其後','戴復古','宋','宋诗','song-poetry','','["\u8861\u5c71"]','道人幽吟巖壑底，伴曉猿啼秋鶴唳。',165,'全唐诗/poet.song.182000.json','["道人幽吟巖壑底，伴曉猿啼秋鶴唳。", "自陶情性樂天真，一心不作求名計。", "一朝邂逅楊東山，詩聲揚揚滿世間。", "東山才與誠齋敵，手腕中有萬斛力。", "爲君翻九淵，探君驪龍珠。", "爲君擘滄海，鈎上珊瑚枝。", "豐城地下掘起龍泉太阿雙寶劍，南山霧裏窺見隠豹文章皮。", "是寶欲藏藏不得，總被東山手拈出。", "道人從此詩價高，石廩祝融爭崒嵂。", "君不見彌明石鼎聯句詩，千載託名韓退之。"]'),
('d4ac9f3f-687a-41cd-966d-3e32d1cefdce','徐京伯通判晚歲得二子','戴復古','宋','宋诗','song-poetry','','[]','竹隠種竹知幾年，千竿萬竿長拂天。',100,'全唐诗/poet.song.182000.json','["竹隠種竹知幾年，千竿萬竿長拂天。", "群飛不敢下棲止，常有清風凜凜然。", "丹穴飛來兩雛鳳，鳳來此竹爲之重。", "牙籤玉軸带芸香，家藏萬卷爲渠用。", "人間豚犬不足多，我來爲作徐卿二子歌。", "手傳竹隠文章印，看取他日官職高嵯峨。"]'),
('e4edc974-5145-40c7-9c59-0e07fd7d15a2','寄報恩長老恭率翁','戴復古','宋','宋诗','song-poetry','','[]','報恩千楹歸一炬，佛也不能逃劫數。',98,'全唐诗/poet.song.182000.json','["報恩千楹歸一炬，佛也不能逃劫數。", "寶坊化作瓦礫場，堪笑月庭來又去。", "率翁修造鳳樓手，第一能將無作有。", "神工作舍鬼築牆，鞭笞木石能飛走。", "風斤月斧日紛然，行看華屋突兀在眼前。", "好留一室舘狂客，早晚來參文字禪。"]'),
('40ff157e-021f-4615-9b7e-eb3be7c1f6d3','織婦歎','戴復古','宋','宋诗','song-poetry','','[]','春蠶成絲復成絹，養得夏蠶重剝繭。',64,'全唐诗/poet.song.182000.json','["春蠶成絲復成絹，養得夏蠶重剝繭。", "絹未脫軸擬輸官，絲未落車圖贖典。", "一春一夏爲蠶忙，織婦布衣仍布裳。", "有布得著猶自可，今年無麻愁殺我。"]'),
('d8dc76b6-8eae-4661-a2e3-0bbd2f4f18f0','刈麥行','戴復古','宋','宋诗','song-poetry','','[]','腰鎌上壠刈黄雲，東家西家麥滿門。',64,'全唐诗/poet.song.182000.json','["腰鎌上壠刈黄雲，東家西家麥滿門。", "前村寡婦拾滯穟，饘粥有餘炊餠餌。", "我聞淮南麥最多，麥田今歲屯干戈。", "飽飯不知征戰苦，生長此方真樂土。"]'),
('a363919e-d1e8-47a4-bfdb-9b2a7db2107e','鄂渚張唐卿周嘉仲送別','戴復古','宋','宋诗','song-poetry','','[]','武昌江頭人送別，楊柳秋來不堪折。',64,'全唐诗/poet.song.182000.json','["武昌江頭人送別，楊柳秋來不堪折。", "漢陽門外望南樓，昨日不知今日愁。", "英雄握手新相識，人情正好成南北。", "酒闌人散最關情，一鴈西飛楚天碧。"]'),
('228b6afa-ae4f-4932-84f4-2d3616c25a7b','詰燕','戴復古','宋','宋诗','song-poetry','','[]','去年汝來巢我屋，梁間汙泥高一尺。',110,'全唐诗/poet.song.182000.json','["去年汝來巢我屋，梁間汙泥高一尺。", "啄腥拋穢不汝厭，生長群雛我護惜。", "家貧惠愛不及人，自謂於汝獨有力。", "不望汝如靈蛇銜寶珠，雀獻金環來報德。", "春風期汝一相顧，對語茅簷慰岑寂。", "如何今年來，於我絕蹤跡。", "一貪簾幕畫堂間，便視吾廬爲棄物。"]'),
('3119cd16-bbd3-4283-83a1-5dc7fc9dd679','寄趙鼎臣','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','學如劉子政，不使校書天祿閣。',116,'全唐诗/poet.song.182000.json','["學如劉子政，不使校書天祿閣。", "文如李太白，不使待詔金鑾殿。", "倚樓終日看廬山，贏得虛名聞九縣。", "才忌太高，心忌太清。", "平平穩穩，爲公爲卿。", "騏驥可覊，乃歸帝閑。", "麟鳳莫馴，爲瑞人間。", "人間爲瑞徒能好，騏驥可覊終遠到。", "歲寒心事幾人知，手把梅花供一笑。"]'),
('13d82973-8645-40bb-8487-2b3d6487d718','毗陵天慶觀畫龍自題姑蘇羽士李懷仁醉筆詩呈王君保寺丞使君','戴復古','宋','宋诗','song-poetry','','[]','姑蘇道士天酒星，醉筆寫出雙龍形。',128,'全唐诗/poet.song.182000.json','["姑蘇道士天酒星，醉筆寫出雙龍形。", "墨蹟從橫奪造化，蜿蜒滿壁令人驚。", "一龍翻身出雲表，口吞八極滄溟小。", "手弄寶珠珠欲飛，握入掌中拳五爪。", "一龍排山山爲開，頭角與石爭崔嵬。", "波濤怒起接雲氣，不向九霄行雨來。", "萬物焦枯天作旱，兩雄壁隠寧非懶。", "真龍不用只畫圖，猛拍欄干寄三歎。"]'),
('a90f8305-9409-423e-83bf-ca411f9d3548','漁父詞四首  其一','戴復古','宋','宋诗','song-poetry','','[]','漁父飲，不須錢。',22,'全唐诗/poet.song.182000.json','["漁父飲，不須錢。", "柳枝斜貫錦鱗鮮，換酒却歸船。"]'),
('3e09921e-7ec6-44b7-adb3-42e8295a8f60','漁父詞四首  其二','戴復古','宋','宋诗','song-poetry','','[]','漁父醉，釣竿閑。',22,'全唐诗/poet.song.182000.json','["漁父醉，釣竿閑。", "柳下呼兒牢繫船，高眠風月天。"]'),
('c722b013-ea65-4bfc-a6a3-72699cc2c987','秋懷','戴復古','宋','宋诗','song-poetry','','[]','紅葉無人掃，黄花獨自妍。',48,'全唐诗/poet.song.182000.json','["紅葉無人掃，黄花獨自妍。", "聽談天下事，愁到酒樽前。", "水闊終非海，樓高不到天。", "昔人已懷古，况復後千年。"]'),
('c4d98232-3e22-492f-995a-7760feb72c10','晚春次韵','戴復古','宋','宋诗','song-poetry','','[]','酒醒愁難醒，春歸客未歸。',48,'全唐诗/poet.song.182000.json','["酒醒愁難醒，春歸客未歸。", "鶑啼花雨歇，燕立柳風微。", "世路多殊轍，人生貴識機。", "低頭飽一粟，仰首愧雲飛。"]'),
('40bf98dd-37b1-49f1-be49-ef0b41a91243','元日二首呈永豐劉叔冶知縣  其一','戴復古','宋','宋诗','song-poetry','','[]','焚香拜元日，受歲客他州。',48,'全唐诗/poet.song.182000.json','["焚香拜元日，受歲客他州。", "白髮難遮老，新年諱說愁。", "無人能訪戴，有地足依劉。", "桃李爭春事，梅花笑未休。"]'),
('56992462-2f8e-4011-99e8-f06ef6f765a0','元日二首呈永豐劉叔冶知縣  其二','戴復古','宋','宋诗','song-poetry','','[]','市近人聲雜，窗明雨色開。',48,'全唐诗/poet.song.182000.json','["市近人聲雜，窗明雨色開。", "異鄉輕度節，同邸重傳杯。", "不礙狂夫醉，知無賀客來。", "故園歸未得，茅屋想蒼苔。"]'),
('110d0157-ad4c-441f-a312-3b4dfd95b238','宿農家','戴復古','宋','宋诗','song-poetry','','[]','門巷規模古，田園氣味長。',48,'全唐诗/poet.song.182000.json','["門巷規模古，田園氣味長。", "小桃紅破萼，大麥綠銜芒。", "稚犬迎來客，歸牛带夕陽。", "儒衣愧飄泊，相就說農桑。"]'),
('80d77a54-303d-4add-9ef7-33aa34f0d830','湘中','戴復古','宋','宋诗','song-poetry','','[]','荆楚一都會，瀟湘八景圖。',48,'全唐诗/poet.song.182000.json','["荆楚一都會，瀟湘八景圖。", "試呼沙鳥問，曾識古人無。", "痛哭賈太傅，行吟屈大夫。", "汀洲芳草歇，轉使客情孤。"]'),
('c8b4dbb1-6fae-4975-a327-41cf7640169a','水陸寺','戴復古','宋','宋诗','song-poetry','','[]','長沙沙上寺，突兀古樓臺。',48,'全唐诗/poet.song.182000.json','["長沙沙上寺，突兀古樓臺。", "四面水光合，一邊山影來。", "靜分僧榻坐，晚趁釣船回。", "明日重相約，前村訪早梅。"]'),
('434cfebe-c979-434f-83ad-2343047c7a45','題分宜縣呈石子和知縣','戴復古','宋','宋诗','song-poetry','','[]','古鎮更爲縣，封疆半是山。',48,'全唐诗/poet.song.182000.json','["古鎮更爲縣，封疆半是山。", "賦繁官吏窘，土瘠稻粱慳。", "流水心何急，高山意自閑。", "春風細吹拂，桃李滿民間。"]'),
('45e090e5-9c54-412a-8b53-fb3dd46ac9c1','清明感傷','戴復古','宋','宋诗','song-poetry','','[]','一笠戴春雨，愁來不可遮。',48,'全唐诗/poet.song.182000.json','["一笠戴春雨，愁來不可遮。", "清明思上塚，昨夜夢還家。", "歸興隨流水，傷心對落花。", "晉原松下淚，沾洒楚天涯。"]'),
('499f44e5-e99a-4145-a29b-20b643ebf10c','都中書懷二首  其一','戴復古','宋','宋诗','song-poetry','','[]','醉卧長安市，思歸東海涯。',48,'全唐诗/poet.song.182000.json','["醉卧長安市，思歸東海涯。", "瓶餘殘臘酒，梅老隔年花。", "日與愁爲地，時憑夢到家。", "鄉書三兩紙，一讀一咨嗟。"]'),
('42be5574-13d8-4803-83fa-411b2bf9c3a6','都中書懷二首  其二','戴復古','宋','宋诗','song-poetry','','[]','雪化晴簷雨，爐烘凍壁春。',48,'全唐诗/poet.song.182000.json','["雪化晴簷雨，爐烘凍壁春。", "窮猶戀詩酒，懶不正衣巾。", "寂寞安吾分，奔馳失我真。", "枯桐就煨燼，容有賞音人。"]'),
('252307fd-3d65-4e3a-9f45-405d3415c165','歲暮呈真翰林','戴復古','宋','宋诗','song-poetry','','[]','歲事朝朝迫，家書字字愁。',48,'全唐诗/poet.song.182000.json','["歲事朝朝迫，家書字字愁。", "頻沽深巷酒，獨倚異鄉樓。", "詩骨梅花瘦，歸心江水流。", "狂謀渺無際，忍看大刀頭。"]'),
('b24a3307-42e1-4e4d-9b5e-4f760abf3d0d','游天竺','戴復古','宋','宋诗','song-poetry','','[]','好山看不了，遂借上方眠。',48,'全唐诗/poet.song.182000.json','["好山看不了，遂借上方眠。", "酒渴傾花露，詩清瀉澗泉。", "生無適俗韵，老欲結僧緣。", "睡覺鐘聲曉，窗騰柏子烟。"]'),
('61470c29-0f07-4cb2-98fc-7d0a8d269a61','盧申之正字小酌','戴復古','宋','宋诗','song-poetry','','[]','清境無塵雜，覊懷向此開。',48,'全唐诗/poet.song.182000.json','["清境無塵雜，覊懷向此開。", "主人有風度，和我不塵埃。", "倚竹評詩句，拈花泛酒杯。", "出門見明月，客去又招回。"]'),
('46253962-a7dd-44ec-9818-d8308fcb7c3d','鳳凰臺','戴復古','宋','宋诗','song-poetry','','[]','登臨舒老眼，吊古得凄凉。',48,'全唐诗/poet.song.182000.json','["登臨舒老眼，吊古得凄凉。", "故國自龍虎，高臺無鳳凰。", "浮雲多改變，喬木見興亡。", "往事渾休問，鍾山又夕陽。"]'),
('c798c67d-bf56-41f3-a018-7ea0305a31ef','山中即目二首  其一','戴復古','宋','宋诗','song-poetry','','[]','巖路穿黄落，人家隠翠微。',48,'全唐诗/poet.song.182000.json','["巖路穿黄落，人家隠翠微。", "籠鷄爲鴨抱，網犬逐鶉飛。", "竹好堪延客，溪清欲浣衣。", "禪扉在何許，僧笠戴雲歸。"]'),
('5d113235-aa6d-4ac5-85a3-59020b546f64','山中即目二首  其二','戴復古','宋','宋诗','song-poetry','','[]','茅屋七五聚，沙汀八九磐。',48,'全唐诗/poet.song.182000.json','["茅屋七五聚，沙汀八九磐。", "梯山畦麥秀，囊石障溪湍。", "父老鷄豚社，兒童梨栗盤。", "幽居有餘樂，奔走愧儒冠。"]'),
('8e9a4f6b-676e-4f55-995d-5549e1fbfaa3','題徐京伯通判北征詩卷','戴復古','宋','宋诗','song-poetry','','[]','一襟忠誼氣，數首北征詩。',48,'全唐诗/poet.song.182000.json','["一襟忠誼氣，數首北征詩。", "不許公卿見，徒爲篋笥奇。", "銜枚衝雪夜，擊楫誓江時。", "此志無人共，愁吟兩鬢絲。"]'),
('60eba51a-d27b-4992-9b6b-96829f474fe5','江上','戴復古','宋','宋诗','song-poetry','','[]','山束江流急，雲兼霧氣深。',48,'全唐诗/poet.song.182000.json','["山束江流急，雲兼霧氣深。", "輕鷗閑態度，孤鴈苦聲音。", "客路行無極，風光古又今。", "梅花出籬落，幽事頗關心。"]'),
('9eecd660-2616-4269-ae8c-01b00372453d','賢女祠','戴復古','宋','宋诗','song-poetry','','[]','士有敗風節，慙魂埋九京。',48,'全唐诗/poet.song.182000.json','["士有敗風節，慙魂埋九京。", "幽閨持大誼，千載著嘉名。", "父不重然諾，女能輕死生。", "寒潭墮秋月，心迹兩清明。"]'),
('bddbfca0-ab19-455b-bb04-356a70a4ab63','春盡日','戴復古','宋','宋诗','song-poetry','','[]','撚指過三月，又當春夏交。',48,'全唐诗/poet.song.182000.json','["撚指過三月，又當春夏交。", "花殘蜂課蜜，林茂鳥安巢。", "芳草生青靄，新篁展綠稍。", "風騷將斷絕，誰有續絃膠。"]'),
('d6b90375-1177-4366-9050-2f0597b67741','寄栗齋鞏仲至','戴復古','宋','宋诗','song-poetry','','[]','幾度觀朝報，差除不到君。',48,'全唐诗/poet.song.182000.json','["幾度觀朝報，差除不到君。", "山林自臺閣，文字即功勳。", "吟苦孟東野，潛深楊子雲。", "一官雖偃蹇，千載有知聞。"]'),
('a1173f0e-22b2-4559-8a79-752315a694ba','次韵史景望雪夜','戴復古','宋','宋诗','song-poetry','','[]','雪中寒力壯，病骨瘦難勝。',48,'全唐诗/poet.song.182000.json','["雪中寒力壯，病骨瘦難勝。", "溫酒撥爐火，題詩敲硯冰。", "驚心雙白鬢，知我一青燈。", "欲誤浮生事，思參小大乘。"]'),
('ae7e32b2-258e-48ca-8ee9-cecb6df5788b','春日懷家','戴復古','宋','宋诗','song-poetry','','[]','細數平生事，何堪挂齒牙。',48,'全唐诗/poet.song.182000.json','["細數平生事，何堪挂齒牙。", "客游兒廢學，身拙婦持家。", "開甕嘗春酒，租山摘早茶。", "關心此時節，歸興滿天涯。"]'),
('d972ca1b-f987-4ad7-af7d-d0ec088c3739','寄沈莊可','戴復古','宋','宋诗','song-poetry','','[]','無山可種菊，强號菊山人。',48,'全唐诗/poet.song.182000.json','["無山可種菊，强號菊山人。", "結得諸公好，吟成五字新。", "紅塵時在路，白髮未離貧。", "吾輩渾如此，天公似不仁。"]'),
('1c67a3bf-fbda-4a78-999d-19f682b618d6','山行','戴復古','宋','宋诗','song-poetry','','[]','度嶺休騎馬，臨淵看網魚。',48,'全唐诗/poet.song.182000.json','["度嶺休騎馬，臨淵看網魚。", "木根高可坐，巖石細堪書。", "谷鳥鳴相答，山雲卷復舒。", "儒衣人賣酒，疑是馬相如。"]'),
('ad8b89a0-d1de-4ef1-ab06-2e60cfedefe0','次韵謝敬之題南康縣劉清老園','戴復古','宋','宋诗','song-poetry','','[]','劉子隠居地，真如李願盤。',48,'全唐诗/poet.song.182000.json','["劉子隠居地，真如李願盤。", "萬松春不老，多竹夏生寒。", "卜築世情遠，登臨客慮寬。", "題詩疥君壁，聊以記游觀。"]'),
('5b193fb7-beb0-4c7d-b687-2da906648b61','淮上春日','戴復古','宋','宋诗','song-poetry','','[]','邊寒客衣薄，漸喜暖風回。',48,'全唐诗/poet.song.182000.json','["邊寒客衣薄，漸喜暖風回。", "社後未聞燕，春深方見梅。", "壯懷頻撫劍，孤憤强銜杯。", "北望山河語，天時不再來。"]'),
('68f75b68-43cd-4abb-934a-348a69c37b59','麻城道中','戴復古','宋','宋诗','song-poetry','','[]','三杯成小醉，行處總堪詩。',48,'全唐诗/poet.song.182000.json','["三杯成小醉，行處總堪詩。", "臨水知魚樂，觀山愛馬遲。", "林塘飛翡翠，籬落带酴醾。", "問訊邊頭事，溪翁總不知。"]'),
('343d2a0c-041b-4626-9ce9-ac7cbac4135c','望花山張老家','戴復古','宋','宋诗','song-poetry','','[]','元從邊上住，來此避兵興。',48,'全唐诗/poet.song.182000.json','["元從邊上住，來此避兵興。", "麥麨朝充食，松明夜當燈。", "蔽門麻菶菶，護壁石層層。", "老嫗逢人哭，吾兒在謝陵。"]'),
('db1fed40-0fdc-4f46-9701-efaa13260854','春日','戴復古','宋','宋诗','song-poetry','','[]','淫滯江湖久，蹉跎歲月新。',48,'全唐诗/poet.song.182000.json','["淫滯江湖久，蹉跎歲月新。", "客愁茅店雨，詩思柳橋春。", "秣馬尋歸路，騎鯨問故人。", "山林與朝市，何處著吾身。"]'),
('3ef1331c-f826-4012-912b-74959856906b','聞李將軍至建康','戴復古','宋','宋诗','song-poetry','','[]','匹馬徑趨府，將軍意氣多。',48,'全唐诗/poet.song.182000.json','["匹馬徑趨府，將軍意氣多。", "來依漢日月，思復晉山河。", "邊將慚尸素，朝臣奏凱歌。", "分明御徂詐，得失竟如何。"]'),
('f43706a4-fd48-47f4-a6a7-7b9e0d17ff67','江漲見移居者','戴復古','宋','宋诗','song-poetry','','[]','夏潦連秋漲，人家水半門。',48,'全唐诗/poet.song.182000.json','["夏潦連秋漲，人家水半門。", "都拋破茅屋，移住小山村。", "聒聒籠鷄犬，纍纍带子孫。", "安居華屋者，應覺此身尊。"]'),
('300e3fdb-b75b-498f-9051-fd1ba980a27d','上喬右司','戴復古','宋','宋诗','song-poetry','','[]','端笏立朝日，肺肝傾上前。',48,'全唐诗/poet.song.182000.json','["端笏立朝日，肺肝傾上前。", "把麾持節處，桃李滿淮壖。", "藥石箴時病，蓍龜燭事先。", "焦頭與曲突，爲計孰爲賢。"]'),
('b30e6c4e-55c5-4517-a240-a7cd3d61e28d','贈郭道人','戴復古','宋','宋诗','song-poetry','','[]','滅性能安樂，深居絕是非。',48,'全唐诗/poet.song.182000.json','["滅性能安樂，深居絕是非。", "英雄行險道，富貴隠危機。", "紙被如綿軟，藜羹勝肉肥。", "蒼苔滿山徑，最喜客來稀。"]'),
('2c58cd08-3804-40cd-a26a-842756372f6f','送湘漕趙蹈中寺丞移憲江東','戴復古','宋','宋诗','song-poetry','','[]','持節復持節，因循霜鬢侵。',48,'全唐诗/poet.song.182000.json','["持節復持節，因循霜鬢侵。", "盛衰關大數，豪傑負初心。", "宇宙虛長算，江湖寄短吟。", "番陽秋水闊，湘浦未爲深。"]'),
('1658d135-1360-4f49-912a-b540cfe934cd','立春後二首  其一','戴復古','宋','宋诗','song-poetry','','[]','夕望春風至，還經閏月遲。',48,'全唐诗/poet.song.182000.json','["夕望春風至，還經閏月遲。", "梅花丈人行，柳色少年時。", "愛酒常無伴，吟詩近得師。", "離騷變風雅，當效楚臣爲。"]'),
('9190bbcf-5472-4902-addd-4176f040e275','立春後二首  其二','戴復古','宋','宋诗','song-poetry','','[]','東風吹竹屋，無數落梅花。',48,'全唐诗/poet.song.182000.json','["東風吹竹屋，無數落梅花。", "凍雀栖簷角，饑烏啄草芽。", "家鄉勞夜夢，客路又春華。", "莫訝狂夫醉，西樓酒可賒。"]'),
('d7f796dd-4052-45e2-929a-46ba68bffba1','寄韓仲止','戴復古','宋','宋诗','song-poetry','','[]','何以澗泉號，取其清又清。',48,'全唐诗/poet.song.182000.json','["何以澗泉號，取其清又清。", "天游一丘壑，孩視幾公卿。", "杯舉即時酒，詩留後世名。", "黄花秋意足，東望憶淵明。"]'),
('03cdfd5b-8f49-48ae-b7d7-ce8cca45a14a','題張簽判園林','戴復古','宋','宋诗','song-poetry','','[]','園圃屋東西，從君一杖藜。',48,'全唐诗/poet.song.182000.json','["園圃屋東西，從君一杖藜。", "雨寒花蕊瘦，春重柳絲低。", "亭舘常留客，軒窗總傍溪。", "摩挲雪色壁，安得好詩題。"]'),
('0b41bb97-94d3-4856-8ea1-4e6a955a1b55','哭趙紫芝','戴復古','宋','宋诗','song-poetry','','[]','嗚呼趙紫芝，其命止於斯。',48,'全唐诗/poet.song.182000.json','["嗚呼趙紫芝，其命止於斯。", "東晉時人物，晚唐家數詩。", "瘦因吟思苦，窮爲宦情癡。", "憶在藏春圃，花邊細話時。"]'),
('846e67cd-915a-4070-92d7-8db9d1cc7eae','江村何宏甫載酒過清江','戴復古','宋','宋诗','song-poetry','','[]','玉笥千峰雨，金風十日秋。',48,'全唐诗/poet.song.182000.json','["玉笥千峰雨，金風十日秋。", "誰能多載酒，來此共登樓。", "山立閲萬變，溪深納衆流。", "故人歸未得，我亦爲詩留。"]'),
('1f293fa5-856d-4bb1-85b1-1dc271e3e539','臨江軍新歲呈王幼學監簿','戴復古','宋','宋诗','song-poetry','','[]','夢說去年事，詩從昨夜吟。',48,'全唐诗/poet.song.182000.json','["夢說去年事，詩從昨夜吟。", "三杯新歲酒，千里故鄉心。", "人共梅花老，愁連江水深。", "家書忽在眼，一紙直千金。"]'),
('3c814e25-70c9-4ae3-8bff-eadcd1ae77f7','訪楊伯子監丞自白沙問路而去  其一','戴復古','宋','宋诗','song-poetry','','[]','欲訪揚雄宅，扁舟過白沙。',48,'全唐诗/poet.song.182000.json','["欲訪揚雄宅，扁舟過白沙。", "自從山以後，直到水之涯。", "風節古人物，文章老作家。", "相尋有忙事，第一問梅花。"]'),
('2c2820e8-ef2e-4c08-9d7d-3d962161c6f9','訪楊伯子監丞自白沙問路而去  其二','戴復古','宋','宋诗','song-poetry','','[]','朝市風波地，乾坤漁獵場。',48,'全唐诗/poet.song.182000.json','["朝市風波地，乾坤漁獵場。", "生民日憔悴，吾道亦凄凉。", "龍不爲霖出，鳳於何處藏。", "群鴉爭晚噪，一意送斜陽。"]'),
('29d7c720-6648-4881-8756-64cc78dd8fbb','劉興伯黄希宋蘇希亮慧力寺避暑','戴復古','宋','宋诗','song-poetry','','[]','何處避炎熱，相期過寶坊。',48,'全唐诗/poet.song.182000.json','["何處避炎熱，相期過寶坊。", "萬松深處坐，六月午時凉。", "鐘磬出深屋，江山界短牆。", "醉來歸興懶，留宿贊公房。"]'),
('17607bb3-b269-436a-9bd0-72ad1f16393e','秋夜旅中','戴復古','宋','宋诗','song-poetry','','[]','旅食思鄉味，砧聲起客愁。',48,'全唐诗/poet.song.182000.json','["旅食思鄉味，砧聲起客愁。", "夜凉風動竹，人靜月當樓。", "浮世百年夢，他鄉幾度秋。", "店翁新酒熟，一醉更何求。"]'),
('3a0725c5-62e9-4e84-8485-3de570f1b40e','舟行往吊故人','戴復古','宋','宋诗','song-poetry','','[]','喬木風聲壯，大江天影圓。',48,'全唐诗/poet.song.182000.json','["喬木風聲壯，大江天影圓。", "悲秋時把酒，愛月夜行船。", "未及到河上，先愁過竹邊。", "倚篷思往事，聞笛爲凄然。"]'),
('5a8cbab8-f4b8-4642-a458-e83e5dda4cc4','擬峴臺杜子野主簿寓居','戴復古','宋','宋诗','song-poetry','','[]','高臺延望眼，風物滿前村。',48,'全唐诗/poet.song.182000.json','["高臺延望眼，風物滿前村。", "細讀南豐記，頻開北海樽。", "遠山如看畫，近市不聞喧。", "詩是君家事，長城在五言。"]'),
('8ad1e5a8-add4-4894-89b4-1f8d5e0ec991','無策','戴復古','宋','宋诗','song-poetry','','[]','老覺登樓懶，心知涉世疎。',48,'全唐诗/poet.song.182000.json','["老覺登樓懶，心知涉世疎。", "夢蕉還得鹿，緣木可求魚。", "晚歲未聞道，平生欠讀書。", "行藏兩無策，究竟果何如。"]'),
('4af24969-89ea-4943-b1d4-253b8ebec427','題萍鄉何叔萬雲山','戴復古','宋','宋诗','song-poetry','','[]','拄杖穿雲去，一坡仍一坡。',48,'全唐诗/poet.song.182000.json','["拄杖穿雲去，一坡仍一坡。", "地高山不峻，花少竹還多。", "家近登臨便，人賢氣味和。", "能詩老姚合，朝夕共吟哦。"]'),
('4aa85cb3-a962-48a9-b8fe-3eb1d1561bd1','常寧縣訪許介之途中即景','戴復古','宋','宋诗','song-poetry','','[]','竹徑入茅屋，松坡連菜畦。',48,'全唐诗/poet.song.182000.json','["竹徑入茅屋，松坡連菜畦。", "深潴漚麻水，斜豎采桑梯。", "區別隣家鴨，群分各線鷄。", "行人來少憇，假道過東溪。"]'),
('08b27d8f-f9df-482d-9b2b-80166d50634e','建昌道上','戴復古','宋','宋诗','song-poetry','','[]','凜凜北風勁，行行西路賒。',48,'全唐诗/poet.song.182000.json','["凜凜北風勁，行行西路賒。", "人情甘淡薄，世事苦參差。", "酒易逢知己，詩難遇作家。", "林間數點雪，錯認是梅花。"]'),
('9cc2482b-ae97-4739-87e1-a6fa562cb15a','訪嚴坦叔','戴復古','宋','宋诗','song-poetry','','[]','麻姑山下泊，城郭带烟霞。',48,'全唐诗/poet.song.182000.json','["麻姑山下泊，城郭带烟霞。", "携刺投詩社，移船傍酒家。", "沙禽時弄水，櫸柳夏飛花。", "小酌未能了，西樓日又斜。"]'),
('b673d898-484b-43a5-97f0-3b8f695209a8','杜仲高自鄂渚下儀真','戴復古','宋','宋诗','song-poetry','','[]','鄂渚三千里，南樓看月回。',48,'全唐诗/poet.song.182000.json','["鄂渚三千里，南樓看月回。", "東園花政好，去歲客重來。", "兄弟皆名士，文章動上台。", "傾城傾國色，也用覓良媒。"]'),
('72b00a8a-af75-42cf-8ff0-dc117adac2c5','見趙知道運使','戴復古','宋','宋诗','song-poetry','','[]','飽食武昌魚，不如歸故廬。',48,'全唐诗/poet.song.182000.json','["飽食武昌魚，不如歸故廬。", "盟鷗還海道，問鴈覓家書。", "又把鄉人刺，來投使者車。", "東園桃與李，莫使著花疎。"]'),
('c0db6948-3a17-49a6-8eff-40bbc2d807e9','趙叔垕山堂安下其家適有喪事','戴復古','宋','宋诗','song-poetry','','[]','一徑沿溪入，數椽松竹間。',48,'全唐诗/poet.song.182000.json','["一徑沿溪入，數椽松竹間。", "豈知人事變，自覺客身閑。", "采菊出尋酒，移床卧看山。", "蒼頭無可作，把釣過西灣。"]'),
('938b5338-922f-402a-b23d-3994f45b2598','黄道士出爻','戴復古','宋','宋诗','song-poetry','','[]','林屋何瀟洒，權爲羽士家。',48,'全唐诗/poet.song.182000.json','["林屋何瀟洒，權爲羽士家。", "客來多載酒，僧至自煎茶。", "試墨題新竹，携筇數落花。", "飲中忙過日，無暇問丹砂。"]'),
('61db8d72-76ba-4717-9eae-d125c4c39a12','陳伯可山亭','戴復古','宋','宋诗','song-poetry','','[]','梯險登霞外，乘流過竹西。',48,'全唐诗/poet.song.182000.json','["梯險登霞外，乘流過竹西。", "寒溪隨雨漲，高閣與雲齊。", "雙鶴有時舞，孤猿何處啼。", "清吟無盡興，白石可留題。"]'),
('9c8bf85c-970f-4c02-a80d-1ffe555955f2','玉山章泉本章氏所居趙昌甫遷居於此章泉之名遂顯','戴復古','宋','宋诗','song-poetry','','[]','茲山自開闢，有此一泓泉。',48,'全唐诗/poet.song.182000.json','["茲山自開闢，有此一泓泉。", "姓自章而立，名因趙以傳。", "源從番水出，地與瑞峰連。", "寄語山中友，臨流著數椽。"]'),
('7f6cea0c-61c3-4a41-adc0-2fd629fc848b','題永州思范堂','戴復古','宋','宋诗','song-poetry','','[]','太守能延客，茲堂爲我開。',48,'全唐诗/poet.song.182000.json','["太守能延客，茲堂爲我開。", "清池照窗戶，列嶂带樓臺。", "剔蘚觀題字，披榛欲訪梅。", "城根數株石，曾識范公來。"]'),
('8086c088-71be-4493-849b-cdecae95a071','舟中病起登覽','戴復古','宋','宋诗','song-poetry','','[]','檥棹病三日，登樓舉一觥。',48,'全唐诗/poet.song.182000.json','["檥棹病三日，登樓舉一觥。", "江山從古在，花草逐時生。", "南浦佳人別，西風送客行。", "錦鱗能自躍，獻我一杯羹。"]'),
('3623c3cf-7d99-4a1f-a729-893d2793bcb0','邵陽趙節齋史君同黄季玉以合江亭三字分韵','戴復古','宋','宋诗','song-poetry','','[]','萬里清秋景，都歸乎此亭。',48,'全唐诗/poet.song.182000.json','["萬里清秋景，都歸乎此亭。", "光陰幾今古，天地一宮廷。", "澬水東西白，梅山表裏青。", "登臨生酒興，欲醉又還醒。"]'),
('24599381-d42c-413a-9119-13d77e2a085c','見湖南繡使陳益甫大著  其一','戴復古','宋','宋诗','song-poetry','','[]','手攬澄清轡，聲名漢范滂。',48,'全唐诗/poet.song.182000.json','["手攬澄清轡，聲名漢范滂。", "一臺振風采，列郡正權綱。", "衡嶽勢增重，文星日有光。", "金門雖藐藐，玉節自堂堂。"]'),
('a6c50688-e1e0-473f-bc99-38ade94a4c83','見湖南繡使陳益甫大著  其二','戴復古','宋','宋诗','song-poetry','','[]','麾節羅群彥，朝廷只數公。',48,'全唐诗/poet.song.182000.json','["麾節羅群彥，朝廷只數公。", "近民多惠澤，望闕負孤忠。", "星殞京城震，沙移海水通。", "欲知休咎證，無路問蒼穹。"]'),
('b6e7bdbe-93e1-4118-9310-7abbd2a28959','見湖南繡使陳益甫大著  其三','戴復古','宋','宋诗','song-poetry','','[]','敢寫散人號，來登君子堂。',48,'全唐诗/poet.song.182000.json','["敢寫散人號，來登君子堂。", "論文才力短，憂世話頭長。", "老不堪行路，心思歸故鄉。", "數行詩後語，夜夜吐光芒。"]'),
('d71be479-c300-46de-ba0b-2753a2b97e53','南臺寺長老乃福州士人陳其姓語及光拙庵遭際寺乃石頭和尚道場','戴復古','宋','宋诗','song-poetry','','[]','元龍湖海士，參得石頭禪。',48,'全唐诗/poet.song.182000.json','["元龍湖海士，參得石頭禪。", "卓筆翻千偈，住山今十年。", "安心一丘壑，過眼幾雲烟。", "莫笑拙庵拙，聲名動九天。"]'),
('3031f113-9d03-45dd-8fdb-4136b73d835a','真西山帥長沙禱雨  其一','戴復古','宋','宋诗','song-poetry','','[]','太守持齋戒，精誠動九天。',48,'全唐诗/poet.song.182000.json','["太守持齋戒，精誠動九天。", "驕陽變霖雨，凶歲轉豐年。", "信是經綸手，行司造化權。", "唐時相房杜，斗米直三錢。"]'),
('16fa4e1c-b010-426e-b006-cf29de0e036f','真西山帥長沙禱雨  其二','戴復古','宋','宋诗','song-poetry','','[]','出郭問農事，家家笑語聲。',48,'全唐诗/poet.song.182000.json','["出郭問農事，家家笑語聲。", "有田皆足水，既雨亦宜晴。", "山下溪流急，街頭米價平。", "明朝聞領客，相見賀秋成。"]'),
('0b85329d-3622-41d4-a5b4-6f28fe8c7db0','蘇希亮約客游劉興伯大自在亭','戴復古','宋','宋诗','song-poetry','','[]','偶爾來江上，從君到酒邊。',48,'全唐诗/poet.song.182000.json','["偶爾來江上，從君到酒邊。", "雨晴花弄日，風定柳凝烟。", "適意共一笑，浮生無百年。", "明朝大自在，誰辦載花船。"]'),
('17510293-4ac4-48b3-b637-d6bac4e411df','客中寄家書併簡季道姪','戴復古','宋','宋诗','song-poetry','','[]','東隠三年別，西風一紙書。',48,'全唐诗/poet.song.182000.json','["東隠三年別，西風一紙書。", "逢人相問訊，念我獨勤渠。", "游子司吾土，先人有弊廬。", "欲歸歸未得，妻子定何如。"]'),
('3961bcff-1831-4917-a0c7-04c912911095','舟中夜坐','戴復古','宋','宋诗','song-poetry','','[]','獨坐觀星斗，一襟秋思長。',48,'全唐诗/poet.song.182000.json','["獨坐觀星斗，一襟秋思長。", "天河司米價，太乙照時康。", "月浦孤帆過，風荷一路香。", "持杯問舟子，今夜宿誰鄉。"]'),
('86b4b369-95e3-4568-94cf-810d9b3a3f4c','淮東趙漕領客東園趙世卿賸談近日諸公僕謂今日東園之會想像歐蘇風流不可見','戴復古','宋','宋诗','song-poetry','','[]','今日東園會，能爲野客期。',48,'全唐诗/poet.song.182000.json','["今日東園會，能爲野客期。", "乾坤一南北，花木幾興衰。", "亭舘經行地，歐蘇無恙時。", "風流不可見，烟雨謾題詩。"]'),
('ea060bf0-89c0-44a0-a697-2a75f8171a3a','沈莊可號菊花山人即其所言','戴復古','宋','宋诗','song-poetry','','[]','老貌非前日，清吟似舊時。',48,'全唐诗/poet.song.182000.json','["老貌非前日，清吟似舊時。", "已無藏酒婦，幸有讀書兒。", "連歲修茅屋，三秋繞菊籬。", "寒儒有奇遇，太守爲刊詩。"]'),
('e56ffa74-61ff-4b86-b3ad-7a0d73c8838e','別章泉定庵二老人','戴復古','宋','宋诗','song-poetry','','[]','臘裏春風轉，塤箎一氣和。',48,'全唐诗/poet.song.182000.json','["臘裏春風轉，塤箎一氣和。", "勸翁新歲酒，唱我老人歌。", "一世聲名重，四方書問多。", "章泉一泓水，思與海同波。"]'),
('9e6f7838-56d7-452c-b73d-7e8e6dd2ae2c','太湖縣雪中簡段子克知縣','戴復古','宋','宋诗','song-poetry','','["\u592a\u6e56"]','臘雪隨風下，蹇馿行路難。',48,'全唐诗/poet.song.182000.json','["臘雪隨風下，蹇馿行路難。", "匆匆投邸舍，草草共杯盤。", "喜見豐年瑞，渾忘昨夜寒。", "兒童不解事，却作柳花看。"]'),
('91821ef6-0916-44b8-8098-876331a5b657','有烹犢延客者食之有感','戴復古','宋','宋诗','song-poetry','','[]','田家繭栗犢，小小可憐生。',48,'全唐诗/poet.song.182000.json','["田家繭栗犢，小小可憐生。", "未試一犂力，俄遭五鼎烹。", "朝來占食指，妙絕此杯羹。", "口腹爲人累，終懷不忍情。"]'),
('200dc22d-09ce-4acb-a483-15ffe5536baf','萍鄉縣圃','戴復古','宋','宋诗','song-poetry','','[]','亭榭八九所，一筇隨往還。',48,'全唐诗/poet.song.182000.json','["亭榭八九所，一筇隨往還。", "四橋朱檻外，三徑綠陰間。", "鑿淺通流水，凭高見遠山。", "琴堂判風月，一笑得雙鬟。"]'),
('b4d8aedd-fadf-45a3-b4ca-7928eab7fb8c','書事','戴復古','宋','宋诗','song-poetry','','[]','兩揆新當國，三邊未解兵。',48,'全唐诗/poet.song.182000.json','["兩揆新當國，三邊未解兵。", "吾君極勤儉，天下望昇平。", "春雨隨時下，福星連夜明。", "寒儒卜天意，對酒百憂輕。"]'),
('e55009aa-5f7f-4d11-8402-f466925b033a','同趙鼎臣游黄甫真人清虛庵','戴復古','宋','宋诗','song-poetry','','[]','昨聞曹兩府，河上遇游仙。',48,'全唐诗/poet.song.182000.json','["昨聞曹兩府，河上遇游仙。", "駐蹕錢塘後，結庵廬阜邊。", "焚香觀御帖，洗盞酌神泉。", "鴈足傳書日，傷心已百年。"]'),
('8f691aa6-bc51-4b57-819f-93558105bf87','同曾景建金陵登覽','戴復古','宋','宋诗','song-poetry','','[]','興廢從誰問，雲烟過眼空。',48,'全唐诗/poet.song.182000.json','["興廢從誰問，雲烟過眼空。", "吁嗟六朝事，想像半山翁。", "百景饒君詠，三杯許我同。", "登臨無限意，多在夕陽中。"]'),
('658ad6f0-f75a-44a9-8ea8-1006201788b6','遇淮人問蘄黄之變哽噎淚下不能語許俊不解圍乃提兵過武昌','戴復古','宋','宋诗','song-poetry','','[]','偶逢淮上客，急急問蘄黄。',48,'全唐诗/poet.song.182000.json','["偶逢淮上客，急急問蘄黄。", "未語心先噎，低頭淚已滂。", "五關人失守，殘虜勢非强。", "聞說許都統，提兵過武昌。"]'),
('c4797359-7612-4463-a722-71c84ab6cb8c','寄姚楚州  其一','戴復古','宋','宋诗','song-poetry','','[]','人材當世用，緩急敢辭難。',48,'全唐诗/poet.song.182000.json','["人材當世用，緩急敢辭難。", "身挾天威重，名驚賊膽寒。", "臨機一著妙，入境衆心安。", "聞已誅元惡，仍須問禍端。"]'),
('b003d9da-6194-4829-af5a-cb331b4b035c','寄姚楚州  其二','戴復古','宋','宋诗','song-poetry','','[]','庸將幾誤國，流民亦弄兵。',48,'全唐诗/poet.song.182000.json','["庸將幾誤國，流民亦弄兵。", "康時仗豪傑，了事是功名。", "車馬長淮路，貔貅細柳營。", "山陽還舊觀，併使虜塵清。"]'),
('153efc7a-6f97-4b2b-be59-373d7cfa3d44','許介之約過清溪道上有成','戴復古','宋','宋诗','song-poetry','','[]','行盡白雲際，乘槎過水西。',48,'全唐诗/poet.song.182000.json','["行盡白雲際，乘槎過水西。", "稻田秋後雀，茅舍午時鷄。", "野飯自不惡，村醪亦可携。", "聞鐘欲投宿，何處是招提。"]'),
('5b7d7aea-1101-46a7-a600-b0c08b66a6cb','送張子孟','戴復古','宋','宋诗','song-poetry','','[]','君爲郴桂客，聽說道途難。',48,'全唐诗/poet.song.182000.json','["君爲郴桂客，聽說道途難。", "不過神愁嶺，須經鬼哭山。", "心平無險路，酒賤有歡顔。", "早作還鄉計，高堂鶴髮斑。"]'),
('379efcc5-bbaa-4586-8f2a-45495335cd77','南豐縣南臺包敏道趙伯成同遊','戴復古','宋','宋诗','song-poetry','','[]','笑傲南臺上，東風吹鬢絲。',48,'全唐诗/poet.song.182000.json','["笑傲南臺上，東風吹鬢絲。", "眼明花在處，春好雨晴時。", "樓閣多臨水，溪山可賦詩。", "留連無盡意，故遣酒行遲。"]'),
('9c4577ba-b644-4d00-a863-e99fe93ee591','長沙道上','戴復古','宋','宋诗','song-poetry','','[]','詩情滿天地，客夢繞瀟湘。',48,'全唐诗/poet.song.182000.json','["詩情滿天地，客夢繞瀟湘。", "何處桂花發，秋風昨夜香。", "登山猶矍鑠，照水見昂藏。", "未了一生事，難禁兩鬢霜。"]'),
('c12c4ee4-cfe5-4e8a-861c-cea981879629','萍鄉客舍','戴復古','宋','宋诗','song-poetry','','[]','草罷惜春賦，持杯亦鮮歡。',48,'全唐诗/poet.song.182000.json','["草罷惜春賦，持杯亦鮮歡。", "簷楹雙燕語，風雨百花殘。", "小閣無聊坐，征衣不耐寒。", "地爐燒石炭，强把故書看。"]'),
('b1853cee-be28-4f3e-b8f3-b029f68989d6','無爲軍界上遇太湖趙尉制府稟議','戴復古','宋','宋诗','song-poetry','','["\u592a\u6e56"]','解后風塵底，周旋鞍馬間。',48,'全唐诗/poet.song.182000.json','["解后風塵底，周旋鞍馬間。", "三杯送行色，一笑强開顔。", "夜宿煖湯市，晨炊冷水關。", "軍前獻籌策，第一守光山。"]'),
('fc07a405-a139-448c-9ded-b3e91499474d','譚俊明雪中見訪從而乞米','戴復古','宋','宋诗','song-poetry','','[]','今日病方起，君來喜可知。',48,'全唐诗/poet.song.182000.json','["今日病方起，君來喜可知。", "地爐燒榾柮，瓦釜煮犁祈。", "門外雪三尺，窗前梅數枝。", "野夫饑欲死，誰與辦晨炊。"]'),
('580a0c1a-2f34-47d1-9f98-8bf50f7d3dda','新喻縣蘇晉叔相會','戴復古','宋','宋诗','song-poetry','','[]','偶作榆溪客，還逢橘井仙。',48,'全唐诗/poet.song.182000.json','["偶作榆溪客，還逢橘井仙。", "多才出人上，笑我老吟邊。", "買錦囊詩卷，典衣供酒錢。", "竹林青眼叔，常說仲容賢。"]'),
('80da14fd-28c5-4e0b-8ca8-150e1ba16672','訪陳與機縣尉於湘潭下攝市  其一','戴復古','宋','宋诗','song-poetry','','[]','清淡守風節，當官若隠居。',48,'全唐诗/poet.song.182000.json','["清淡守風節，當官若隠居。", "自稱爲漫尉，人道是迂儒。", "俸外無炊米，公餘但讀書。", "王門多貴戚，道眼視如無。"]'),
('eca58d16-29c1-4e75-b10f-9253057df38d','訪陳與機縣尉於湘潭下攝市  其二','戴復古','宋','宋诗','song-poetry','','[]','買得南坡景，創成西尉司。',48,'全唐诗/poet.song.182000.json','["買得南坡景，創成西尉司。", "宅幽連寺觀，地廣带亭池。", "能事事易了，役民民不知。", "題詩記顛末，政不假人碑。"]'),
('03ac488d-04ca-411d-af54-a1ad7d78a26e','訪陳與機縣尉於湘潭下攝市  其三','戴復古','宋','宋诗','song-poetry','','[]','吾里不識面，他鄉喜見君。',49,'全唐诗/poet.song.182000.json','["吾里不識面，他鄉喜見君。", "數朝相款曲，杯酒接慇。", "懃。", "清挹湘江水，笑開衡嶽雲。", "歸心逐回鴈，轉首歎離群。"]'),
('d2500e19-ddd0-4a8a-a70c-1fa49c90c53e','訪曾魯叔有少嫌先從金仙假榻長老作筍供','戴復古','宋','宋诗','song-poetry','','[]','俗物敗佳興，余非後汝期。',48,'全唐诗/poet.song.182000.json','["俗物敗佳興，余非後汝期。", "既來遲一見，政恐錯相疑。", "同訪金仙老，因參玉板師。", "樽前有餘暇，細讀放翁詩。"]'),
('bcbd75fe-e9f1-400b-aac8-0739e5507c40','觀靜江山水呈陳魯叟漕使  其一','戴復古','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','桂林佳絕處，人道勝匡廬。',48,'全唐诗/poet.song.182000.json','["桂林佳絕處，人道勝匡廬。", "山好石骨露，洞多巖腹虛。", "崢嶸勢相敵，溫厚氣無餘。", "可惜登臨地，春風草木疎。"]'),
('86812092-365d-461c-a87a-4136feab3b27','觀靜江山水呈陳魯叟漕使  其二','戴復古','宋','宋诗','song-poetry','','[]','昨者登梅嶺，茲來入桂林。',48,'全唐诗/poet.song.182000.json','["昨者登梅嶺，茲來入桂林。", "相從萬里外，不負一生心。", "湖上千峰立，樽前十客吟。", "譏評到泉石，吾敢望知音。"]'),
('5ccc83f2-edce-4aa0-aba3-a6a2c7fc2410','昭武劉圻甫以㟳篁隠居圖求詩','戴復古','宋','宋诗','song-poetry','','[]','相對兩山碧，春風摇綠篁。',48,'全唐诗/poet.song.182000.json','["相對兩山碧，春風摇綠篁。", "一巢雲建造，三澗水宮商。", "谷口躬耕稼，盤中歌壽昌。", "桃花認行路，他日訪劉郎。"]'),
('e3ef4baf-f009-425c-8f6c-b50e83491a58','過三衢尋鄉僧適遇愛山徐叔高同訪鄭監丞其家梅園甚佳選百家詩','戴復古','宋','宋诗','song-poetry','','[]','暫作三衢客，尋僧出郭遲。',48,'全唐诗/poet.song.182000.json','["暫作三衢客，尋僧出郭遲。", "適逢徐孺子，同訪鄭當時。", "詩集百家富，梅花幾樹奇。", "匆匆又行役，不見爛柯棋。"]'),
('24cdbba0-dc11-4669-926c-0aea378c36b9','題趙庶可山臺  其一','戴復古','宋','宋诗','song-poetry','','[]','層臺高幾許，此即會稽圖。',48,'全唐诗/poet.song.182000.json','["層臺高幾許，此即會稽圖。", "一目空秦望，千峰壓鏡湖。", "雲烟分境界，城郭限廉隅。", "他日傳佳話，蘭亭與此俱。"]'),
('a99c0c9c-0e27-42a6-900d-9fff0eda5efc','題趙庶可山臺  其二','戴復古','宋','宋诗','song-poetry','','[]','天造此一景，趨然闤闠間。',48,'全唐诗/poet.song.182000.json','["天造此一景，趨然闤闠間。", "坐分臺上石，看盡越中山。", "松月照今古，樵風送往還。", "只愁軒冕出，閑却白雲關。"]'),
('e7e6c376-5bbb-4976-b7ef-dd273f9c38b2','董叔宏黄伯厚載酒黄塘送別','戴復古','宋','宋诗','song-poetry','','[]','愁酌開懷酒，凉生破暑風。',48,'全唐诗/poet.song.182000.json','["愁酌開懷酒，凉生破暑風。", "論交談洒洒，告別恨匆匆。", "十里黄塘路，扁舟白髮翁。", "多情今夜月，爲我照吟篷。"]'),
('0a39ee6d-95fc-4aa7-82ef-937a3e881735','贈張季冶','戴復古','宋','宋诗','song-poetry','','[]','秋扇交情薄，儒衣行路難。',48,'全唐诗/poet.song.182000.json','["秋扇交情薄，儒衣行路難。", "縱懷千里志，也要一枝安。", "夢繞梅花帳，愁生苜蓿盤。", "從來食肉相，千萬强加餐。"]'),
('2d090429-bdfe-4ad1-b577-14875d4067f0','姪淑遠游不得書','戴復古','宋','宋诗','song-poetry','','[]','客夢江湖遠，窮居骨肉離。',48,'全唐诗/poet.song.182000.json','["客夢江湖遠，窮居骨肉離。", "尺書無寄處，中夜不眠時。", "念爾衣裘薄，滿懷風露悲。", "狂游斷消息，深負竹林期。"]'),
('fcfe61fe-d783-4720-8bb6-fdac2ed60482','寄梅屋趙季防縣尉','戴復古','宋','宋诗','song-poetry','','[]','疇昔交游密，暌違歲月多。',48,'全唐诗/poet.song.182000.json','["疇昔交游密，暌違歲月多。", "石屏今老矣，梅屋病如何。", "世路生荆棘，家山足薜蘿。", "共尋深處隠，此計莫蹉跎。"]'),
('4d5f583e-eef3-495f-8de6-fe6880af95ae','雨後有感','戴復古','宋','宋诗','song-poetry','','[]','逐日愁聞雨，今朝喜遇晴。',48,'全唐诗/poet.song.182000.json','["逐日愁聞雨，今朝喜遇晴。", "雲開山獻狀，月出海生明。", "天地有常理，古今無限情。", "靜中觀世變，安得見河清。"]'),
('1aee12a8-7240-44eb-895d-d25f3fb5ea80','歸來二首兒子創小樓以安老者  其一','戴復古','宋','宋诗','song-poetry','','[]','老去知無用，歸來得自如。',48,'全唐诗/poet.song.182000.json','["老去知無用，歸來得自如。", "幾年眠客舍，今日愛吾廬。", "處世無長策，閑時讀故書。", "但能營一飽，渾莫問其餘。"]'),
('c8811887-da15-44e5-aa3b-1df58de3c1c1','歸來二首兒子創小樓以安老者  其二','戴復古','宋','宋诗','song-poetry','','[]','破屋不可住，如何著老身。',48,'全唐诗/poet.song.182000.json','["破屋不可住，如何著老身。", "喜於喬木下，見此小樓新。", "山好如佳客，吾歸作主人。", "摩挲雙脚底，無復踏紅塵。"]'),
('f9216eb8-07d7-4c4f-9e82-c6b7ec0b8797','歸後遣書問訊李敷文  其一','戴復古','宋','宋诗','song-poetry','','[]','繡斧離章貢，旋聞帥壽沙。',48,'全唐诗/poet.song.182000.json','["繡斧離章貢，旋聞帥壽沙。", "先生方易節，客子已還家。", "別後仙凡隔，歸來道路賒。", "秋風兩行字，也勝寄梅花。"]'),
('8b851a55-2aa2-4d43-8f18-e1f9b10f6c5d','歸後遣書問訊李敷文  其二','戴復古','宋','宋诗','song-poetry','','[]','身退謀家易，時危致主難。',48,'全唐诗/poet.song.182000.json','["身退謀家易，時危致主難。", "才能今管樂，人物舊張韓。", "吾國日以小，邊疆風正寒。", "平生倚天劍，終待斬樓蘭。"]'),
('a8f16d76-22d4-4ae3-9c02-00a5d20dfdb1','歸後遣書問訊李敷文  其三','戴復古','宋','宋诗','song-poetry','','[]','聞說營新第，無從賀落成。',48,'全唐诗/poet.song.182000.json','["聞說營新第，無從賀落成。", "門庭山水色，樓閣管絃聲。", "海內二三傑，胸中十萬兵。", "寧爲一區計，不使九州平。"]'),
('10d661b6-ae23-476a-bcc1-5e9aa11bc6d6','歸後遣書問訊李敷文  其四','戴復古','宋','宋诗','song-poetry','','[]','憶作南州客，歸來東海濱。',48,'全唐诗/poet.song.182000.json','["憶作南州客，歸來東海濱。", "尚懷憂世志，忍說在家貧。", "老作山林計，夢隨車馬塵。", "鬰孤臺上月，無復照詩人。"]'),
('a8fbbe0e-f083-4265-bb2d-6368c47cab7d','醉眠夢中得夏閏得秋早雨多宜歲豐一聯起來西風悲人且聞邊事','戴復古','宋','宋诗','song-poetry','','[]','夏閏得秋早，雨多宜歲豐。',48,'全唐诗/poet.song.182000.json','["夏閏得秋早，雨多宜歲豐。", "今朝上東閣，昨夜已西風。", "田野一飽外，乾坤萬感中。", "傳聞招戰士，人尚說和戎。"]'),
('b5c19a91-d9b9-403a-a09c-1f0d1a7bdd77','姪孫仲晦亦龍和前詩甚佳其家有林塘之勝兄弟和睦日以奉親爲樂用此韵以美之','戴復古','宋','宋诗','song-poetry','','[]','有母身長健，無營家自豐。',48,'全唐诗/poet.song.182000.json','["有母身長健，無營家自豐。", "林塘孝子宅，詩禮古人風。", "壠畝秋成後，弟兄和氣中。", "時聞有佳話，常欲訪王戎。"]'),
('1f4078c4-6b10-4157-8d57-854381f6ac94','一笑','戴復古','宋','宋诗','song-poetry','','[]','海曲荒凉地，吟邊蹭蹬身。',48,'全唐诗/poet.song.182000.json','["海曲荒凉地，吟邊蹭蹬身。", "時危法當隠，年老慣居貧。", "俗客苦戀坐，小孫癡弄人。", "等閑成一笑，不覺把杯頻。"]'),
('66874a24-5a76-450c-9582-914df3c491e5','寄趙茂實大著二首  其一','戴復古','宋','宋诗','song-poetry','','[]','久坐圖書府，方登著作庭。',48,'全唐诗/poet.song.182000.json','["久坐圖書府，方登著作庭。", "人知才可敬，公以德爲馨。", "議論參諸老，文章本六經。", "省中相別後，夜夜望奎星。"]'),
('ec05da18-7cc1-4023-9bd8-739357da20d6','寄趙茂實大著二首  其二','戴復古','宋','宋诗','song-poetry','','[]','詞臣工筆墨，亦足致功勳。',48,'全唐诗/poet.song.182000.json','["詞臣工筆墨，亦足致功勳。", "細草平戎策，兼爲諭蜀文。", "一言關治亂，千載有知聞。", "應笑垂綸叟，愁吟對海雲。"]'),
('6e11874f-3d9c-4305-9553-6119246b41ad','送彭司戶之官三山','戴復古','宋','宋诗','song-poetry','','[]','祭酒家風重，民曹官職卑。',48,'全唐诗/poet.song.182000.json','["祭酒家風重，民曹官職卑。", "公勤爲己任，清白取人知。", "臘月三山雪，梅花一路詩。", "舊時來往處，今有夢相隨。"]'),
('6144a854-879e-4384-8bc0-a6406787e6ca','送姪孫汝白往東嘉問訊陳叔方諸丈','戴復古','宋','宋诗','song-poetry','','[]','子去尋名勝，何慚著布衣。',48,'全唐诗/poet.song.182000.json','["子去尋名勝，何慚著布衣。", "出門知所鄉，在旅亦如歸。", "道誼無窮達，文章有是非。", "寄聲陳與趙，相賞莫相違。"]'),
('0ba1b98f-35ba-4526-9eef-33a184871eeb','寄南昌故人黄存之宋謙甫二首  其一','戴復古','宋','宋诗','song-poetry','','[]','謙甫多才思，存之重誼襟。',48,'全唐诗/poet.song.182000.json','["謙甫多才思，存之重誼襟。", "一書愁話別，千里夢相尋。", "南浦扁舟上，東湖萬柳陰。", "舊時行樂處，何事不關心。"]'),
('6488d23a-c716-48b9-b2d8-2d537762db57','寄南昌故人黄存之宋謙甫二首  其二','戴復古','宋','宋诗','song-poetry','','[]','久客歸來後，家如舊日貧。',48,'全唐诗/poet.song.182000.json','["久客歸來後，家如舊日貧。", "青山何處隠，白髮也愁人。", "畎畝一生事，乾坤百病身。", "時無嵇呂駕，相憶莫相親。"]'),
('dee2a45e-98ec-4304-ba90-12e97aec206b','送趙安仁之官上虞二首  其一','戴復古','宋','宋诗','song-poetry','','[]','表表魁梧相，面如田字方。',48,'全唐诗/poet.song.182000.json','["表表魁梧相，面如田字方。", "早宜朝玉陛，猶自綰銅章。", "上挹葉丞相，近瞻商侍郎。", "風流接前輩，偃室有輝光。"]'),
('431912d2-78e0-44de-a6af-3888d36a1697','送趙安仁之官上虞二首  其二','戴復古','宋','宋诗','song-poetry','','[]','遠庵家學在，持此去爲官。',48,'全唐诗/poet.song.182000.json','["遠庵家學在，持此去爲官。", "冰雪吾身白，風霜吏膽寒。", "一心毋妄用，百姓自相安。", "賢者妙爲政，誰言宰劇難。"]'),
('f9f529b1-98a7-4275-b0ea-535c28254712','秋日','戴復古','宋','宋诗','song-poetry','','[]','秋風梧葉雨，衮衮送秋凉。',48,'全唐诗/poet.song.182000.json','["秋風梧葉雨，衮衮送秋凉。", "一氣四時轉，幾人雙鬢蒼。", "舊游如說夢，久客乍還鄉。", "欲作安居計，生涯尚渺茫。"]'),
('bc734c93-cd61-43f5-ab7b-d50d8f44b957','君玉同訪豈潛飲間君度曼卿不約而至鶴方換翎羽出舞于桂花之下不可無語','戴復古','宋','宋诗','song-poetry','','[]','秋來常日雨，雨霽忽秋深。',48,'全唐诗/poet.song.182000.json','["秋來常日雨，雨霽忽秋深。", "鶴換一身雪，花開滿樹金。", "三杯動情性，一笑付園林。", "莫怪先歸去，衰翁薄疾侵。"]'),
('2f367e54-973e-4886-ad76-21ef4dfd5151','倚樓','戴復古','宋','宋诗','song-poetry','','[]','賢愚不同道，用捨要知機。',48,'全唐诗/poet.song.182000.json','["賢愚不同道，用捨要知機。", "涉世有臧否，倚樓無是非。", "鴉分枯樹立，鴈逐斷雲飛。", "朝暮尋常事，何須歎落暉。"]'),
('86cd0458-d52c-4850-a4c8-95547b7de04f','戊戌冬','戴復古','宋','宋诗','song-poetry','','[]','造化人難測，寒時暖似春。',48,'全唐诗/poet.song.182000.json','["造化人難測，寒時暖似春。", "蛟龍冬不蟄，雷電夜驚人。", "四海瘡痍甚，三邊戰伐頻。", "靜中觀氣數，愁殺草茅臣。"]'),
('3e176f5e-97eb-4347-973a-a02712ba7c7c','題姪孫豈潛家平遠圖','戴復古','宋','宋诗','song-poetry','','[]','好山橫遠碧，平野带林塘。',48,'全唐诗/poet.song.182000.json','["好山橫遠碧，平野带林塘。", "四望耕桑地，幾年雲水鄉。", "海天龍上下，秋日鶴翶翔。", "覩物忽有感，無心住草堂。"]'),
('a0c1cbf7-a757-417f-b8ed-aa57c47bb391','夏日續題','戴復古','宋','宋诗','song-poetry','','[]','海近朝曦赫，山明宿霧消。',48,'全唐诗/poet.song.182000.json','["海近朝曦赫，山明宿霧消。", "紫雲縈碧落，白鷺點青苗。", "避暑軒亭爽，凭虛眼界遥。", "時來一登眺，初不待招邀。"]'),
('f7bf0868-3e38-4c7b-a167-e83052ea8e07','因風再寄南昌故人兼簡王帥子文  其一','戴復古','宋','宋诗','song-poetry','','[]','寄聲黄與宋，書去望書還。',48,'全唐诗/poet.song.182000.json','["寄聲黄與宋，書去望書還。", "別後交情在，年來世路艱。", "吾思蹈東海，君合隠西山。", "詩卷勤收拾，留名天地間。"]'),
('607680af-086f-4699-b3c6-e0ec9b50bfcd','因風再寄南昌故人兼簡王帥子文  其二','戴復古','宋','宋诗','song-poetry','','[]','江湖歸亦好，朋友恨相疎。',48,'全唐诗/poet.song.182000.json','["江湖歸亦好，朋友恨相疎。", "倏作三年別，纔通一紙書。", "詩盟誰是主，世道正愁予。", "若見王都督，煩君問起居。"]'),
('898f74d8-68bf-4bdc-8d3e-59b4e3fcd304','舟中','戴復古','宋','宋诗','song-poetry','','[]','檥棹河梁畔，推篷得句新。',48,'全唐诗/poet.song.182000.json','["檥棹河梁畔，推篷得句新。", "雲爲山態度，水借月精神。", "密樹藏飛翮，平波見躍鱗。", "饑年村落底，也有醉歸人。"]'),
('db56c228-7a02-45f6-ac63-1a6a994438e7','送曉山夏肯甫入京','戴復古','宋','宋诗','song-poetry','','[]','歲月頻看鏡，功名一據鞍。',48,'全唐诗/poet.song.182000.json','["歲月頻看鏡，功名一據鞍。", "勿言行路惡，有志戀家難。", "芳草客程遠，落花春夜寒。", "江湖舊時夢，相逐到長安。"]'),
('06aa3543-30f6-4ea2-965f-ab455f94ad55','辛丑歲暮三首  其一','戴復古','宋','宋诗','song-poetry','','[]','日月易流轉，一年仍一年。',48,'全唐诗/poet.song.182000.json','["日月易流轉，一年仍一年。", "身從憂患老，事逐歲時遷。", "白首未聞道，清貧不愧天。", "寒林松柏瘦，花柳又春妍。"]'),
('9f88d199-56e3-4ca1-9abf-2d26dc4b6ab2','辛丑歲暮三首  其二','戴復古','宋','宋诗','song-poetry','','[]','臘盡無多日，吾生有幾年。',48,'全唐诗/poet.song.182000.json','["臘盡無多日，吾生有幾年。", "老於人事懶，貧覺世情偏。", "獨枕江湖夢，閉門風雪天。", "三杯動詩興，得句落梅邊。"]'),
('79228036-2a09-4190-b553-f0c455ebb695','辛丑歲暮三首  其三','戴復古','宋','宋诗','song-poetry','','[]','意氣久凋落，形模老可憎。',48,'全唐诗/poet.song.182000.json','["意氣久凋落，形模老可憎。", "能扶雙病脚，頼有一枯藤。", "世味淡如水，吾心達似僧。", "明朝今日事，一任運騰騰。"]'),
('d6a0cd58-d9d3-45d9-8c74-a7927857c5b2','小畦','戴復古','宋','宋诗','song-poetry','','[]','小畦尋丈許，鑿壁置柴扉。',48,'全唐诗/poet.song.182000.json','["小畦尋丈許，鑿壁置柴扉。", "雨後菜蟲死，秋來花蝶稀。", "插籬新種菊，抱甕已忘機。", "俗客忽相訪，妨人洗布衣。"]'),
('2120cc28-84d0-400b-bdf5-6ff68ab63997','有感','戴復古','宋','宋诗','song-poetry','','[]','浩浩海風勁，滔滔河水渾。',48,'全唐诗/poet.song.182000.json','["浩浩海風勁，滔滔河水渾。", "古人皆去世，喬木自當門。", "族黨諸孫盛，吾宗一綫存。", "興衰知有數，心事與誰論。"]'),
('dbbab660-117f-4a91-923e-be0c6ab18f3c','次韵陳叔强見寄  其一','戴復古','宋','宋诗','song-poetry','','[]','識面者無數，論交要有緣。',48,'全唐诗/poet.song.182000.json','["識面者無數，論交要有緣。", "未聞蒼玉佩，先枉碧雲篇。", "采鳳騰詩筆，持螯泛酒船。", "山陰或乘興，何待菊花天。"]'),
('cbd433a9-6120-4d50-bd49-01f345622cee','次韵陳叔强見寄  其二','戴復古','宋','宋诗','song-poetry','','[]','窮通元有命，富貴柰無緣。',48,'全唐诗/poet.song.182000.json','["窮通元有命，富貴柰無緣。", "對此黄梅雨，歌君白雪篇。", "風生三尺劍，夢逐五湖船。", "白首成何事，歸來敢問天。"]'),
('62e934d0-48b5-4d82-be5f-b8dfafa6cdd2','一冬無雨雪而有雷','戴復古','宋','宋诗','song-poetry','','[]','萬物久如渴，三冬一向晴。',48,'全唐诗/poet.song.182000.json','["萬物久如渴，三冬一向晴。", "時無臘雪下，夜有瑞雷鳴。", "休咎占天意，悲歡見物情。", "山禽何所感，爛熳作春聲。"]'),
('403297c8-825f-46e4-a4e0-bb63e9de9d0e','歲旦族黨會拜','戴復古','宋','宋诗','song-poetry','','[]','衣冠拜元日，樽俎對芳辰。',48,'全唐诗/poet.song.182000.json','["衣冠拜元日，樽俎對芳辰。", "上下二百位，尊卑五世人。", "排門喬木古，照水早梅春。", "寒事將消歇，風光又一新。"]'),
('b1114bf0-9ef7-4cb7-96b3-493cbfaddced','寄節齋陳叔方寺丞','戴復古','宋','宋诗','song-poetry','','[]','今時古君子，玉立衆人間。',48,'全唐诗/poet.song.182000.json','["今時古君子，玉立衆人間。", "再世黄叔度，三生元魯山。", "把麾渾細事，憂國欲愁顔。", "恨不頻相見，空書謾往還。"]'),
('5133bc77-acd6-4867-805c-41cf998e527f','姪孫子淵新居落成二首  其一','戴復古','宋','宋诗','song-poetry','','[]','結屋鄰蒼海，開門面翠屏。',48,'全唐诗/poet.song.182000.json','["結屋鄰蒼海，開門面翠屏。", "堂前萱草綠，壽母鬢絲青。", "禮樂陳罇俎，詩書立戶庭。", "一時勤卜築，百世享康寧。"]'),
('35d37ff8-6301-4892-9f4b-da34061fe628','姪孫子淵新居落成二首  其二','戴復古','宋','宋诗','song-poetry','','[]','一區揚子宅，中有讀書堂。',48,'全唐诗/poet.song.182000.json','["一區揚子宅，中有讀書堂。", "早覺儒風好，兼看野趣長。", "籓籬带花竹，里巷接農桑。", "安得茅三架，爲鄰住汝傍。"]'),
('596a25e6-bad9-4f21-8ee0-f78fa4502ae7','子淵送牡丹','戴復古','宋','宋诗','song-poetry','','[]','有酒何孤我，因花賦惱公。',48,'全唐诗/poet.song.182000.json','["有酒何孤我，因花賦惱公。", "可憐秋鬢白，羞見牡丹紅。", "海上盟鷗客，人間失馬翁。", "不知衰病後，禁得幾春風。"]'),
('783f526a-3ab5-4e73-9a9f-5cb422358625','寄山臺趙庶可二首  其一','戴復古','宋','宋诗','song-poetry','','[]','天族文章士，會稽山水州。',48,'全唐诗/poet.song.182000.json','["天族文章士，會稽山水州。", "地靈鍾秀異，人物信風流。", "要自用卿法，如何與婦謀。", "功名須早計，莫爲海雲留。"]'),
('92231fb6-0eb0-4dad-9f43-bfe95df203fe','寄山臺趙庶可二首  其二','戴復古','宋','宋诗','song-poetry','','[]','頃上山臺謁，臨行辱贈詩。',48,'全唐诗/poet.song.182000.json','["頃上山臺謁，臨行辱贈詩。", "相思寸心在，莫訝尺書遲。", "好月登樓夜，清秋落木時。", "見君花萼集，夢到謝公池。"]'),
('9f089f05-35a7-45ed-8172-ae23e8110e62','晚春','戴復古','宋','宋诗','song-poetry','','[]','春來涉幾日，又到落花時。',48,'全唐诗/poet.song.182000.json','["春來涉幾日，又到落花時。", "老面羞看鏡，愁懷强作詩。", "雨牆蝸篆古，風樹鳥巢危。", "有客適相過，樽前一局棋。"]'),
('29f2efdd-2307-4b77-b2dd-026c46503cb6','姪孫景文多女賀其得雄','戴復古','宋','宋诗','song-poetry','','[]','陰極一陽轉，君家氣數回。',48,'全唐诗/poet.song.182000.json','["陰極一陽轉，君家氣數回。", "試看庭竹上，新有鳳雛來。", "端的傳書種，分明是福胎。", "三朝食牛氣，端不類嬰孩。"]'),
('714a8500-f31a-4302-9206-938ce1c5f368','屏上懷黄伯高兄弟','戴復古','宋','宋诗','song-poetry','','[]','扁舟到溪上，移杖即行吟。',48,'全唐诗/poet.song.182000.json','["扁舟到溪上，移杖即行吟。", "問麥雨多少，探梅春淺深。", "古屏今日景，脩竹舊時陰。", "疇昔同游者，遺蹤何處尋。"]'),
('5471846d-a620-4ef8-a607-9822ea2fe7bd','嘉熙己亥大旱荒庚子夏麥熟  其一','戴復古','宋','宋诗','song-poetry','','[]','四野蕭條甚，百年無此荒。',48,'全唐诗/poet.song.182000.json','["四野蕭條甚，百年無此荒。", "早禾遭夏旱，晚稻被蟲傷。", "富室無儲粟，農家已絕糧。", "逢人相告語，生理尚茫茫。"]'),
('3beb290f-b0c2-4fdd-a9cf-55072fe0822e','嘉熙己亥大旱荒庚子夏麥熟  其二','戴復古','宋','宋诗','song-poetry','','[]','旱潦併爲虐，三農哭歲饑。',48,'全唐诗/poet.song.182000.json','["旱潦併爲虐，三農哭歲饑。", "當秋穀價貴，出廣米船稀。", "救死知吾拙，謀生恐計非。", "固窮君子事，辦采北山薇。"]'),
('ea3e924d-659b-45f2-91dc-be337716844f','嘉熙己亥大旱荒庚子夏麥熟  其三','戴復古','宋','宋诗','song-poetry','','[]','餓喙偏生事，空言不療饑。',48,'全唐诗/poet.song.182000.json','["餓喙偏生事，空言不療饑。", "誰知歲豐歉，實係國安危。", "世變到極處，人心無藉時。", "客來談盜賊，相對各愁眉。"]'),
('72b3499b-7118-4799-833a-fdd2732ee43b','嘉熙己亥大旱荒庚子夏麥熟  其四','戴復古','宋','宋诗','song-poetry','','[]','瑣瑣饑年事，駸駸穀價高。',48,'全唐诗/poet.song.182000.json','["瑣瑣饑年事，駸駸穀價高。", "人將委溝壑，誰肯發倉厫。", "涸沼魚枯死，荒村犬餓號。", "與人同一飽，安得米千艘。"]'),
('efddbb9f-b9de-4a98-b0d8-8efd281a8d8f','嘉熙己亥大旱荒庚子夏麥熟  其五','戴復古','宋','宋诗','song-poetry','','[]','瀕海數十里，饑民及萬家。',48,'全唐诗/poet.song.182000.json','["瀕海數十里，饑民及萬家。", "雨多憂壞麥，春好忍看花。", "鑿淺疏田水，占晴視晚霞。", "老農如鬼瘦，不住作生涯。"]'),
('8a0eb94f-e956-4a64-a711-b634702fc1e4','嘉熙己亥大旱荒庚子夏麥熟  其六','戴復古','宋','宋诗','song-poetry','','[]','積雨喜新霽，山禽亦好音。',48,'全唐诗/poet.song.182000.json','["積雨喜新霽，山禽亦好音。", "白雲開曠野，紅日照高林。", "歉歲地惜寶，惠民天用心。", "君看大麥熟，顆顆是黄金。"]'),
('03f67d5d-b20c-4064-8aba-13c83c62ff53','人不聊生梅柳早有春意','戴復古','宋','宋诗','song-poetry','','[]','歲歉家家窘，時危事事難。',48,'全唐诗/poet.song.182000.json','["歲歉家家窘，時危事事難。", "出門如有礙，對酒亦無歡。", "楊柳含春思，梅花耐歲寒。", "少須天意轉，穀熟萬民安。"]'),
('0f12f2bf-e8ee-4654-86f7-6a3b0a58115d','庚子荐饑  其一','戴復古','宋','宋诗','song-poetry','','[]','正月彗星出，連年旱魃興。',48,'全唐诗/poet.song.182000.json','["正月彗星出，連年旱魃興。", "自應多變故，何可望豐登。", "孰有回天力，誰懷濟世能。", "嫠居不卹緯，憂國瘦崚嶒。"]'),
('b2b5e755-72ba-433e-93eb-7edffd87fc1f','庚子荐饑  其二','戴復古','宋','宋诗','song-poetry','','[]','連歲遭饑饉，民間氣索然。',48,'全唐诗/poet.song.182000.json','["連歲遭饑饉，民間氣索然。", "十家九不爨，升米百餘錢。", "凜凜饑寒地，蕭蕭風雪天。", "人無告急處，閉戶抱愁眠。"]'),
('54f46a34-ce00-4fbf-b884-f751293b701d','庚子荐饑  其三','戴復古','宋','宋诗','song-poetry','','[]','餓走拋家舍，從橫死路岐。',48,'全唐诗/poet.song.182000.json','["餓走拋家舍，從橫死路岐。", "有天不雨粟，無地可埋屍。", "劫數慘如此，吾曹忍見之。", "官司行賑卹，不過是文移。"]'),
('97d84137-0e6f-4974-a01e-570ea544bc5c','庚子荐饑  其四','戴復古','宋','宋诗','song-poetry','','[]','乘時皆閉糶，有穀貴如金。',48,'全唐诗/poet.song.182000.json','["乘時皆閉糶，有穀貴如金。", "寒士糟糠腹，豪民鐵石心。", "可憐饑欲死，那更病相侵。", "到處聞愁歎，傷時淚滿襟。"]'),
('38ec6d89-8f0f-49ae-8395-20eab3ddf886','庚子荐饑  其五','戴復古','宋','宋诗','song-poetry','','[]','杵臼成虛設，蛛絲網釜鬵。',48,'全唐诗/poet.song.182000.json','["杵臼成虛設，蛛絲網釜鬵。", "啼饑食草木，嘯聚斫山林。", "人語無生意，鳥啼空好音。", "休言穀價貴，菜亦貴如金。"]'),
('ce067b87-0827-4a95-ad5a-61605a4feadd','庚子荐饑  其六','戴復古','宋','宋诗','song-poetry','','[]','去歲未爲歉，今年始是凶。',48,'全唐诗/poet.song.182000.json','["去歲未爲歉，今年始是凶。", "穀高三倍價，人到十分窮。", "險淅矛頭菜，愁聞飯後鍾。", "新來慰心處，隴麥早芃芃。"]'),
('a4879073-e1fd-4805-b864-1290e12a848a','壬寅歲旦景明子淵君玉携酒與詩爲壽次韵','戴復古','宋','宋诗','song-poetry','','[]','捨我白甆椀，把君金屈巵。',48,'全唐诗/poet.song.182000.json','["捨我白甆椀，把君金屈巵。", "判爲元日醉，共賦早春詩。", "冰泮魚龍起，花開蜂蝶知。", "爲子扶病脚，頼有古藤枝。"]'),
('2b7debf2-1e7c-4d9e-b005-d2bc47378697','花朝姪孫子固家小集','戴復古','宋','宋诗','song-poetry','','[]','今朝當社日，明日是花朝。',48,'全唐诗/poet.song.182000.json','["今朝當社日，明日是花朝。", "佳節唯宜飲，東池適見招。", "綠深楊柳重，紅透海棠嬌。", "自笑鬢邊雪，多年不肯消。"]'),
('f0e7451b-fdae-45fb-bf2c-0f2e7b14829e','次韵君玉春日','戴復古','宋','宋诗','song-poetry','','[]','風雨不相貸，繁華能幾時。',48,'全唐诗/poet.song.182000.json','["風雨不相貸，繁華能幾時。", "纔歌喜晴賦，又作惜春詩。", "壓架酴醾老，翻階芍藥遲。", "無花何足算，有酒且相期。"]'),
('f6f5dd95-e51c-4dd7-aff2-7116e9bfd313','代書寄韓履善右司趙庶可寺簿  其一','戴復古','宋','宋诗','song-poetry','','[]','懶不脩書札，將詩問起居。',48,'全唐诗/poet.song.182000.json','["懶不脩書札，將詩問起居。", "升沉元自異，故舊忍相疎。", "學術有餘用，班行不次除。", "功名付公等，世道莫愁予。"]'),
('ebd934d2-f14a-4cd0-ab2d-077c48606c77','代書寄韓履善右司趙庶可寺簿  其二','戴復古','宋','宋诗','song-poetry','','[]','涉世幾三折，行年近八旬。',48,'全唐诗/poet.song.182000.json','["涉世幾三折，行年近八旬。", "江湖倦游客，天地苦吟身。", "白髮可憐老，青雲多故人。", "東風雖有力，朽木不逢春。"]'),
('0a381d6c-f36f-46b9-944e-5ec054b9ba78','代書寄韓履善右司趙庶可寺簿  其三','戴復古','宋','宋诗','song-poetry','','[]','閉戶生涯薄，憂時念慮長。',48,'全唐诗/poet.song.182000.json','["閉戶生涯薄，憂時念慮長。", "老猶思汗漫，貧已在膏肓。", "弱柳饒春色，幽蘭抱國香。", "窮通安我命，一笑且持觴。"]'),
('fb9d476d-c0e1-43e3-9794-4ba3d34d6424','月夜懷董叔宏聞其入京未得振','戴復古','宋','宋诗','song-poetry','','[]','酒醒興未已，詩成吟不休。',48,'全唐诗/poet.song.182000.json','["酒醒興未已，詩成吟不休。", "一凉風滿座，半夜月明樓。", "老驥思千里，飛鴻閲九州。", "故人何處在，誰作置書郵。"]'),
('8969adf8-d0c3-455d-91d2-f324511d4627','夢中題林逢吉軒壁覺來全篇可讀天明忘了落句','戴復古','宋','宋诗','song-poetry','','[]','囂塵不到眼，瀟灑似僧家。',48,'全唐诗/poet.song.182000.json','["囂塵不到眼，瀟灑似僧家。", "風月三千首，圖書四十車。", "綠垂當戶柳，紅映隔牆花。", "好讀天台賦，登樓詠落霞。"]'),
('a07d1ca3-ecb2-4db3-9e17-7bba7db710a1','姪孫子直家有西閣吾有東樓相望秋來景物佳甚','戴復古','宋','宋诗','song-poetry','','[]','逼仄人間世，思從造物游。',48,'全唐诗/poet.song.182000.json','["逼仄人間世，思從造物游。", "君方倚西閣，吾亦上東樓。", "挹彼千峰秀，森然萬象秋。", "相看成二老，更有幾年留。"]'),
('d8972834-4ce7-4ffa-b9ca-35f7e1f09df5','諸姪孫登白峰觀海上一景','戴復古','宋','宋诗','song-poetry','','[]','自有此山在，無人作此遊。',48,'全唐诗/poet.song.182000.json','["自有此山在，無人作此遊。", "氣吞雲海浪，笑撼玉峰秋。", "開闢幾百載，登臨第一籌。", "諸郎莫高興，刻石記風流。"]'),
('28b37114-f679-4410-9d8f-5e95e6cf96d0','鴈山羅漢寺省王總幹之墓待和甫主簿之來','戴復古','宋','宋诗','song-poetry','','[]','山鳥怪儒衣，遊山我亦癡。',48,'全唐诗/poet.song.182000.json','["山鳥怪儒衣，遊山我亦癡。", "叫雲雲不應，問水水相知。", "俗物刺人眼，春風發我詩。", "噪簷鴉鵲喜，主簿有來期。"]'),
('0037b12d-f845-4333-b65f-639ce76111f4','解后樂清主簿姜昌齡一見如平生歡同宿能仁','戴復古','宋','宋诗','song-poetry','','[]','鴈去蕩猶在，龍居山亦靈。',48,'全唐诗/poet.song.182000.json','["鴈去蕩猶在，龍居山亦靈。", "高峰穿碧落，虛谷吸滄溟。", "愁見僧頭白，喜逢君眼青。", "燈前聞妙語，字字摘天星。"]'),
('7a70e91d-1f7a-4d3a-aedb-6c93434f9dfc','鴈山總題此山本朝方顯  其一','戴復古','宋','宋诗','song-poetry','','[]','此地古無聞，誰封萬石君。',48,'全唐诗/poet.song.182000.json','["此地古無聞，誰封萬石君。", "山林纔整整，來往早紛紛。", "兩派龍湫水，千峰鴈蕩雲。", "東西十八寺，紀載欠碑文。"]'),
('09e2de20-7586-4cd6-b5a7-f17631e3c2e9','鴈山總題此山本朝方顯  其二','戴復古','宋','宋诗','song-poetry','','[]','幾山兼幾水，更有幾烟霞。',48,'全唐诗/poet.song.182000.json','["幾山兼幾水，更有幾烟霞。", "不立僊人宅，都爲釋氏家。", "賓秋多少鴈，報曉一雙鴉。", "有此山林勝，如何在海涯。"]'),
('9cd06a59-e1c3-4e05-a45b-35b2067e8001','會心','戴復古','宋','宋诗','song-poetry','','[]','我本江湖客，來觀鴈蕩奇。',48,'全唐诗/poet.song.182000.json','["我本江湖客，來觀鴈蕩奇。", "脚穿靈運履，口誦貫休詩。", "景物與心會，山靈莫我知。", "白雲迷去路，臨水坐多時。"]'),
('e493859c-3ca7-4744-95dc-93ab38040ed5','大龍湫','戴復古','宋','宋诗','song-poetry','','[]','百丈雲巖上，神龍噀水飛。',48,'全唐诗/poet.song.182000.json','["百丈雲巖上，神龍噀水飛。", "四時作風雨，萬斛瀉珠璣。", "不可形容處，無窮造化機。", "非他瀑布比，對此欲忘歸。"]'),
('6965751c-9714-47c8-87fd-f0f2b8e951a1','靈峰靈巖有天柱石屏之勝自昔號二靈','戴復古','宋','宋诗','song-poetry','','[]','駭見二靈景，山林體勢豪。',48,'全唐诗/poet.song.182000.json','["駭見二靈景，山林體勢豪。", "插空天柱壯，障日石屏高。", "覽勝苦不足，登危不憚勞。", "白雲飛動處，絕壁走猿猱。"]'),
('31c83931-7cb6-49b2-9cab-c691a0f5f1c5','凈明','戴復古','宋','宋诗','song-poetry','','[]','林巒相掩映，巖谷獨玲瓏。',48,'全唐诗/poet.song.182000.json','["林巒相掩映，巖谷獨玲瓏。", "下置維摩室，上通龍伯宮。", "靈珠四時雨，秋水一簾風。", "甚欲觀新月，山高脚力窮。"]'),
('a7c82bd1-94e5-4bdd-9453-d505232660d6','題胡立方思齋','戴復古','宋','宋诗','song-poetry','','[]','每事再思過，參之以古今。',48,'全唐诗/poet.song.182000.json','["每事再思過，參之以古今。", "唯求合天理，毋妄用吾心。", "和氣生琴室，清風動竹林。", "所居雖近市，不許市塵侵。"]'),
('4570214c-96c1-4c3b-aea3-7aff744e387c','張子明索賦永齋詩諾之久矣杜撰四十字以還冷債','戴復古','宋','宋诗','song-poetry','','[]','爲學日不足，毋勞課近功。',48,'全唐诗/poet.song.182000.json','["爲學日不足，毋勞課近功。", "聲名垂不朽，文字用無窮。", "草色朝朝碧，桃花歲歲紅。", "一機長運轉，造物與人同。"]'),
('3aaa8d4f-a194-4651-a49b-09bfd8cdd5a3','謝項子宜帥幹遣饋','戴復古','宋','宋诗','song-poetry','','[]','聞說沙溪上，分明似渭川。',48,'全唐诗/poet.song.182000.json','["聞說沙溪上，分明似渭川。", "重山照華屋，萬竹遶清泉。", "遣餽知相憶，登門未有緣。", "一樓先月景，想像在吟邊。"]'),
('05a02a67-d586-4be2-98e9-c9f28ebe9f71','姪孫昺以東野農歌一編來細讀足以起予七言有汲水灌花私雨露臨池疊石幻溪山草欺蘭瘦能香否杏笑梅殘柰俗何似此兩聯皆自出新意自可傳世然言語之工又未足多其體格純正氣象和平爲可喜余非諛言自有識者因題其卷末以歸之','戴復古','宋','宋诗','song-poetry','','[]','吾宗有東野，詩律頗留心。',48,'全唐诗/poet.song.182000.json','["吾宗有東野，詩律頗留心。", "不學晚唐體，曾聞大雅音。", "霜空孤鶴唳，雲洞老龍吟。", "群噪無才思，昏鴉自滿林。"]'),
('a4bb5eb0-de2e-42dc-963c-e09f67831ea8','風雨無憀中覽鏡有感作小詩未有斷句適兩姪孫携詩卷來','戴復古','宋','宋诗','song-poetry','','[]','覽鏡忽有感，誰能寫我真。',49,'全唐诗/poet.song.182000.json','["覽鏡忽有感，誰能寫我真。", "崚嶒:忍饑面，蹭蹬苦吟身。", "風葉飄零夜，雨花狼藉春。", "相過慰牢落，吾族有詩人。"]'),
('47025e87-4a18-4fb4-b918-bbcad94a6a66','歲暮書懷寄林玉溪  其一','戴復古','宋','宋诗','song-poetry','','[]','吾年幾八十，暮景不勝斜。',48,'全唐诗/poet.song.182000.json','["吾年幾八十，暮景不勝斜。", "老鶴猶能語，枯梅强作花。", "一心爲死計，無意問生涯。", "有酒時相過，東隣八九家。"]'),
('2c85b811-4b08-4d84-a5b8-e9de78e5bdbc','歲暮書懷寄林玉溪  其二','戴復古','宋','宋诗','song-poetry','','[]','笑共梅花語，窮難與命爭。',48,'全唐诗/poet.song.182000.json','["笑共梅花語，窮難與命爭。", "人皆居燠舘，我獨墮寒坑。", "假合非吾道，幽棲了此生。", "門牆元自靜，群小莫從橫。"]'),
('7575a0b5-3758-4106-8ac3-1cb39839facd','歲暮書懷寄林玉溪  其三','戴復古','宋','宋诗','song-poetry','','[]','衮衮日不暇，看看歲又徂。',48,'全唐诗/poet.song.182000.json','["衮衮日不暇，看看歲又徂。", "一生賦茅屋，幾度換桃符。", "天肯容吾老，人皆笑我迂。", "玉溪何所見，時復問詩癯。"]'),
('ea4756b8-d830-4dc3-aad2-0439871f1759','壬寅除夜','戴復古','宋','宋诗','song-poetry','','[]','今夕知何夕，滿堂燈燭光。',48,'全唐诗/poet.song.182000.json','["今夕知何夕，滿堂燈燭光。", "杜陵分歲了，賈島祭詩忙。", "橫笛梅花老，傳杯柏葉香。", "明朝賀元日，政恐雨相妨。"]'),
('efeeaea6-abf2-4257-a876-2ef652a317cc','癸卯歲旦','戴復古','宋','宋诗','song-poetry','','[]','淳祐第三載，正朝把一杯。',48,'全唐诗/poet.song.182000.json','["淳祐第三載，正朝把一杯。", "老夫真是病，賀客不須來。", "擇日脩茅屋，當春覓柳栽。", "新年莫多事，且放好懷開。"]'),
('e5439e47-5c00-40ce-b5f1-a552f52dfafe','新年多雨一日晴色可喜','戴復古','宋','宋诗','song-poetry','','[]','一晴良可喜，始覺好新年。',48,'全唐诗/poet.song.182000.json','["一晴良可喜，始覺好新年。", "綠漲春前水，青開雨後天。", "看花吾老矣，把酒興悠然。", "病脚妨行樂，三杯歸醉眠。"]'),
('6c0c67cb-2634-4834-a05b-72ecb387bca1','讀三學士人論事三書  其一','戴復古','宋','宋诗','song-poetry','','[]','邦計傷虛耗，邊民苦亂離。',48,'全唐诗/poet.song.182000.json','["邦計傷虛耗，邊民苦亂離。", "諸公事緘默，三學論安危。", "災異天垂戒，脩爲國可醫。", "傳聞上元夜，絕似太平時。"]'),
('f742ab81-cbba-442f-8e25-29f59fd6cf02','讀三學士人論事三書  其二','戴復古','宋','宋诗','song-poetry','','[]','黄屋見聞遠，朱門富貴忙。',48,'全唐诗/poet.song.182000.json','["黄屋見聞遠，朱門富貴忙。", "屠沽思報國，樵牧解談王。", "能轉禍爲福，毋令聖作狂。", "草茅垂白叟，尚擬見時康。"]'),
('89713a42-fc63-4fa2-8c71-ef269f86b8ff','六月三日聞王鑑除殿前都虞候孟樞除夔路策應大使時制司籍定漁船守江甚急','戴復古','宋','宋诗','song-poetry','','[]','聞說北風凜，其然其不然。',48,'全唐诗/poet.song.182000.json','["聞說北風凜，其然其不然。", "新除策應使，急點守江船。", "設險渾無地，扶危頼有天。", "吾皇自神武，北伐美周宣。"]'),
('dc096b9d-ca0c-4299-8608-39e7e30b96d6','送王仲彝制機宰瀏陽  其一','戴復古','宋','宋诗','song-poetry','','[]','一身供世用，六月赴官忙。',48,'全唐诗/poet.song.182000.json','["一身供世用，六月赴官忙。", "當此炎天熱，知君心地凉。", "吏能師卓魯，縣界接瀟湘。", "試飲瀏陽水，清清滋味長。"]'),
('c0c2072f-8469-4693-8660-1d99e917181f','送王仲彝制機宰瀏陽  其二','戴復古','宋','宋诗','song-poetry','','[]','瀏陽誰謂小，桑柘萬家春。',48,'全唐诗/poet.song.182000.json','["瀏陽誰謂小，桑柘萬家春。", "遠宦逢知己，推心在惠民。", "速宜還縣債，聞早綴朝紳。", "說與諸公道，方巖後有人。"]'),
('96992b7a-e1a2-4a0b-855b-44e21904b6fb','送黎明府  其一','戴復古','宋','宋诗','song-poetry','','[]','黄巖萬家縣，山海界民居。',48,'全唐诗/poet.song.182000.json','["黄巖萬家縣，山海界民居。", "百里蜀中秀，一廉天下無。", "財多能辦否，官滿賦歸歟。", "已作青雲料，猶驚急急符。"]'),
('7206c948-0775-4adb-aae7-3929cf551b7c','送黎明府  其二','戴復古','宋','宋诗','song-poetry','','[]','縣債三年了，鄉心萬里飛。',48,'全唐诗/poet.song.182000.json','["縣債三年了，鄉心萬里飛。", "一身如許瘦，百姓不妨肥。", "買宅憑誰辦，抱琴何處歸。", "諸公競推轂，穩去著朝衣。"]');
